def get_evc_generator():
    global EVCGenerator, EVCParams, params_from_qra_dict
    if EVCGenerator is None:
        try:
            import evc_generator
            # The class might be named EVCGenerator or EVCMainWindow depending on the file version
            EVCGenerator = getattr(evc_generator, 'EVCGenerator', None)
            if EVCGenerator is None:
                EVCGenerator = getattr(evc_generator, 'EVCMainWindow', None)
            
            EVCParams = getattr(evc_generator, 'EVCParams', None)
            params_from_qra_dict = getattr(evc_generator, 'params_from_qra_dict', None)
            
            return EVCGenerator, EVCParams, params_from_qra_dict
        except Exception as e:
            print(f"Error importing EVC generator: {e}")
            return None, None, None
    return EVCGenerator, EVCParams, params_from_qra_dict


# ─────────────────────────────────────────────────────────────────────────────
# Fire position + RP weights helper
# Source: 터널교통량등제원, row 73:
#   - fire mapping in F73:L73
#   - RP(1..6) weights in M73:R73
# ─────────────────────────────────────────────────────────────────────────────
def tunnel_fire_positions_and_rp(
    tunnel_length_m: float,
    exit_position_m: float,
    excluded_end_region_m: float = 25.0,
    num_fire_points: int = 6,
) -> dict:
    """
    Reproduces the asymmetric Excel logic from:
    터널교통량등제원!F73:L73 (fire points), M73:R73 (RP1..RP6)

    Parameters
    ----------
    tunnel_length_m : float
        Total tunnel length [m]
    exit_position_m : float
        End position of usable tunnel section [m] (D73 equivalent)
    excluded_end_region_m : float
        Region excluded from fire placement near the end [m]
        (ranEVCFire in workbook, default 25 m)
    num_fire_points : int
        Number of fire locations (default 6)

    Returns
    -------
    dict
        {
            "spacing_m": float,
            "fire_positions_m": [...],
            "rp_percent": [...]
        }
    """
    # Excel-verified asymmetric placement uses the effective tunnel span
    # for sectioning. If an exit-derived span is shorter than TL, use TL.
    effective_span_m = max(float(tunnel_length_m or 0.0), float(exit_position_m or 0.0))
    usable_length = effective_span_m - excluded_end_region_m
    if usable_length <= 0:
        usable_length = max(effective_span_m, 0.0)
    spacing = usable_length / num_fire_points

    fire_positions = [
        spacing / 2 + i * spacing
        for i in range(num_fire_points)
    ]

    rp_values = []
    for i in range(num_fire_points):
        if i == 0:
            rp_length = (
                fire_positions[i]
                + (fire_positions[i + 1] - fire_positions[i]) / 2
            )
        elif i == num_fire_points - 1:
            rp_length = (
                (fire_positions[i] - fire_positions[i - 1]) / 2
                + (tunnel_length_m - fire_positions[i])
            )
        else:
            rp_length = (
                (fire_positions[i] - fire_positions[i - 1]) / 2
                + (fire_positions[i + 1] - fire_positions[i]) / 2
            )
        # Keep workbook-level precision for row M73:R73 percentages.
        rp_values.append(round((rp_length / tunnel_length_m) * 100, 2))

    return {
        "spacing_m": round(spacing, 1),
        "fire_positions_m": [round(p, 1) for p in fire_positions],
        "rp_percent": rp_values,
    }


class FDSSimulationThread(QThread):
    """Background thread for running FDS simulations without blocking GUI"""
    progress_signal = pyqtSignal(int)  # Progress percentage
    status_signal = pyqtSignal(str)    # Status messages
    finished_signal = pyqtSignal(int, int, int)  # completed, failed, total
    
    def __init__(self, fds_exe, fds_files, output_dir, num_cores=4, timeout_per_file=10800, parallel_jobs=1):
        super().__init__()
        self.fds_exe = fds_exe
        self.fds_files = fds_files
        self.output_dir = output_dir
        self.num_cores = num_cores  # Total cores available
        self.timeout_per_file = timeout_per_file
        self.parallel_jobs = parallel_jobs  # Number of parallel simulations
        self.should_stop = False
        self.active_processes = []  # Track active subprocesses
        self._proc_lock = __import__('threading').Lock()  # Guard active_processes list
        self._file_progress = {}   # {filename: float 0.0–1.0} for granular progress
    
    def stop(self):
        """Request thread to stop and terminate active processes"""
        self.should_stop = True
        # Terminate all active processes
        with self._proc_lock:
            for proc in list(self.active_processes):
                try:
                    if proc.poll() is None:  # Process still running
                        proc.terminate()
                except:
                    pass
    
    def run_single_simulation(self, fds_file, cores_per_job):
        """Run a single FDS simulation (helper method for parallel execution).
        
        Each simulation runs in the directory where its .FDS file is located.
        Output files (*.smv, *.out, *.csv, etc.) are written alongside the input
        file, keeping every scenario self-contained and preventing file-name
        collisions when multiple jobs run in parallel.
        
        Uses subprocess.Popen for real-time output streaming so the GUI status
        text updates while the simulation is running (not only after it finishes).
        The Popen object is tracked in self.active_processes so the Stop button
        can terminate running simulations immediately.
        """
        import subprocess
        import os
        import time
        import threading
        import re as _re_sim
        from pathlib import Path
        
        # ── Parse simulation end-time from the FDS input file ──────────
        t_end_file = 900.0  # safe default
        chid = None          # will hold the CHID from the FDS file
        try:
            with open(fds_file, 'r', errors='replace') as _fh:
                _raw = _fh.read()
            _m = _re_sim.search(r"&TIME[^/]*T_END\s*=\s*([\d.]+)", _raw, _re_sim.I | _re_sim.S)
            if _m:
                t_end_file = float(_m.group(1))
            else:
                _m = _re_sim.search(r"&TIME[^/]*TWFIN\s*=\s*([\d.]+)", _raw, _re_sim.I | _re_sim.S)
                if _m:
                    t_end_file = float(_m.group(1))
            # Parse CHID — FDS uses this as the base name for ALL output files
            _m_chid = _re_sim.search(r"&HEAD[^/]*CHID\s*=\s*'([^']+)'", _raw, _re_sim.I | _re_sim.S)
            if not _m_chid:
                _m_chid = _re_sim.search(r'&HEAD[^/]*CHID\s*=\s*"([^"]+)"', _raw, _re_sim.I | _re_sim.S)
            if not _m_chid:
                # Unquoted CHID (rare but possible)
                _m_chid = _re_sim.search(r"&HEAD[^/]*CHID\s*=\s*(\S+)", _raw, _re_sim.I | _re_sim.S)
            if _m_chid:
                chid = _m_chid.group(1).strip().rstrip('/')
        except Exception:
            pass
        
        # Regex to detect current simulation time from FDS stdout
        # FDS6:  " Time Step  1234, Simulation Time:  120.45 s"
        # FDS5:  " Time Step  1234  T=  120.45 ..."
        _sim_time_re = _re_sim.compile(
            r'Simulation\s+Time[:\s]+(\d+\.?\d*)'
            r'|Time\s+Step\s+\d+.*?T\s*=\s*(\d+\.?\d*)',
            _re_sim.IGNORECASE
        )
        
        # Initialise this file's progress fraction
        with self._proc_lock:
            self._file_progress[fds_file.name] = 0.0
        
        proc = None  # will hold the Popen object
        try:
            fds_filename = fds_file.name
            # Run in the source directory of the .FDS file, NOT in fdb_files/.
            # This is required because FDS writes all output files (*.smv, *.out,
            # *.csv, slice files …) relative to its working directory using the
            # CHID name.  When multiple jobs share one directory they all try to
            # write the same TN.smv / TN.out file → "Access is denied" error.
            sim_dir = fds_file.parent
            
            # Set up FDS environment variables
            fds_env = os.environ.copy()
            
            # Detect FDS bin directory from executable path
            fds_exe_path = Path(self.fds_exe)
            fds_bin_dir = fds_exe_path.parent
            fds_mpi_dir = fds_bin_dir / 'mpi'
            
            # Set Intel MPI environment variables
            fds_env['I_MPI_ROOT'] = str(fds_mpi_dir)
            fds_env['OMP_NUM_THREADS'] = str(cores_per_job)  # Cores for this specific job
            fds_env['IN_CMDFDS'] = '1'
            
            # Add MPI directory to PATH if it exists
            if fds_mpi_dir.exists():
                fds_env['PATH'] = str(fds_mpi_dir) + os.pathsep + fds_env.get('PATH', '')
            
            if self.fds_exe.lower().endswith('.bat'):
                # Batch file execution - pass FDS input file as parameter to batch file.
                # cd into the simulation directory first so FDS writes outputs there.
                drive = sim_dir.drive  # e.g. 'C:'
                
                # For FDS5 batch files, prepend the FDS5 bin to PATH if available.
                if "fds5" in self.fds_exe.lower():
                    fds5_bin = Path("C:/FDS5/bin")
                    if fds5_bin.exists():
                        fds_env['PATH'] = str(fds5_bin) + os.pathsep + fds_env.get('PATH', '')

                # Build cmd /c command with proper quoting.
                # Use double-double-quotes inside the outer cmd /c "..." wrapper
                # so paths with spaces are handled correctly by cmd.exe.
                sim_dir_str = str(sim_dir)
                exe_str = str(fds_exe_path)
                if drive:
                    inner = f'{drive} && cd /d "{sim_dir_str}" && "{exe_str}" "{fds_filename}"'
                else:
                    inner = f'cd /d "{sim_dir_str}" && "{exe_str}" "{fds_filename}"'
                cmd = f'cmd /c "{inner}"'
                
                proc = subprocess.Popen(
                    cmd,
                    cwd=str(sim_dir),
                    env=fds_env,
                    stdout=subprocess.PIPE,
                    stderr=subprocess.PIPE,
                    text=True,
                    shell=True
                )
            else:
                # Direct executable execution
                proc = subprocess.Popen(
                    [str(fds_exe_path), fds_filename],
                    cwd=str(sim_dir),
                    env=fds_env,
                    stdout=subprocess.PIPE,
                    stderr=subprocess.PIPE,
                    text=True
                )
            
            # Register the process so Stop button can terminate it
            with self._proc_lock:
                self.active_processes.append(proc)
            
            # Stream stdout in real-time, emitting status updates to the GUI
            stdout_lines = []
            stderr_lines = []
            last_emit_time = time.time()
            last_progress_time = time.time()
            
            # Read stderr in a background thread to prevent deadlock
            def _drain_stderr():
                for err_line in proc.stderr:
                    stderr_lines.append(err_line)
            
            stderr_thread = threading.Thread(target=_drain_stderr, daemon=True)
            stderr_thread.start()
            
            for line in proc.stdout:
                stdout_lines.append(line)
                stripped = line.strip()
                now = time.time()
                
                # ── Detect FDS simulation time → granular progress ─────
                m_t = _sim_time_re.search(stripped)
                if m_t:
                    cur_t = float(m_t.group(1) or m_t.group(2))
                    frac = min(cur_t / t_end_file, 1.0) if t_end_file > 0 else 0.0
                    with self._proc_lock:
                        self._file_progress[fds_file.name] = frac
                    # Throttle progress-bar updates to every 2 s
                    if now - last_progress_time >= 2.0:
                        with self._proc_lock:
                            _overall = sum(self._file_progress.values())
                        _pct = int(_overall / max(len(self.fds_files), 1) * 100)
                        self.progress_signal.emit(min(_pct, 99))
                        last_progress_time = now
                
                # Emit key FDS progress lines to GUI (throttled to ~every 5 s)
                if stripped and (now - last_emit_time >= 5.0):
                    # Show the most recent meaningful output line
                    self.status_signal.emit(f"    {fds_file.name}: {stripped[:120]}")
                    last_emit_time = now
                
                if self.should_stop:
                    proc.terminate()
                    break
            
            # Wait for process to finish (with timeout)
            try:
                proc.wait(timeout=self.timeout_per_file)
            except subprocess.TimeoutExpired:
                proc.kill()
                proc.wait(timeout=10)
            
            stderr_thread.join(timeout=5)
            
            # Remove from active list
            with self._proc_lock:
                try:
                    self.active_processes.remove(proc)
                except ValueError:
                    pass
            
            returncode = proc.returncode
            stdout_text = ''.join(stdout_lines)
            stderr_text = ''.join(stderr_lines)
            
            # Get basename (handle both .fds and .FDS extensions)
            fds_basename = Path(fds_filename).stem
            
            # The CHID (from &HEAD) is the *real* base name for all FDS
            # output files (.smv, .out, .sf, .csv …).  It often differs
            # from the .fds filename (e.g. file "020CFV0.FDS" → CHID "TN").
            output_stem = chid if chid else fds_basename
            
            # Save FDS output to log file alongside the input file
            log_file = sim_dir / f"{fds_basename}_run.log"
            with open(log_file, 'w') as f:
                f.write("=== FDS STDOUT ===\n")
                f.write(stdout_text if stdout_text else "(no output)\n")
                f.write("\n=== FDS STDERR ===\n")
                f.write(stderr_text if stderr_text else "(no errors)\n")
            
            # Check if we were stopped by user
            if self.should_stop:
                return ('error', fds_file.name, 'Stopped by user')
            
            # ── Robust completion check ──────────────────────────────────
            # FDS5/batch files frequently return non-zero even on success.
            # FDS5 also writes its version header to stderr (not an error).
            # Therefore we check actual output artefacts rather than relying
            # solely on the return code.
            
            # 1. Look for the .out file (CHID-based, then filename-based)
            out_file = sim_dir / f"{output_stem}.out"
            if not out_file.exists() and output_stem != fds_basename:
                out_file = sim_dir / f"{fds_basename}.out"
            
            # 2. Check .out tail for "completed successfully"
            fds_completed = False
            if out_file.exists():
                try:
                    with open(out_file, 'r', errors='replace') as f:
                        tail = f.readlines()[-60:]
                    for tl in tail:
                        if 'completed successfully' in tl.lower():
                            fds_completed = True
                            break
                except Exception:
                    pass
            
            # 3. Also check stdout (batch scripts may echo it)
            if not fds_completed and stdout_text:
                if 'completed successfully' in stdout_text.lower():
                    fds_completed = True
            
            # 4. Look for .smv file (CHID-based, then filename-based, then any .smv)
            smv_file = sim_dir / f"{output_stem}.smv"
            if not smv_file.exists() and output_stem != fds_basename:
                smv_file = sim_dir / f"{fds_basename}.smv"
            if not smv_file.exists():
                # Fallback: any .smv created in sim_dir
                any_smv = list(sim_dir.glob("*.smv"))
                if any_smv:
                    smv_file = any_smv[0]
            
            smv_exists = smv_file.exists()
            
            # Decision matrix
            if fds_completed and smv_exists:
                return ('success', fds_file.name, None)
            elif fds_completed and not smv_exists:
                return ('success', fds_file.name,
                        f"FDS completed but no .smv found (CHID={output_stem})")
            elif smv_exists and returncode == 0:
                return ('success', fds_file.name, None)
            elif smv_exists:
                # Non-zero return code but output exists — likely FDS5 batch quirk
                return ('success', fds_file.name,
                        f"Return code {returncode} (ignored — output files present)")
            elif returncode == 0:
                return ('warning', fds_file.name,
                        f"No .smv file found (CHID={output_stem}). Check {log_file.name}")
            else:
                # Genuine failure
                rc_unsigned = returncode & 0xFFFFFFFF
                # 0xC0000135 = STATUS_DLL_NOT_FOUND (MPI runtime missing)
                # 0xC000007B = STATUS_INVALID_IMAGE_FORMAT
                if rc_unsigned in (0xC0000135, 0xC000007B):
                    error_msg = (f"DLL not found (0x{rc_unsigned:08X}). "
                                 "The FDS5 MPI exe requires MPICH2 runtime. "
                                 "Install MPICH2 or use the non-MPI exe (fds5_win_64.exe).")
                else:
                    error_msg = f"Return code {returncode}"
                    # Only include stderr if it looks like a real error (not just FDS header)
                    if stderr_text and 'fire dynamics simulator' not in stderr_text.lower():
                        error_msg = stderr_text.strip()[:200]
                return ('failed', fds_file.name, error_msg)
                
        except subprocess.TimeoutExpired:
            # Kill the process if it's still running
            if proc and proc.poll() is None:
                proc.kill()
                try:
                    proc.wait(timeout=10)
                except:
                    pass
            # Check if actually completed despite timeout
            fds_basename = Path(fds_filename).stem
            output_stem = chid if chid else fds_basename
            
            # Look for .smv / .out using CHID first, then filename
            expected_smv = sim_dir / f"{output_stem}.smv"
            if not expected_smv.exists() and output_stem != fds_basename:
                expected_smv = sim_dir / f"{fds_basename}.smv"
            if not expected_smv.exists():
                any_smv = list(sim_dir.glob("*.smv"))
                if any_smv:
                    expected_smv = any_smv[0]
            
            expected_out = sim_dir / f"{output_stem}.out"
            if not expected_out.exists() and output_stem != fds_basename:
                expected_out = sim_dir / f"{fds_basename}.out"
            
            completed_successfully = False
            if expected_out.exists():
                try:
                    with open(expected_out, 'r', errors='replace') as f:
                        last_lines = f.readlines()[-60:]
                        for line in last_lines:
                            if 'completed successfully' in line.lower():
                                completed_successfully = True
                                break
                except:
                    pass
            
            if completed_successfully or expected_smv.exists():
                return ('success', fds_file.name, 'Completed (detected after timeout)')
            else:
                return ('timeout', fds_file.name, f"Exceeded {self.timeout_per_file/60:.1f} minutes")
                
        except Exception as e:
            return ('error', fds_file.name, str(e))
        finally:
            # Mark this file as complete and clean up
            with self._proc_lock:
                self._file_progress[fds_file.name] = 1.0
                _overall = sum(self._file_progress.values())
                if proc is not None:
                    try:
                        self.active_processes.remove(proc)
                    except ValueError:
                        pass
            _pct = int(_overall / max(len(self.fds_files), 1) * 100)
            self.progress_signal.emit(min(_pct, 99))
    
    def run(self):
        """Run FDS simulations in background with parallel processing"""
        from concurrent.futures import ThreadPoolExecutor, as_completed
        import threading
        
        completed = 0
        failed = 0
        total = len(self.fds_files)
        
        # Calculate cores per job
        cores_per_job = max(1, self.num_cores // self.parallel_jobs)
        
        self.status_signal.emit(f"\n🚀 Starting parallel processing:")
        self.status_signal.emit(f"  • Total simulations: {total}")
        self.status_signal.emit(f"  • Parallel jobs: {self.parallel_jobs}")
        self.status_signal.emit(f"  • Cores per job: {cores_per_job}")
        self.status_signal.emit(f"  • Total cores used: {self.num_cores}")
        
        # Use ThreadPoolExecutor for parallel execution
        completed_count = 0
        lock = threading.Lock()
        
        with ThreadPoolExecutor(max_workers=self.parallel_jobs) as executor:
            # Submit all jobs
            future_to_file = {executor.submit(self.run_single_simulation, fds_file, cores_per_job): fds_file 
                             for fds_file in self.fds_files}
            
            # Process completed jobs as they finish
            for future in as_completed(future_to_file):
                if self.should_stop:
                    self.status_signal.emit("\n⚠️ Simulations stopped by user")
                    executor.shutdown(wait=False, cancel_futures=True)
                    break
                
                fds_file = future_to_file[future]
                
                try:
                    status, filename, message = future.result()
                    
                    with lock:
                        completed_count += 1
                        
                        self.status_signal.emit(f"\n[{completed_count}/{total}] {filename}")
                        
                        if status == 'success':
                            self.status_signal.emit(f"  ✓ Completed successfully")
                            if message:
                                self.status_signal.emit(f"    Note: {message}")
                            completed += 1
                        elif status == 'warning':
                            self.status_signal.emit(f"  ⚠️ Warning: {message}")
                            failed += 1
                        elif status == 'timeout':
                            self.status_signal.emit(f"  ⏱️ Timeout: {message}")
                            failed += 1
                        elif status == 'failed':
                            self.status_signal.emit(f"  ✗ Failed: {message}")
                            failed += 1
                        elif status == 'error':
                            self.status_signal.emit(f"  ❌ Error: {message}")
                            failed += 1
                        
                        # (granular progress is handled inside run_single_simulation)
                        
                except Exception as e:
                    with lock:
                        self.status_signal.emit(f"\n[{completed_count}/{total}] {fds_file.name}")
                        self.status_signal.emit(f"  ❌ Exception: {str(e)}")
                        failed += 1
                        completed_count += 1
        
        # Emit finished signal
        self.finished_signal.emit(completed, failed, total)


