        self.generate_evc_btn.clicked.connect(self.generate_evc_files)

        self.run_evc_btn = QPushButton("▶  Run EVC / FED Analysis")
        self.run_evc_btn.setStyleSheet(
            "QPushButton{background:#e67e22;color:white;font-weight:bold;"
            "font-size:12px;padding:7px 16px;border-radius:4px;}"
            "QPushButton:hover{background:#f39c12;}")
        self.run_evc_btn.clicked.connect(self.run_evc_analysis)

        self.import_ascii_btn = QPushButton("📥  Load ASCII Files")
        self.import_ascii_btn.setStyleSheet(
            "QPushButton{background:#3498db;color:white;font-weight:bold;"
            "font-size:12px;padding:7px 16px;border-radius:4px;}"
            "QPushButton:hover{background:#5dade2;}")
        self.import_ascii_btn.clicked.connect(self.import_ascii_files)

        btn_row = QHBoxLayout()
        btn_row.addWidget(self.evc_autoscan_btn)
        btn_row.addSpacing(12)
        btn_row.addWidget(self.import_ascii_btn)
        btn_row.addWidget(self.generate_evc_btn)
        btn_row.addWidget(self.run_evc_btn)
        btn_row.addStretch()
        file_gl.addLayout(btn_row, 3, 0, 1, 4)

        # Status log (compact, dark terminal style)
        self.evc_status_text = QTextEdit()
        self.evc_status_text.setReadOnly(True)
        self.evc_status_text.setFixedHeight(70)
        self.evc_status_text.setStyleSheet(
            "background:#1e272e; color:#dfe6e9; "
            "font-family:'Courier New'; font-size:10px; border-radius:3px;")
        file_gl.addWidget(self.evc_status_text, 4, 0, 1, 4)

        # Hidden scenario table (kept for ASCII import compatibility)
        self.scenario_table = QTableWidget(0, 4)
        self.scenario_table.setHorizontalHeaderLabels(
            ["Scenario (CHID)", "HRR", "Position", "ASCII Files"])
        self.scenario_table.setMaximumHeight(0)   # hidden by default
        file_gl.addWidget(self.scenario_table, 5, 0, 1, 4)

        # ══════════════════════════════════════════════════════════════════════
        # BATCH EVC GENERATION PANEL
        # Generates one .evc file per FDB found in a root folder tree.
        # This is completely independent of the single-file flow above.
        # ══════════════════════════════════════════════════════════════════════
        batch_grp = QGroupBox("📦  Batch EVC Generation  —  Multiple FDB/FDS Pairs")
        batch_grp.setStyleSheet(GS)
        batch_gl = QGridLayout()
        batch_gl.setHorizontalSpacing(8)
        batch_gl.setVerticalSpacing(6)
        batch_gl.setContentsMargins(10, 8, 10, 8)
        batch_gl.setColumnStretch(1, 1)
        batch_grp.setLayout(batch_gl)

        # Row 0: root folder picker
        batch_gl.addWidget(_lbl("Root Folder:"), 0, 0)
        self.batch_evc_root_le = _le(ph="Select folder containing FDB files (searched recursively)…", ro=True)
        batch_gl.addWidget(self.batch_evc_root_le, 0, 1)
        btn_batch_browse = QPushButton("📂 Browse Root")
        btn_batch_browse.setStyleSheet(
            "QPushButton{background:#7f8c8d;color:white;font-weight:bold;"
            "padding:5px 10px;border-radius:4px;}"
            "QPushButton:hover{background:#95a5a6;}")
        btn_batch_browse.setFixedHeight(32)
        btn_batch_browse.clicked.connect(self.batch_evc_browse_folder)
        batch_gl.addWidget(btn_batch_browse, 0, 2)

        # Row 1: output folder picker
        batch_gl.addWidget(_lbl("Output Folder:"), 1, 0)
        self.batch_evc_out_le = _le(ph="Defaults to project evc_files/ if left empty…", ro=True)
        batch_gl.addWidget(self.batch_evc_out_le, 1, 1)
        btn_batch_out = QPushButton("📂 Browse Out")
        btn_batch_out.setStyleSheet(
            "QPushButton{background:#7f8c8d;color:white;font-weight:bold;"
            "padding:5px 10px;border-radius:4px;}"
            "QPushButton:hover{background:#95a5a6;}")
        btn_batch_out.setFixedHeight(32)
        btn_batch_out.clicked.connect(self.batch_evc_browse_output)
        batch_gl.addWidget(btn_batch_out, 1, 2)

        # Row 2: discovery preview label + generate button
        self.batch_evc_preview_lbl = QLabel("No root folder selected.")
        self.batch_evc_preview_lbl.setStyleSheet(
            "font-size:11px; color:#555; padding-left:4px;")
        batch_gl.addWidget(self.batch_evc_preview_lbl, 2, 0, 1, 2)

        self.batch_evc_generate_btn = QPushButton("⚙️  Generate Batch EVC Files")
        self.batch_evc_generate_btn.setStyleSheet(
            "QPushButton{background:#8e44ad;color:white;font-weight:bold;"
            "font-size:12px;padding:7px 16px;border-radius:4px;}"
            "QPushButton:hover{background:#9b59b6;}")
        self.batch_evc_generate_btn.setFixedHeight(36)
        self.batch_evc_generate_btn.clicked.connect(self.generate_batch_evc_files)
        batch_gl.addWidget(self.batch_evc_generate_btn, 2, 2)

        # Row 3: batch status log
        self.batch_evc_status = QTextEdit()
