        # ── Row index constants ──────────────────────────────────────────────
        ROW_PLUS_DIR   = 0   # "+Dir"
        ROW_MINUS_DIR  = 1   # "-Dir"
        ROW_PLUS_MIX   = 2   # "+Mix Rate"
        ROW_MINUS_MIX  = 3   # "-Mix Rate"

        # Background colours
        _CLR_COMPUTED  = QColor(230, 247, 255)   # light blue  – auto-calculated
        _CLR_DISABLED  = QColor(235, 235, 235)   # grey        – locked/cleared
        _CLR_NORMAL    = QColor("white")          # white       – user-editable
        _CLR_ERROR     = QColor(253, 232, 232)    # light red   – invalid input

        def _recalc_mix_rates():
            """Recalculate both +Mix Rate and -Mix Rate rows from Dir counts.

            Formula (per type i):
                mix_rate_i = (vehicles_i / total_vehicles) × 100   [%]

            If total_vehicles == 0 for a direction, all mix rates are set to 0.
            The -Mix Rate row is only updated when Two-way mode is active.
            Also updates the read-only Petrol/Diesel split table below.
            """
            tbl      = self.tbi_veh_table
            n_cols   = tbl.columnCount()
            is_twoway = self.tbi_radio_twoway.isChecked()

            tbl.blockSignals(True)
            try:
                # ── Helper: read a float from a cell (0.0 if blank/invalid) ──
                def _cell_val(row, col):
                    it = tbl.item(row, col)
                    if it is None:
                        return 0.0
                    try:
                        return float(it.text().strip())
                    except (ValueError, AttributeError):
                        return 0.0

                # ── Helper: write a computed mix-rate cell (read-only, blue) ─
                def _set_mix(row, col, value):
                    txt = f"{value:.6g}"
                    it = tbl.item(row, col)
                    if it is None:
                        it = QTableWidgetItem(txt)
                        it.setTextAlignment(Qt.AlignCenter)
                        tbl.setItem(row, col, it)
                    else:
                        it.setText(txt)
                    it.setFlags(Qt.ItemIsSelectable | Qt.ItemIsEnabled)   # read-only
                    it.setBackground(_CLR_COMPUTED)
                    it.setToolTip("Auto-calculated: (vehicles_i / total_vehicles) × 100")

                # ── +Mix Rate row ─────────────────────────────────────────────
                plus_vals  = [_cell_val(ROW_PLUS_DIR, c) for c in range(n_cols)]
                plus_total = sum(plus_vals)
                for ci in range(n_cols):
                    pct = (plus_vals[ci] / plus_total * 100.0) if plus_total else 0.0
                    _set_mix(ROW_PLUS_MIX, ci, pct)

                # ── -Mix Rate row (two-way only) ─────────────────────────────
                if is_twoway:
                    minus_vals  = [_cell_val(ROW_MINUS_DIR, c) for c in range(n_cols)]
                    minus_total = sum(minus_vals)
                    for ci in range(n_cols):
                        pct = (minus_vals[ci] / minus_total * 100.0) if minus_total else 0.0
                        _set_mix(ROW_MINUS_MIX, ci, pct)

            finally:
                tbl.blockSignals(False)

            # ── Update the Petrol/Diesel split table (if created yet) ────────
            if hasattr(self, '_update_split_table'):
                self._update_split_table()
                # Clavg (row 11) was just recomputed inside _update_split_table
                # with signals blocked — cascade to density → speed → zone → lane
                if hasattr(self, '_calc_density_table'):
                    self._calc_density_table()
                    self._calc_speed_table()
                    if hasattr(self, '_calc_zone_veh_table'):
                        self._calc_zone_veh_table()
                    if hasattr(self, '_calc_lane_distribution'):
                        self._calc_lane_distribution()

        def _apply_direction_mode(btn_id):
            """Apply One-way (0) or Two-way (1) mode to the vehicle table.

            One-way  → clear and lock both '-Dir' and '-Mix Rate' rows.
            Two-way  → restore '-Dir' as editable, recalculate '-Mix Rate'.
            """
            is_twoway = (btn_id == 1)
            tbl       = self.tbi_veh_table
            n_cols    = tbl.columnCount()

            tbl.blockSignals(True)
            try:
                for ci in range(n_cols):
                    # ── -Dir row ──────────────────────────────────────────────
                    it_dir = tbl.item(ROW_MINUS_DIR, ci)
                    if it_dir is None:
                        it_dir = QTableWidgetItem("")
                        it_dir.setTextAlignment(Qt.AlignCenter)
                        tbl.setItem(ROW_MINUS_DIR, ci, it_dir)

                    # ── -Mix Rate row ─────────────────────────────────────────
                    it_mix = tbl.item(ROW_MINUS_MIX, ci)
                    if it_mix is None:
                        it_mix = QTableWidgetItem("")
                        it_mix.setTextAlignment(Qt.AlignCenter)
                        tbl.setItem(ROW_MINUS_MIX, ci, it_mix)

                    if is_twoway:
                        # Mirror +Dir value into -Dir so -Mix Rate auto-calculates
                        it_plus = tbl.item(ROW_PLUS_DIR, ci)
                        mirror_val = it_plus.text() if it_plus else ""
                        it_dir.setText(mirror_val)
                        # Restore -Dir as user-editable
                        it_dir.setFlags(Qt.ItemIsSelectable | Qt.ItemIsEditable | Qt.ItemIsEnabled)
                        it_dir.setBackground(_CLR_NORMAL)
                        it_dir.setToolTip("")
                        # -Mix Rate will be set by _recalc_mix_rates below
                        it_mix.setBackground(_CLR_COMPUTED)
                    else:
                        # Lock and clear -Dir
                        it_dir.setText("")
                        it_dir.setFlags(Qt.ItemIsSelectable)
                        it_dir.setBackground(_CLR_DISABLED)
                        it_dir.setToolTip("Not applicable in One-way mode")
                        # Lock and clear -Mix Rate
                        it_mix.setText("")
                        it_mix.setFlags(Qt.ItemIsSelectable)
                        it_mix.setBackground(_CLR_DISABLED)
                        it_mix.setToolTip("Not applicable in One-way mode")
            finally:
                tbl.blockSignals(False)

            # Always refresh +Mix Rate; refresh -Mix Rate if two-way
            _recalc_mix_rates()

        def _on_veh_cell_changed(row, col):
            """Validate numeric input; trigger mix-rate recalculation when a
            +Dir or -Dir cell is edited."""
            tbl = self.tbi_veh_table
            itm = tbl.item(row, col)
            if itm is None:
                return
            txt = itm.text().strip()

            # Blank / partial entry – skip validation
            if txt in ("", "-", "."):
                itm.setBackground(_CLR_NORMAL)
                itm.setToolTip("")
                return

            try:
                float(txt)
                itm.setBackground(_CLR_NORMAL)
                itm.setToolTip("")
            except ValueError:
                itm.setBackground(_CLR_ERROR)
                itm.setToolTip(
                    "Please enter a valid number (e.g. 3.25, -3, or 100).\n"
                    "Only digits, decimal point, and minus sign are allowed.")
                QMessageBox.warning(
                    self, "Invalid Input",
                    f"The value \"{txt}\" in row '{VEH_ROWS[row]}', "
                    f"column '{VEH_COLS[col]}' is not a valid number.\n\n"
                    "Please enter a numeric value (e.g. 3.25, -3, or 100).")
                return

            # Recalculate mix rates whenever a Dir row changes
            if row in (ROW_PLUS_DIR, ROW_MINUS_DIR):
                _recalc_mix_rates()

        self.tbi_veh_table.cellChanged.connect(_on_veh_cell_changed)

        # Wire radio buttons → direction-mode handler
        self.tbi_traffic_btn_group.idClicked.connect(_apply_direction_mode)

        # Apply initial state (Two-way is default) and seed mix rates
        _apply_direction_mode(1)

        veh_main.addWidget(self.tbi_veh_table)

