        # ── Split table updater (called from _recalc_mix_rates) ──────────────
        _SPLIT_COMPUTED = QColor(234, 244, 251)   # light blue
        _SPLIT_HEAVY    = QColor(255, 243, 224)   # light orange

        def _update_split_table():
            """Populate the read-only Petrol/Diesel split table via
            compute_estimated_traffic for both +Dir and -Dir.

            Rows:
              0  +Count          4  +Mix%×PCU
              1  -Count          5  -Mix%×PCU
              2  +Mix %          6  PCU%/Units%
              3  -Mix %          7  Heavy Veh %
            """
            stbl = self.tbi_veh_split_table
            stbl.blockSignals(True)
            try:
                def _veh_val(row, col):
                    it = self.tbi_veh_table.item(row, col)
                    if it is None:
                        return 0.0
                    try:
                        return float(it.text().strip())
                    except (ValueError, AttributeError):
                        return 0.0

                # PCU factors from tbi_veh_table row 4 (7 cols)
                # Map to 8 split-cols: petrol-car & diesel-car share same PCU
                ROW_PCU_IDX = 4
                pcu_7 = [_veh_val(ROW_PCU_IDX, c) for c in range(self.tbi_veh_table.columnCount())]
                # 8-col PCU: [car_pcu, car_pcu, smBus, lgBus, smTrk, mdTrk, lgTrk, sp]
                pcu_8 = [pcu_7[0], pcu_7[0]] + pcu_7[1:]

                def _fill_dir(dir_row, count_row, mix_row, mix_pcu_row):
                    """Compute & fill one direction (count, mix %, mix%×PCU)."""
                    car_total = _veh_val(dir_row, 0)
                    inp_kw = dict(
                        passenger_aadt=car_total,
                        bus_small=_veh_val(dir_row, 1),
                        bus_large=_veh_val(dir_row, 2),
                        truck_small=_veh_val(dir_row, 3),
                        truck_medium=_veh_val(dir_row, 4),
                        truck_large=_veh_val(dir_row, 5),
                        truck_special=_veh_val(dir_row, 6),
                    )

                    if compute_estimated_traffic is not None and TrafficInput is not None:
                        result = compute_estimated_traffic(TrafficInput(**inp_kw))
                        counts_8 = [
                            result.counts.get("passengerGasoline", 0.0),
                            result.counts.get("passengerDiesel", 0.0),
                            result.counts.get("busSmall", 0.0),
                            result.counts.get("busLarge", 0.0),
                            result.counts.get("truckSmall", 0.0),
                            result.counts.get("truckMedium", 0.0),
                            result.counts.get("truckLarge", 0.0),
                            result.counts.get("truckSpecial", 0.0),
                        ]
                        mix_8 = [
                            result.mix_percents.get("passengerGasoline", 0.0),
                            result.mix_percents.get("passengerDiesel", 0.0),
                            result.mix_percents.get("busSmall", 0.0),
                            result.mix_percents.get("busLarge", 0.0),
                            result.mix_percents.get("truckSmall", 0.0),
                            result.mix_percents.get("truckMedium", 0.0),
                            result.mix_percents.get("truckLarge", 0.0),
                            result.mix_percents.get("truckSpecial", 0.0),
                        ]
                        heavy = result.heavy_vehicle_mix_pt
                    else:
                        gas_split = PASSENGER_SPLIT.get("gasoline", 0.6)
                        diesel_split = PASSENGER_SPLIT.get("diesel", 0.4)
                        counts_8 = [
                            car_total * gas_split,
                            car_total * diesel_split,
                            inp_kw["bus_small"], inp_kw["bus_large"],
                            inp_kw["truck_small"], inp_kw["truck_medium"],
                            inp_kw["truck_large"], inp_kw["truck_special"],
                        ]
                        total = sum(counts_8)
                        mix_8 = [round(c / total * 100, 2) if total else 0.0
                                 for c in counts_8]
                        heavy = round(mix_8[3] + mix_8[5] + mix_8[6] + mix_8[7], 2)

                    # Mix% × PCU for each type
                    mix_pcu_8 = [mix_8[i] * pcu_8[i] / 100.0 for i in range(8)]

                    for ci, v in enumerate(counts_8):
                        itm = stbl.item(count_row, ci)
                        itm.setText(f"{v:.1f}")
                        itm.setBackground(_SPLIT_COMPUTED)
                    for ci, v in enumerate(mix_8):
                        itm = stbl.item(mix_row, ci)
                        itm.setText(f"{v:.2f}")
                        itm.setBackground(_SPLIT_COMPUTED)
                    for ci, v in enumerate(mix_pcu_8):
                        itm = stbl.item(mix_pcu_row, ci)
                        itm.setText(f"{v:.4f}")
                        itm.setBackground(_SPLIT_COMPUTED)
                    return heavy, mix_8, mix_pcu_8

                # +Dir → count=0, mix=2, mix×pcu=4
                heavy_plus, plus_mix, plus_mix_pcu = _fill_dir(ROW_PLUS_DIR, 0, 2, 4)

                # +Mix%/100 row (row 6) — split-table row 2 (+Mix %) values / 100
                _MIX_FRAC_CLR = QColor(234, 244, 251)   # light blue
                for ci in range(8):
                    try:
                        val = float(stbl.item(2, ci).text()) / 100.0
                    except (ValueError, AttributeError):
                        val = 0.0
                    itm = stbl.item(6, ci)
                    itm.setText(f"{val:.6f}")
                    itm.setBackground(_MIX_FRAC_CLR)

                # -Dir → count=1, mix=3, mix×pcu=5  — only if two-way
                is_twoway = self.tbi_radio_twoway.isChecked()
                if is_twoway:
                    _fill_dir(ROW_MINUS_DIR, 1, 3, 5)
                else:
                    for ci in range(8):
                        stbl.item(1, ci).setText("—")
                        stbl.item(3, ci).setText("—")
                        stbl.item(5, ci).setText("—")

                # AADT row (row 8) — round(sum(+Count row), 0)
                _AADT_CLR = QColor(234, 244, 251)   # light blue
                aadt_sum = 0.0
                for ci in range(8):
                    try:
                        aadt_sum += float(stbl.item(2, ci).text())  # row 2 = +Mix %
                    except (ValueError, AttributeError):
                        pass
                aadt_val = round(aadt_sum, 0)
                for ci in range(8):
                    itm = stbl.item(8, ci)
                    if ci == 0:
                        itm.setText(f"{aadt_val:.0f}")
                    else:
                        itm.setText("")
                    itm.setBackground(_AADT_CLR)

                # PCU(%)/Units(%) row (row 9) — single aggregate value
                import math as _math
                _PCU_RATIO_CLR = QColor(232, 248, 232)   # light green
                pcu_weighted_total = sum(plus_mix_pcu)
                val_str = f"{_math.ceil(pcu_weighted_total * 10000) / 10000:.4f}"
                for ci in range(8):
                    itm = stbl.item(9, ci)
                    if ci == 0:
                        itm.setText(val_str)
                    else:
                        itm.setText("")
                    itm.setBackground(_PCU_RATIO_CLR)

                # Heavy vehicle % row (row 10)
                for ci in range(8):
                    itm = stbl.item(10, ci)
                    if ci == 0:
                        itm.setText(f"{heavy_plus:.2f} %")
                    else:
                        itm.setText("")
                    itm.setBackground(_SPLIT_HEAVY)

                # Avg Veh Length (Clavg) row (row 11)
                # = ROUND( SUM( +Mix%/100[ci] * Veh Length[ci] ), 2)
                _CLAVG_CLR = QColor(232, 248, 232)   # light green
                clavg = 0.0
                for ci in range(8):
                    try:
                        mix_frac = float(stbl.item(6, ci).text())
                    except (ValueError, AttributeError):
                        mix_frac = 0.0
                    try:
                        vlen = float(stbl.item(7, ci).text())
                    except (ValueError, AttributeError):
                        vlen = 0.0
                    clavg += mix_frac * vlen
                clavg = round(clavg, 2)
                for ci in range(8):
                    itm = stbl.item(11, ci)
                    if ci == 0:
                        itm.setText(f"{clavg}")
                    else:
                        itm.setText("")
                    itm.setBackground(_CLAVG_CLR)

                # Spacing (LTH) row (row 12) — user-editable, skip auto-fill

            finally:
                stbl.blockSignals(False)

        self._update_split_table = _update_split_table

        t1l.addWidget(veh_grp)
