        # ── Keep evc_tunnel_length in sync with tbi_length (sub-tab 1 Length) ─
        # tbi_length (QLineEdit) is the authoritative user input on sub-tab 1.
        # evc_tunnel_length (hidden QDoubleSpinBox) is the internal relay used
        # by all downstream calculations (zone table, speed table, evac zones,
        # fire point generation, etc.).
        #
        # IMPORTANT: setValue() is called with blockSignals(True) to avoid
        # recursive loops — so valueChanged does NOT fire automatically.
        # We therefore call each downstream recalc function explicitly so that
        # typing a new length on sub-tab 1 immediately updates ALL sub-tabs.
        def _sync_tunnel_length(text):
            try:
                v = float(text.strip())
                if v > 0:
                    self.evc_tunnel_length.blockSignals(True)
                    self.evc_tunnel_length.setValue(v)
                    self.evc_tunnel_length.blockSignals(False)
                    # Explicitly trigger downstream recalcs — blockSignals
                    # suppresses valueChanged so we must call them directly.
                    if hasattr(self, '_calc_zone_veh_table'):
                        self._calc_zone_veh_table()   # Traffic_Man zone table
                    if hasattr(self, '_live_evac_zone_calc'):
                        self._live_evac_zone_calc()   # Simulation evac zones
            except ValueError:
                pass
        self.tbi_length.textChanged.connect(_sync_tunnel_length)

