        self.evc_detect_time.setFixedWidth(85)
        self.evc_detect_time.setToolTip("감지시간 — fire detection delay (s)")
        row_rt.addWidget(self.evc_detect_time)

        row_rt.addWidget(QLabel("Warning Broadcast Time:"))
