        self.evac_abs_elderly_speed.setDecimals(2); self.evac_abs_elderly_speed.setSuffix(" m/s")
        self.evac_abs_elderly_speed.setFixedWidth(95); self.evac_abs_elderly_speed.setFixedHeight(26)
        self.evac_abs_elderly_speed.setToolTip(
            "절대 노약자 이동속도 (Absolute elderly walk speed)\n"
            "Written to EVC row 9 col 1.\n"
            "VB reference value: 0.5 m/s  (verified from 020CFV0_P1_1.evc row 9)\n"
            "Distinct from the elderly simulation speed-reduction factor in row 87 col 1.")
        row_abs.addWidget(self.evac_abs_elderly_speed)

        row_abs.addStretch()
        evac_vbox.addLayout(row_abs)

        # ── Row B1b: R74 n_occ formula parameters ─────────────────────────────
        # ── R74 Occupant Formula Parameters: REMOVED from UI ────────────────
        # r74_pcpkpl=216.0, r74_dir_mult=2.41, r74_occ_per_veh=1.50 (VB defaults)
