        t4l_main.setContentsMargins(6, 6, 6, 6)
        t4l_main.setSpacing(8)

        # ─── LEFT PANEL (scrollable) ─────────────────────────────────────────
        t4_left = QWidget()
        t4_left.setMinimumWidth(380)
        t4_left.setMaximumWidth(480)
        t4_left_scroll = QScrollArea()
        t4_left_scroll.setWidgetResizable(True)
        t4_left_scroll.setWidget(t4_left)
        t4_left_scroll.setHorizontalScrollBarPolicy(Qt.ScrollBarAlwaysOff)
        t4l = QVBoxLayout(t4_left)
        t4l.setSpacing(6)
        t4l.setContentsMargins(6, 6, 6, 6)

        # helper: 2-column grid
        def _make_gl2():
            gl = QGridLayout()
            gl.setHorizontalSpacing(6); gl.setVerticalSpacing(6)
            gl.setContentsMargins(8, 8, 8, 8)
            gl.setColumnMinimumWidth(0, 0); gl.setColumnMinimumWidth(1, 0)
            gl.setColumnStretch(0, 0); gl.setColumnStretch(1, 0)
            return gl

        def _row2(gl, row, label_txt, widget):
            lw = QLabel(label_txt); lw.setStyleSheet(LBL)
            lw.setAlignment(Qt.AlignLeft | Qt.AlignVCenter)
            widget.setFixedWidth(140)
            gl.addWidget(lw, row, 0, Qt.AlignLeft)
            gl.addWidget(widget, row, 1, Qt.AlignLeft)

        # ── Program Settings ──────────────────────────────────────────────────
        ps_grp = QGroupBox("Program Settings")
        ps_grp.setStyleSheet(GS)
        ps_gl = _make_gl2(); ps_grp.setLayout(ps_gl)
        r = 0
        self.evc_sim_interval_s4 = _dsb(0.1, 60, 2.0, 1, unit=" s", step=0.5)
        _row2(ps_gl, r, "Simulation Time Interval:", self.evc_sim_interval_s4); r += 1
        self.evc_monitor_pt_s4 = _sb(1, 10000, 200, step=10)
        _row2(ps_gl, r, "Monitoring Point:", self.evc_monitor_pt_s4); r += 1
        self.evc_sim_data_save = _dsb(1, 300, 10.0, 1, unit=" s", step=5)
        _row2(ps_gl, r, "Simulation Data Saving Time:", self.evc_sim_data_save); r += 1
        self.evc_monitor_save_s4 = _dsb(1, 300, 10.0, 1, unit=" s", step=5)
        _row2(ps_gl, r, "Monitoring Data Saving Time:", self.evc_monitor_save_s4)
        t4l.addWidget(ps_grp)

        # Shared table style matching sub-tab 1 & 2 header colors
        S4_TBL = """
            QTableWidget {
                gridline-color: #bdc3c7; font-size: 11px;
                selection-background-color: #d4e6f1; selection-color: #1a252f;
                border: 1px solid #95a5a6;
            }
            QTableWidget::item { padding: 2px 4px; border-bottom: 1px solid #d5d8dc; border-right: 1px solid #d5d8dc; }
            QTableWidget::item:selected { background-color: #d4e6f1; }
            QHeaderView::section {
                background-color: #eef2f7; border: 1px solid #bdc3c7;
                padding: 3px; font-weight: bold; font-size: 11px; color: #1a252f;
            }
            QHeaderView::section:horizontal { border-bottom: 2px solid #3498db; }
            QHeaderView::section:vertical { border-right: 2px solid #3498db; }
        """

        # ── Fire Location & Evacuation Zone ───────────────────────────────────
        # Dynamic implementation: rows auto-expand as entries are added;
        # EvacZone table rebuilds live whenever fire-loc data or tunnel length
        # changes.  Mirrors the VB cEVCAZone() formula:
        #   defaDistExit = TLENG*1000 / (NEXIT+1)
        #   pos[i]       = defaDistExit * i
        # with boundary pins at 0 m and tunnel_length_m.
        fz_grp = QGroupBox("Fire Location, Evacuation Zone")
        fz_grp.setStyleSheet(GS)
        fz_vl = QVBoxLayout(fz_grp)
        fz_vl.setContentsMargins(6, 6, 6, 6); fz_vl.setSpacing(4)

        # ── Number of Cross-Passage Exits ─────────────────────────────────────
        # VB formula:  defaDistExit = (TL × 1000) / (nExit + 1)
        #              Exit_pos(i)  = defaDistExit × i    for i = 1 … nExit
        nexit_row = QHBoxLayout(); nexit_row.setSpacing(6)
        _nexit_lbl = QLabel("No. of Cross-Passage Exits:")
        _nexit_lbl.setStyleSheet("font-size:11px; font-weight:bold;")
        nexit_row.addWidget(_nexit_lbl)
        self.evc_nexit_spin = QSpinBox()
        self.evc_nexit_spin.setRange(0, 200)
        self.evc_nexit_spin.setValue(1)
        self.evc_nexit_spin.setFixedWidth(70)
        self.evc_nexit_spin.setToolTip(
            "Number of intermediate cross-passage exits (NEXIT).\n"
            "Positions are auto-calculated as:\n"
            "  defaDistExit = TunnelLength / (NEXIT + 1)\n"
            "  Exit_pos(i)  = defaDistExit × i   for i = 1 … NEXIT")
        nexit_row.addWidget(self.evc_nexit_spin)
        _nexit_gen_btn = QPushButton("⟳  Generate Exit Positions")
        _nexit_gen_btn.setFixedHeight(26); _nexit_gen_btn.setFixedWidth(180)
        _nexit_gen_btn.setStyleSheet(
            "QPushButton{background:#2980b9;color:white;font-weight:bold;"
            "font-size:11px;border-radius:3px;}"
            "QPushButton:hover{background:#1a6fa8;}")
        _nexit_gen_btn.setToolTip(
            "Auto-fill exit rows using VB formula:\n"
            "  defaDistExit = TunnelLength / (NEXIT + 1)\n"
            "  Exit_pos(i)  = defaDistExit × i   for i = 1 … NEXIT")
        nexit_row.addWidget(_nexit_gen_btn)
        nexit_row.addStretch()
        fz_vl.addLayout(nexit_row)

        # ── sub-label ─────────────────────────────────────────────────────────
        _fl_lbl = QLabel("화재위치, 피난연락갬  (Name / Position / Width)")
        _fl_lbl.setStyleSheet("font-size:10px; color:#555; margin-bottom:1px;")
        fz_vl.addWidget(_fl_lbl)

        # ── Fire Location table — dynamic rows ────────────────────────────────
        # Starts with 2 seed rows matching the FDS example; a blank sentinel
        # row is always kept at the bottom so the user can type a new entry.
        # Row color coding:
        #   fire rows  → white background
        #   exit rows  → light-green background  (Qt green tint)
        #   sentinel   → light-grey              (read-only hint)
        ROW_H          = 22
        FIRELOC_COLS   = ["Name", "Position (m)", "Width (m)"]
        EXIT_BG        = QColor(220, 255, 220)   # light green  — exit rows
        FIRE_BG        = QColor(255, 255, 255)   # white        — fire rows
        SENTINEL_BG    = QColor(245, 245, 245)   # light grey   — new-entry hint

        SEED_FIRELOC = [
            ["Fire_Point", "68.33", "1.35"],
            ["exit",       "205",   "1.35"],
        ]

        self.evc_fireloc_table = QTableWidget(0, 3)
        self.evc_fireloc_table.setHorizontalHeaderLabels(FIRELOC_COLS)
        self.evc_fireloc_table.setStyleSheet(S4_TBL)
        fhdr = self.evc_fireloc_table.horizontalHeader()
        for ci in range(3):
            fhdr.setSectionResizeMode(ci, QHeaderView.Stretch)
        self.evc_fireloc_table.verticalHeader().setDefaultSectionSize(ROW_H)
        self.evc_fireloc_table.verticalHeader().setVisible(False)

        def _fl_row_bg(name: str) -> QColor:
            """Return background colour for a fire-loc row by entry type."""
            return EXIT_BG if name.strip().lower() == "exit" else FIRE_BG

        def _fl_set_row(tbl: QTableWidget, ri: int,
                        vals: list, editable: bool = True):
            """Write (or overwrite) one fire-loc table row."""
            name = vals[0] if vals else ""
            bg   = _fl_row_bg(name)
            for ci, v in enumerate(vals):
                itm = QTableWidgetItem(str(v))
                itm.setTextAlignment(Qt.AlignCenter)
                itm.setBackground(bg)
                if not editable:
                    itm.setFlags(itm.flags() & ~Qt.ItemIsEditable)
                    itm.setForeground(QColor(160, 160, 160))
                tbl.setItem(ri, ci, itm)

        def _fl_add_sentinel():
            """Append the blank sentinel row (placeholder for next entry)."""
            tbl = self.evc_fireloc_table
            ri  = tbl.rowCount()
            tbl.insertRow(ri)
            for ci, hint in enumerate(["+ add row", "", ""]):
                itm = QTableWidgetItem(hint)
                itm.setTextAlignment(Qt.AlignCenter)
                itm.setBackground(SENTINEL_BG)
                itm.setForeground(QColor(180, 180, 180))
                tbl.setItem(ri, ci, itm)

        def _fl_resize_table():
            """Adjust fixed height to show all rows (max 8 visible)."""
            n   = self.evc_fireloc_table.rowCount()
            vis = min(n, 8)
            self.evc_fireloc_table.setFixedHeight(
                ROW_H * vis + fhdr.height() + 4)

        # Populate seed rows
        self.evc_fireloc_table.blockSignals(True)
        for rd in SEED_FIRELOC:
            ri = self.evc_fireloc_table.rowCount()
            self.evc_fireloc_table.insertRow(ri)
            _fl_set_row(self.evc_fireloc_table, ri, rd)
        _fl_add_sentinel()
        self.evc_fireloc_table.blockSignals(False)
        _fl_resize_table()

        # ── cellChanged handler: validate, expand, live-recalc ────────────────
        def _on_fireloc_changed(row: int, col: int):
            tbl  = self.evc_fireloc_table
            itm  = tbl.item(row, col)
            if itm is None:
                return
            txt  = itm.text().strip()
            last = tbl.rowCount() - 1   # sentinel row index

            # 1. If user typed into the sentinel row — promote it to a real row
            #    then append a fresh sentinel.
            if row == last and txt and txt != "+ add row":
                tbl.blockSignals(True)
                # Re-colour the now-real row
                name_itm = tbl.item(row, 0)
                name = name_itm.text().strip() if name_itm else ""
                bg   = _fl_row_bg(name)
                for ci in range(tbl.columnCount()):
                    ci_itm = tbl.item(row, ci)
                    if ci_itm:
                        ci_itm.setBackground(bg)
                        ci_itm.setForeground(QColor(0, 0, 0))
                        ci_itm.setFlags(ci_itm.flags() | Qt.ItemIsEditable)
                _fl_add_sentinel()
                tbl.blockSignals(False)
                _fl_resize_table()

            # 2. If the Name column changed on an existing row — update its colour
            if col == 0 and row < last:
                name = txt
                bg   = _fl_row_bg(name)
                tbl.blockSignals(True)
                for ci in range(tbl.columnCount()):
                    ci_itm = tbl.item(row, ci)
                    if ci_itm:
                        ci_itm.setBackground(bg)
                tbl.blockSignals(False)

            # 3. Validate numeric columns (Position, Width)
            if col in (1, 2) and row < last:
                if txt in ('', '-', '.'):
                    itm.setBackground(_fl_row_bg(
                        (tbl.item(row, 0) or QTableWidgetItem("")).text()))
                    return
                try:
                    float(txt)
                    itm.setBackground(_fl_row_bg(
                        (tbl.item(row, 0) or QTableWidgetItem("")).text()))
                except ValueError:
                    itm.setBackground(QColor(253, 232, 232))

            # 4. Live-recalculate the evac zone table whenever data changes
            _live_evac_zone_calc()

        self.evc_fireloc_table.cellChanged.connect(_on_fireloc_changed)
        fz_vl.addWidget(self.evc_fireloc_table)

        # ── Add / Remove row buttons ──────────────────────────────────────────
        fl_btn_row = QHBoxLayout(); fl_btn_row.setSpacing(4)
        _fl_add_btn = QPushButton("＋ Add Exit")
        _fl_add_btn.setFixedHeight(22); _fl_add_btn.setFixedWidth(90)
        _fl_add_btn.setStyleSheet(
            "QPushButton{background:#27ae60;color:white;font-size:10px;"
            "border-radius:2px;} QPushButton:hover{background:#2ecc71;}")
        _fl_rem_btn = QPushButton("－ Remove")
        _fl_rem_btn.setFixedHeight(22); _fl_rem_btn.setFixedWidth(80)
        _fl_rem_btn.setStyleSheet(
            "QPushButton{background:#e74c3c;color:white;font-size:10px;"
            "border-radius:2px;} QPushButton:hover{background:#c0392b;}")

        def _fl_add_exit_row():
            """Insert a new exit row before the sentinel."""
            tbl  = self.evc_fireloc_table
            tbl.blockSignals(True)
            last = tbl.rowCount() - 1
            tbl.insertRow(last)            # push sentinel down by 1
            _fl_set_row(tbl, last, ["exit", "", "1.35"])
            tbl.blockSignals(False)
            _fl_resize_table()
            _live_evac_zone_calc()

        def _fl_remove_row():
            """Remove the currently selected row (not the sentinel)."""
            tbl      = self.evc_fireloc_table
            selected = tbl.currentRow()
            last     = tbl.rowCount() - 1
            if selected < 0 or selected == last:
                return   # nothing selected or sentinel selected
            tbl.blockSignals(True)
            tbl.removeRow(selected)
            tbl.blockSignals(False)
            _fl_resize_table()
            _live_evac_zone_calc()

        _fl_add_btn.clicked.connect(_fl_add_exit_row)
        _fl_rem_btn.clicked.connect(_fl_remove_row)

        def _generate_exit_positions():
            """
            Auto-populate exit rows using the VB cEVCAZone() formula:
                defaDistExit = TunnelLength / (NEXIT + 1)
                Exit_pos(i)  = defaDistExit * i   for i = 1 … NEXIT

            Tunnel length is read from evc_tunnel_length, which is always kept
            in sync with the Length field on sub-tab 1 (Tunnel Info).
            Preserves any existing Fire_Point rows; replaces all exit rows.
            """
            tbl    = self.evc_fireloc_table
            n_exit = self.evc_nexit_spin.value()
            tl_m   = float(self.evc_tunnel_length.value())   # synced from sub-tab 1

            if tl_m <= 0:
                return

            # VB formula: defaDistExit = TL / (NEXIT+1)
            defa_dist_exit = tl_m / (n_exit + 1)

            tbl.blockSignals(True)

            # Collect existing non-exit (Fire_Point) rows, skip sentinel
            fire_rows = []
            last = tbl.rowCount() - 1
            for ri in range(last):
                name_itm = tbl.item(ri, 0)
                if name_itm and name_itm.text().strip().lower() != "exit":
                    row_data = []
                    for ci in range(3):
                        itm = tbl.item(ri, ci)
                        row_data.append(itm.text() if itm else "")
                    fire_rows.append(row_data)

            # Rebuild: fire rows first, then auto-generated exit rows
            tbl.setRowCount(0)

            for rd in fire_rows:
                ri = tbl.rowCount()
                tbl.insertRow(ri)
                _fl_set_row(tbl, ri, rd)

            for idx in range(1, n_exit + 1):
                pos_m = defa_dist_exit * idx      # Exit_pos(i) = defaDistExit × i
                ri = tbl.rowCount()
                tbl.insertRow(ri)
                _fl_set_row(tbl, ri, ["exit", f"{pos_m:.2f}", "1.35"])

            # Re-add sentinel row
            _fl_add_sentinel()

            tbl.blockSignals(False)
            _fl_resize_table()
            _live_evac_zone_calc()

        _nexit_gen_btn.clicked.connect(_generate_exit_positions)

        fl_btn_row.addWidget(_fl_add_btn)
        fl_btn_row.addWidget(_fl_rem_btn)
        fl_btn_row.addStretch()
