        # ── Live evac zone core logic ─────────────────────────────────────────
        # Called automatically whenever: fire-loc rows change, zone-factor
        # changes, or tunnel length changes.  Also called by the manual button.
        #
        # VB formula reproduced here exactly:
        #   defaDistExit = TLENG*1000 / (NEXIT+1)   → equal spacing default
        #   pos[i]       = defaDistExit * i           → for each exit node
        #   pos[0]       = 0                          → entry pin
        #   pos[NEXIT+1] = TLENG*1000                 → exit-end pin
        #
        # Exit point assignment per zone:
        #   Each zone (segment between two adjacent exit nodes) drains toward
        #   the node that is closer to its midpoint, biased by zone_factor.
        #   boundary = from_m + span * zone_factor
        #   if zone_mid <= boundary  →  exit_pt = left node (from_m)
        #   else                     →  exit_pt = right node (to_m)

        def _live_evac_zone_calc():
            tbl      = self.evc_fireloc_table
            tl_m     = float(self.evc_tunnel_length.value())
            zf       = float(self.evc_zone_factor_s4.value())
            last_row = tbl.rowCount() - 1   # sentinel

            # Collect valid entries from fire-loc table (skip sentinel)
            fire_pts = []    # (pos_m,) for fire-source rows
            exit_pts = []    # (pos_m,) for exit rows

            for ri in range(last_row):
                name_itm = tbl.item(ri, 0)
                pos_itm  = tbl.item(ri, 1)
                if name_itm is None or pos_itm is None:
                    continue
                name = name_itm.text().strip()
                pos_txt = pos_itm.text().strip()
                if not name or not pos_txt:
                    continue
                try:
                    pos_m = float(pos_txt)
                except ValueError:
                    continue
                if name.lower() == "exit":
                    exit_pts.append(pos_m)
                else:
                    fire_pts.append(pos_m)

            # NEXIT = number of intermediate cross-passages (exit rows)
            n_exit = len(exit_pts)

            # VB: defaDistExit = TLENG*1000 / (NEXIT+1)
            default_spacing = tl_m / (n_exit + 1)

            # Build node list: entry(0) + n_exit intermediate + exit-end
            nodes = []   # list of pos_m values
            nodes.append(0.0)           # entry — always 0
            for k in range(1, n_exit + 1):
                # Use user-entered exit position if available; otherwise default
                if k - 1 < len(exit_pts):
                    nodes.append(exit_pts[k - 1])
                else:
                    nodes.append(default_spacing * k)
            nodes.append(tl_m)          # exit-end — always tunnel length

            # Build zones from consecutive node pairs
            zones = []   # list of (from_m, to_m, exit_pt_m)
            for k in range(len(nodes) - 1):
                from_m = nodes[k]
                to_m   = nodes[k + 1]
                span   = to_m - from_m
                mid_m  = from_m + span * 0.5
                # Zone divide factor shifts the drain-direction boundary
                boundary = from_m + span * zf
                exit_pt  = from_m if mid_m <= boundary else to_m
                zones.append((from_m, to_m, exit_pt))

            # Write results into evac zone table (read-only, no signals needed)
            ez = self.evc_evzone_table
            ez.setRowCount(len(zones))
            for ri, (frm, to, ep) in enumerate(zones):
                bg = ZONE_BG_ODD if ri % 2 else ZONE_BG_EVEN
                for ci, val in enumerate([frm, to, ep]):
                    txt = f"{val:.2f}"
                    itm = QTableWidgetItem(txt)
                    itm.setTextAlignment(Qt.AlignCenter)
                    itm.setBackground(bg)
                    ez.setItem(ri, ci, itm)
            _ez_resize_table(len(zones))

            # Update EVC / FDB spinboxes
            if fire_pts:
                self.evc_fp_evc_s4.setValue(fire_pts[0])
                self.evc_fp_evc.setValue(fire_pts[0])
            if n_exit > 0:
                self.evc_fp_fdb_s4.setValue(exit_pts[0])
                self.evc_fp_fdb.setValue(exit_pts[0])
            elif zones:
                self.evc_fp_fdb_s4.setValue(tl_m)
                self.evc_fp_fdb.setValue(tl_m)

        # Store reference so calculate_evac_zones() can also call it
        self._live_evac_zone_calc = _live_evac_zone_calc

        # Run once on startup to populate the zone table from the seed data
        _live_evac_zone_calc()

        # Trigger live recalc when tunnel length changes (Sub-tab 1 widget)
        self.evc_tunnel_length.valueChanged.connect(lambda _: _live_evac_zone_calc())

