    # ── public entry-point wired to the button ────────────────────────────────
    def _get_asym_exit_position_m(self) -> float:
        """Return the exit-connection position (m) for asymmetric fire placement.

        Reads the first 'exit' row from evc_fireloc_table (col 1 = position).
        Falls back to full tunnel length when no exit row is available.
        """
        tl_m = 0.0
        try:
            tl_m = float(self.evc_tunnel_length.value())
        except Exception:
            pass
        tbl = getattr(self, "evc_fireloc_table", None)
        if tbl is not None:
            last = tbl.rowCount() - 1
            for ri in range(last):
                name_itm = tbl.item(ri, 0)
                if name_itm and name_itm.text().strip().lower() == "exit":
                    pos_itm = tbl.item(ri, 1)
                    if pos_itm:
                        try:
                            ep = float(pos_itm.text().strip())
                            if ep > 0:
                                return ep
                        except ValueError:
                            pass
        return tl_m

    def _apply_rp_for_mode(self, is_asymmetric: bool):
        """Update the Results-tab RP(1..6) spinboxes to match the fire placement mode.

        Asymmetric:
            Uses tunnel_fire_positions_and_rp() with exit_position_m from the
            fire-location table (D73 equivalent) to populate F73:L73 fire-point
            mapping and M73:R73 RP(1..6) weights.

        Symmetric (N equal points):
            RP1–RP6 = 1/6 ≈ 0.1667  (equal weight per fire position)
        """
        if not hasattr(self, "t6_rp_inputs") or len(self.t6_rp_inputs) < 6:
            return
        if is_asymmetric:
            # Asymmetric mode: position-based RP from tunnel_fire_positions_and_rp
            tl_m = 0.0
            try:
                tl_m = float(self.evc_tunnel_length.value())
            except Exception:
                pass
            exit_pos = self._get_asym_exit_position_m()
            if tl_m > 0 and exit_pos > 0:
                result = tunnel_fire_positions_and_rp(tl_m, exit_pos, num_fire_points=len(self.t6_rp_inputs))
                weights = [round(rp / 100, 4) for rp in result["rp_percent"]]
            else:
                # geometry unavailable: keep neutral equal split
                weights = [round(1.0 / 6, 4)] * 6
        else:
            # Symmetric mode: equal weight per fire point
            weights = [round(1.0 / 6, 4)] * 6
        for sp, w in zip(self.t6_rp_inputs, weights):
            sp.blockSignals(True)
            sp.setValue(w)
            sp.blockSignals(False)

    def _estimate_fire_points(self):
        """Button handler — routes to symmetric or asymmetric implementation.

        Corrected convention:

          checkedId()==0  "Symmetric fire placement"
                          -> uniform full-tunnel spacing
                             (_calc_evc_zone_fire_points)

          checkedId()==1  "Asymmetric fire placement"
                          -> exit-position-based spacing
                             (_calc_evc_asymmetric_fire_points)
        """
        grp = getattr(self, "evc_fp_mode_group", None)
        if grp is not None and grp.checkedId() == 0:
            # Symmetric fire placement
            self._calc_evc_zone_fire_points(_skip_exits=True)
        else:
            # Asymmetric fire placement
            self._calc_evc_asymmetric_fire_points()

    def _autofill_mdb_pt_x(self, only_row: int | None = None) -> None:
        """Determine MDB pt. X for the Fire Point Mapping table — VB parity.

        Decompile grounding (now1.txt + reference_to_DAT_004a6000.txt):
        VB's auto-fill walks the loaded fire-database entries and assigns,
        per fire-point row, the X-coordinate of the database whose fire
        location brackets that point's zone:

            for each FPT row j:
                find DB entry i with  col1(j) <= X(i) <= col2(j)
                MDB_pt_X(j) = X(i)

        X(i) is the DB's own fire-source location — the FDB header's
        "FIRE PT" field (range midpoint, e.g. "317.000- 323.000" -> 320) —
        which is exactly what FDBData.fire_center / _parse_fdb_fire_pt read.
        With a single shared FDB (the standard workflow) every row receives
        the same value.  With several FDBs known (Filename List col 3 /
        per-scenario candidates), each fire point takes the DB whose fire X
        is nearest — the degenerate form of VB's interval match when zone
        bounds aren't carried in this table.

        The engine consumes the same anchor independently
        (EVCEngine: fdb_offset = fdb.fire_center − fire_x;
        x_query = current_pos + fdb_offset), so this column is the visible,
        checkable statement of the fire-point → database mapping, matching
        the VB UI.  Cells the user has typed over are repopulated only when
        Fire pt. X changes or fire points are re-estimated, same as VB's
        write-back loop.

        Auto-filled cells get a light-green tint to distinguish them from
        manual entries.
        """
        tbl = getattr(self, "evc_fpm_table_s4", None)
        if tbl is None:
            return

        # ── Collect candidate fire databases and their FIRE PT values ──
        db_pts = []   # list of (fire_pt_x_in_db, path)
        seen = set()

        def _add(path_str):
            p = (path_str or "").strip()
            if not p or p in seen:
                return
            seen.add(p)
            try:
                v = self._parse_fdb_fire_pt(p)
            except Exception:
                v = None
            if v is not None:
                db_pts.append((float(v), p))

        _add(getattr(self, "evc_fdb_path_le", None) and
             self.evc_fdb_path_le.text())
        # Filename List column 3 may carry per-scenario FDB files
        fn_tbl = getattr(self, "evc_s4_filename_table", None)
        if fn_tbl is not None:
            for r in range(fn_tbl.rowCount()):
                it = fn_tbl.item(r, 3)
                if it is not None:
                    _add(it.text())

        if not db_pts:
            return   # nothing known — leave MDB column untouched

        tint = QColor(232, 250, 236)
        rows = range(tbl.rowCount()) if only_row is None else [only_row]
        tbl.blockSignals(True)
        try:
            for ri in rows:
                fire_itm = tbl.item(ri, 1)
                try:
                    fx = float(fire_itm.text()) if fire_itm and \
                        fire_itm.text().strip() else None
                except ValueError:
                    fx = None
                if len(db_pts) == 1 or fx is None:
                    mdb_x = db_pts[0][0]
                else:
                    # nearest-DB selection (degenerate VB interval match)
                    mdb_x = min(db_pts, key=lambda t: abs(t[0] - fx))[0]
                itm = tbl.item(ri, 2)
                if itm is None:
                    itm = QTableWidgetItem("")
                    itm.setTextAlignment(Qt.AlignCenter)
                    tbl.setItem(ri, 2, itm)
                itm.setText(f"{mdb_x:.1f}")
                itm.setBackground(tint)
        finally:
            tbl.blockSignals(False)

    def _calc_evc_asymmetric_fire_points(self):
        """Asymmetric fire point placement (always 6 points).

        Uses tunnel_fire_positions_and_rp() — formula from
        터널교통량등제원, row 73, cols F:R:

            section_distance = exit_position_m / 6
            fire_positions   = [section_distance/2 + i*section_distance  for i in 0..5]
            RP_i             = zone_midpoint_span / total_length

        exit_position_m is read from the first 'exit' row in the fire-location
        table (D73 equivalent).  Falls back to TL × 0.775 when not set.
        """
        # ── tunnel length ────────────────────────────────────────────────────
        tl_m = 0.0
        try:
            tl_m = float(self.tbi_length.text().strip() or 0)
        except (ValueError, AttributeError):
            tl_m = 0.0
        if tl_m <= 0:
            tl_m = float(self.evc_tunnel_length.value())
        if tl_m <= 0:
            QMessageBox.warning(self, "Invalid Tunnel Length",
                "Tunnel length must be greater than 0.\n"
                "Please enter the tunnel length in Sub-tab 1 "
                "(Tunnel Info → Length field).")
            return

        self.evc_tunnel_length.blockSignals(True)
        self.evc_tunnel_length.setValue(tl_m)
        self.evc_tunnel_length.blockSignals(False)

        # ── compute positions and RP using the sheet-faithful formula ────────
        nfire    = max(2, self.evc_num_fp_s4.value())
        # For asymmetric row-73 mapping, sectioning is based on tunnel span.
        # We still call the helper with exit_pos for compatibility, but pass
        # tunnel length so the computed F73:L73 and M73:R73 align.
        exit_pos = tl_m
        result   = tunnel_fire_positions_and_rp(tl_m, exit_pos, num_fire_points=nfire)
        positions = result["fire_positions_m"]
        rp_pct    = result["rp_percent"]
        section_distance = result["spacing_m"]

        total = nfire
        self.evc_num_fp_s4.blockSignals(True)
        self.evc_num_fp_s4.setValue(total)
        self.evc_num_fp_s4.blockSignals(False)

        # ── populate Fire Point Mapping table ────────────────────────────────
        tbl = self.evc_fpm_table_s4
        tbl.blockSignals(True)
        tbl.setRowCount(total)

        asym_color = QColor(255, 230, 200)   # light orange for last point (tail zone)
        for row_idx, fp_x in enumerate(positions):
            itm0 = QTableWidgetItem(str(row_idx + 1))
            itm0.setTextAlignment(Qt.AlignCenter)
            tbl.setItem(row_idx, 0, itm0)

            itm1 = QTableWidgetItem(f"{fp_x:.1f}")
            itm1.setTextAlignment(Qt.AlignCenter)
            if row_idx == total - 1:  # last point — tail-zone
                itm1.setBackground(asym_color)
            tbl.setItem(row_idx, 1, itm1)

            itm2 = QTableWidgetItem("")
            itm2.setTextAlignment(Qt.AlignCenter)
            tbl.setItem(row_idx, 2, itm2)

        tbl.blockSignals(False)

        vis = min(total, 8)
        tbl.setFixedHeight(22 * vis + tbl.horizontalHeader().height() + 4)

        # VB parity: determine MDB pt. X from the loaded fire database(s)
        self._autofill_mdb_pt_x()

        rp_str = ", ".join(f"{r:.2f}%" for r in rp_pct)
        msg = (
            f"✅ Asymmetric fire points ({total}): exit_pos={exit_pos:.1f} m, "
            f"spacing={section_distance:.1f} m — "
            f"positions={positions}  RP=[{rp_str}]"
        )
        if hasattr(self, "evc_status_text"):
            self.evc_status_text.append(msg)

        # Sync Results-tab RP spinboxes directly from computed values
        if hasattr(self, "t6_rp_inputs") and len(self.t6_rp_inputs) >= 6:
            for sp, rp in zip(self.t6_rp_inputs, rp_pct):
                sp.blockSignals(True)
                sp.setValue(round(rp / 100, 4))
                sp.blockSignals(False)


    def _calc_evc_zone_fire_points(self, _skip_exits: bool = False):
        """Calculate fire point positions per zone using the Excel-verified formula.

        When *_skip_exits* is True (symmetric mode) exit nodes are ignored and
        the full tunnel is treated as a single zone, giving uniform TL/n spacing.

        Formula (confirmed from 터널교통량등제원 sheet, rows 68-73):

            Per zone:
                a = zone entry position (m)    ← boundary only, NOT a fire point
                b = zone exit  position (m)    ← boundary only, NOT a fire point
                n = NFIRE  (fire points per zone, from evc_num_fp_s4)
                k = b / n                      section width
                fn[0]   = a + (k / 2)          centre of first section
                fn[i]   = fn[i - 1] + k        each subsequent centre
                fn      = [round(x, 1) for x in fn]

        With no intermediate exits (NEXIT = 0):
            a = 0, b = TL → k = TL / n
            e.g. TL=690, n=6: k=115 → [57.5, 172.5, 287.5, 402.5, 517.5, 632.5]

        With exits (NEXIT > 0):
            The same formula is applied independently per zone.
            Zone i spans [nodes[i], nodes[i+1]].
            Each zone produces n fire points at the centres of its n sections.
            Total fire points = n × (NEXIT + 1).

        # ── SUPERSEDED IMPLEMENTATION (VB cEVCAZone — kept for reference) ────
        # The old code below used a different VB-style spacing formula that
        # applied ranevcfire edge margins at zone boundaries:
        #
        #   Edge zones (i==0 or i==NEXIT):
        #     sd = (zone_len - ranevcfire/2) / (NFIRE-1)
        #   Interior zones:
        #     sd = (zone_len - ranevcfire)   / (NFIRE-1)
        #
        # Fire point positions were then built cumulatively from the section
        # distance using different offsets for first/middle/last points and
        # for entry/interior/exit zone types (7 distinct cases).
        #
        # This was replaced by the simpler and spreadsheet-verified formula
        # above, which produces identical results for the standard case
        # (no ranevcfire margin needed when using uniform section centres).
        # ─────────────────────────────────────────────────────────────────────
        """
        # ── 1. Tunnel length ─────────────────────────────────────────────────
        tl_m = 0.0
        try:
            tl_m = float(self.tbi_length.text().strip() or 0)
        except (ValueError, AttributeError):
            tl_m = 0.0
        if tl_m <= 0:
            tl_m = float(self.evc_tunnel_length.value())
        if tl_m <= 0:
            QMessageBox.warning(self, "Invalid Tunnel Length",
                "Tunnel length must be greater than 0.\n"
                "Please enter the tunnel length in Sub-tab 1 "
                "(Tunnel Info → Length field).")
            return

        self.evc_tunnel_length.blockSignals(True)
        self.evc_tunnel_length.setValue(tl_m)
        self.evc_tunnel_length.blockSignals(False)

        # ── 2. Fire points per zone ───────────────────────────────────────────
        nfire = max(1, self.evc_num_fp_s4.value())

        # ── 3. Exit nodes from evc_fireloc_table ─────────────────────────────
        exit_nodes = []
        if not _skip_exits:   # when True (symmetric mode): single zone, ignore exits
            tbl_fl = self.evc_fireloc_table
            for ri in range(tbl_fl.rowCount()):
                name_itm = tbl_fl.item(ri, 0)
                pos_itm  = tbl_fl.item(ri, 1)
                if name_itm is None:
                    continue
                name = name_itm.text().strip()
                if name.lower() in ("", "+ add row"):
                    continue
                if name.lower() == "exit" and pos_itm:
                    try:
                        exit_nodes.append(float(pos_itm.text().strip()))
                    except ValueError:
                        pass
            exit_nodes.sort()
        n_exit  = len(exit_nodes)

        # ── 4. Zone node list: [0, exit1, exit2, ..., TL] ────────────────────
        defa_dist = tl_m / (n_exit + 1)
        nodes = [0.0]
        for ki in range(1, n_exit + 1):
            nodes.append(exit_nodes[ki - 1] if ki - 1 < len(exit_nodes)
                         else defa_dist * ki)
        nodes.append(tl_m)

        # ── 5. Apply formula per zone ─────────────────────────────────────────
        #
        #   For each zone i spanning [nodes[i], nodes[i+1]]:
        #
        #       a = nodes[i]        (zone entry — boundary only)
        #       b = nodes[i + 1]    (zone exit  — boundary only)
        #       n = nfire
        #       k = (b - a) / n     section width within this zone
        #
        #       fn[0]   = a + (k / 2)
        #       fn[j]   = fn[j - 1] + k
        #       fn      = [round(x, 1) for x in fn]
        #
        all_fire_x = []   # list of (zone_idx, point_idx, x_m)

        for i in range(n_exit + 1):
            a = nodes[i]         # zone entry boundary
            b = nodes[i + 1]     # zone exit  boundary

            k = (b - a) / nfire  # section width

            fn = [a + (k / 2)]
            for j in range(1, nfire):
                fn.append(fn[j - 1] + k)
            fn = [round(x, 1) for x in fn]

            for j, fp_x in enumerate(fn):
                all_fire_x.append((i, j, fp_x))

        # ── 6. Update spinner ────────────────────────────────────────────────
        total = len(all_fire_x)
        self.evc_num_fp_s4.blockSignals(True)
        self.evc_num_fp_s4.setValue(total)
        self.evc_num_fp_s4.blockSignals(False)

        # ── 7. Populate Fire Point Mapping table ─────────────────────────────
        tbl = self.evc_fpm_table_s4
        tbl.blockSignals(True)
        tbl.setRowCount(total)

        zone_colors = [
            QColor(255, 255, 255),   # zone 0 — white
            QColor(232, 244, 253),   # zone 1 — light blue
            QColor(232, 253, 232),   # zone 2 — light green
            QColor(253, 252, 232),   # zone 3 — light yellow
            QColor(253, 232, 253),   # zone 4 — light purple
            QColor(253, 244, 232),   # zone 5 — light orange
        ]

        for row_idx, (zone_i, fp_j, fp_x) in enumerate(all_fire_x):
            itm0 = QTableWidgetItem(str(row_idx + 1))
            itm0.setTextAlignment(Qt.AlignCenter)
            tbl.setItem(row_idx, 0, itm0)

            itm1 = QTableWidgetItem(f"{fp_x:.1f}")
            itm1.setTextAlignment(Qt.AlignCenter)
            itm1.setBackground(zone_colors[zone_i % len(zone_colors)])
            tbl.setItem(row_idx, 1, itm1)

            itm2 = QTableWidgetItem("")
            itm2.setTextAlignment(Qt.AlignCenter)
            tbl.setItem(row_idx, 2, itm2)

        tbl.blockSignals(False)

        # ── 8. Resize table height ────────────────────────────────────────────
        vis = min(total, 8)
        tbl.setFixedHeight(22 * vis + tbl.horizontalHeader().height() + 4)

        # ── 8b. VB parity: MDB pt. X from the loaded fire database(s) ────────
        self._autofill_mdb_pt_x()

        # ── 9. Log ────────────────────────────────────────────────────────────
        all_x = [x for _, _, x in all_fire_x]
        msg = (f"✅ Fire points ({total}) across {n_exit + 1} zone(s) "
               f"[n={nfire}/zone, TL={tl_m:.1f} m]: {all_x}")
        if hasattr(self, "evc_status_text"):
            self.evc_status_text.append(msg)

        # Sync Results-tab RP weights for symmetric (uniform-spacing) mode
        self._apply_rp_for_mode(is_asymmetric=False)

    def create_tab5_statistics(self):
        """Tab 5 — Man Position (Mesa OpenGL) + Monitoring Point (matplotlib).
        All figures use EVC tunnel length as the spatial reference.
        Simulate / Pause / Stop drive a QTimer that steps through all time frames.
        """
        import matplotlib
