        self.t5_xmin_sb.setRange(0, 99999); self.t5_xmin_sb.setValue(0)
        self.t5_xmin_sb.setFixedWidth(80)
        self.t5_xmin_sb.valueChanged.connect(self._t5_redraw_man)
        row2.addWidget(self.t5_xmin_sb)

