        ctrl_box.setFixedWidth(270)
        ctrl_gl = QGridLayout(ctrl_box)
        ctrl_gl.setContentsMargins(8, 8, 8, 8); ctrl_gl.setSpacing(5)

        ctrl_gl.addWidget(QLabel("Current time:"), 0, 0)
        self.t5_time_text = QLineEdit("T = 0 s")
        self.t5_time_text.setReadOnly(True); self.t5_time_text.setFixedWidth(90)
        ctrl_gl.addWidget(self.t5_time_text, 0, 1)

        _sel = QPushButton("Select Time")
        _sel.setStyleSheet("QPushButton{background:#7f8c8d;color:white;border-radius:3px;}")
        _sel.clicked.connect(self._t5_select_time_dialog)
        ctrl_gl.addWidget(_sel, 0, 2)

        self.t5_mon_scroll = QScrollBar(Qt.Horizontal)
        self.t5_mon_scroll.setMinimum(0); self.t5_mon_scroll.setMaximum(0)
        self.t5_mon_scroll.valueChanged.connect(self._t5_on_mon_scroll)
