    # ── Evacuation Time Setting helpers ───────────────────────────────────────

    def _evac_reset_veh_table(self):
        """Reset the vehicle evacuation table to factory defaults."""
        DEFAULTS = [
            ["PC (Passenger Car)", "4.5",  "1.8", "1.5", "0.10", "30",  "60",  "0", "0", "0", "0", "0.86"],
            ["BS (Small Bus)",     "7.0",  "2.3", "15",  "0.10", "60",  "90",  "0", "0", "0", "0", "0.03"],
            ["BL (Large Bus)",     "12.0", "2.5", "45",  "0.15", "90",  "120", "0", "0", "0", "0", "0.06"],
            ["TS (Small Truck)",   "5.0",  "1.9", "2.0", "0.05", "30",  "60",  "0", "0", "0", "0", "0.01"],
            ["TM (Medium Truck)",  "8.0",  "2.3", "2.0", "0.05", "45",  "90",  "0", "0", "0", "0", "0.02"],
            ["TL (Large Truck)",   "15.0", "2.5", "2.0", "0.05", "60",  "120", "0", "0", "0", "0", "0.01"],
            ["SP (Special)",       "20.0", "3.0", "2.0", "0.05", "90",  "180", "0", "0", "0", "0", "0.01"],
        ]
        tbl = self.evac_veh_table
        tbl.blockSignals(True)
        for ri, row in enumerate(DEFAULTS):
            for ci, val in enumerate(row):
                if ci > 0:  # skip type col (read-only)
                    item = tbl.item(ri, ci)
                    if item:
                        item.setText(val)
        tbl.blockSignals(False)
        self.evac_status_lbl.setText("↺  Table reset to defaults.")

    def _evac_load_avg_dat(self):
        """Load S?AVG.DAT file and populate Evac (1-4) columns."""
        path, _ = QFileDialog.getOpenFileName(
            self, "Select S?AVG.DAT File",
            str(self.project_dir) if self.project_dir else "",
            "DAT Files (*.dat *.DAT);;All Files (*.*)")
        if not path:
            return
        try:
            from pathlib import Path
            lines = Path(path).read_text(encoding='utf-8', errors='replace').splitlines()
            times = []
            for line in lines:
                line = line.strip()
                if not line or line.startswith('#') or line.startswith('T'):
                    continue
                parts = line.split()
                if len(parts) >= 2:
                    try:
                        times.append(float(parts[1]))  # SFX time
                    except ValueError:
                        pass
            if not times:
                self.evac_status_lbl.setText("⚠  No numeric time data found in file.")
                return
            # Distribute times into evac cols 7-10 (Evac 1-4) for each vehicle row
            tbl = self.evac_veh_table
            tbl.blockSignals(True)
            avg_t = sum(times) / len(times)
            for ri in range(tbl.rowCount()):
                for ci, t_val in enumerate([avg_t * 0.8, avg_t, avg_t * 1.1, avg_t * 1.2]):
                    item = tbl.item(ri, 7 + ci)
                    if item:
                        item.setText(f"{t_val:.1f}")
            tbl.blockSignals(False)
            self.evac_status_lbl.setText(
                f"✅  Loaded {len(times)} time steps from {Path(path).name} — avg {avg_t:.1f} s")
        except Exception as exc:
            self.evac_status_lbl.setText(f"⚠  Load error: {exc}")

    def _evac_get_params(self) -> dict:
        """Read the Evacuation Time Setting panel and return a structured dict.

        This is called by generate_evc_files() and _collect_evc_params() to
        embed the values into each generated .evc file.

        Returns:
            {
              'broadcast_time':         float (s),
              'delay_after_broadcast':  bool,
              'early_start_temp':       bool,
              'early_start_smoke':      bool,
              'min_speed':              float (m/s),
              'elderly_speed':          float (m/s),
              'time_interval':          int (s),
              'vehicles': [
                  { 'type', 'length_m', 'width_m', 'occupants',
                    'elderly_ratio', 'depart_t1', 'depart_t2',
                    'evac_1', 'evac_2', 'evac_3', 'evac_4', 'ratio' },
                  ...
              ]
            }
        """
        def _f(widget, default):
            try: return float(widget.value())
            except Exception: return default

        def _b(widget):
            try: return widget.isChecked()
            except Exception: return False

        vehicles = []
        tbl = getattr(self, 'evac_veh_table', None)
        if tbl:
            for ri in range(tbl.rowCount()):
                def _cell(ci, default=0.0):
                    item = tbl.item(ri, ci)
                    if item and item.text().strip():
                        try: return float(item.text())
                        except ValueError: return default
                    return default
                vehicles.append({
                    'type':         (tbl.item(ri, 0).text() if tbl.item(ri, 0) else ""),
                    'length_m':     _cell(1, 4.5),
                    'width_m':      _cell(2, 1.8),
                    'occupants':    _cell(3, 1.5),
                    'elderly_ratio': _cell(4, 0.10),
                    'depart_t1':    _cell(5, 30.0),
                    'depart_t2':    _cell(6, 60.0),
                    'evac_1':       _cell(7, 0.0),
                    'evac_2':       _cell(8, 0.0),
                    'evac_3':       _cell(9, 0.0),
                    'evac_4':       _cell(10, 0.0),
                    'ratio':        _cell(11, 0.0),
                })

        return {
            'broadcast_time':        _f(getattr(self, 'evac_broadcast_time', None), 180.0),
            'delay_after_broadcast': _b(getattr(self, 'evac_delay_after_broadcast', None)),
            'early_start_temp':      _b(getattr(self, 'evac_es_temperature', None)),
            'early_start_smoke':     _b(getattr(self, 'evac_es_smoke', None)),
            'min_speed':             _f(getattr(self, 'evac_min_speed', None), 0.45),
            'elderly_speed':         _f(getattr(self, 'evac_elderly_speed', None), 0.60),
            'abs_min_speed':         _f(getattr(self, 'evac_abs_min_speed', None), 0.50),
            'abs_elderly_speed':     _f(getattr(self, 'evac_abs_elderly_speed', None), 0.50),
            'time_interval':         int(getattr(self, 'evac_time_interval',
                                                 type('_', (), {'value': lambda s: 30})()).value()),
            'vehicles': vehicles,
        }

    # ── Tab5 helper methods ────────────────────────────────────────────────

    def _t5_browse_fdb(self):
        start = str(self.project_dir) if self.project_dir else ""
        path, _ = QFileDialog.getOpenFileName(
            self, "Select FDB File", start,
            "FDB Files (*.fdb *.FDB);;All Files (*.*)")
        if path:
            self.t5_fdb_le.setText(path)

    def _t5_get_evc_geometry(self):
        """Return (tunnel_len_m, exit_positions, fire_points) from EVC widgets."""
        try:
            tunnel_len = float(self.evc_tunnel_length.value())
        except Exception:
            tunnel_len = 410.0

        exits = []
        try:
            tbl = self.evc_evzone_table
            for r in range(tbl.rowCount()):
                item = tbl.item(r, 2)
                if item and item.text().strip():
                    exits.append(float(item.text().strip()))
        except Exception:
            pass

        fire_pts = []
        try:
            tbl = self.evc_fpm_table_s4
            for r in range(tbl.rowCount()):
                for col in (1, 2):
                    item = tbl.item(r, col)
                    if item and item.text().strip():
                        try:
                            fire_pts.append(float(item.text().strip()))
                            break
                        except ValueError:
                            pass
        except Exception:
            pass

        return tunnel_len, exits, fire_pts

    def _t5_load_fdb(self):
        """Parse selected FDB and populate both visualization panels."""
        path_str = self.t5_fdb_le.text().strip()
        if not path_str:
            QMessageBox.warning(self, "No File", "Please browse to a .fdb file first.")
            return
        fdb_path = Path(path_str)
        if not fdb_path.exists():
            QMessageBox.warning(self, "Not Found", f"File not found:\n{path_str}")
            return

        self.t5_status.setText(f"Loading {fdb_path.name} …")
        QApplication.processEvents()

        try:
            result = self._t5_parse_fdb_spatial(fdb_path)
            if result is None:
                self.t5_status.setText("Could not parse FDB file — check format.")
                return

            self._t5_fdb_data = result
            n_times = len(result['times'])
            n_pts   = len(result['x_coords'])

            self.t5_time_slider.setMaximum(max(0, n_times - 1))
            self.t5_time_slider.setValue(0)
            self.t5_mon_scroll.setMaximum(max(0, n_times - 1))
            self.t5_mon_scroll.setValue(0)

            # Xmin = 0, Xmax = EVC tunnel length
            tunnel_len, _, _ = self._t5_get_evc_geometry()
            self.t5_xmin_sb.setValue(0.0)
            self.t5_xmax_sb.setValue(tunnel_len)

            self._t5_time_idx = 0

            # Reveal fire-point radio buttons based on loaded fire points
            _, _, fire_pts_loaded = self._t5_get_evc_geometry()
            n_fp = max(1, len(fire_pts_loaded))
            for k, rb in enumerate(self._t5_fp_radios):
                rb.setVisible(k < n_fp)
            # Select P1 (index 0) by default on every fresh load
            self._t5_active_fp = 0
            self._t5_mc_state  = None
            if self._t5_fp_radios:
                self._t5_fp_radios[0].setChecked(True)

            self._t5_build_man_data(0)
            self._t5_redraw_man()
            self._t5_redraw_mon(0)

            self.t5_status.setText(
                f"\u2705  {fdb_path.name}  |  {n_pts} monitoring pts  |  "
                f"{n_times} time steps  |  "
                f"T = {result['times'][0]:.0f}\u2013{result['times'][-1]:.0f} s  |  "
                f"Tunnel L = {tunnel_len:.0f} m"
            )
        except Exception as exc:
            self.t5_status.setText(f"Load error: {exc}")

    def _t5_parse_fdb_spatial(self, fdb_path):
        """Parse FDB into 2-D arrays [t_idx, x_idx] for each quantity."""
        import numpy as np

        rows = []
        col_map = None
        in_data = False

        for enc in ('utf-8', 'latin-1', 'cp1252'):
            try:
                raw = fdb_path.read_bytes().decode(enc, errors='replace')
                break
            except Exception:
                continue

        # ── Extract FIRE PT from FDB header ──────────────────────────────
        import re as _re_fdb
        fdb_fire_pt = None
        _in_tunx = False; _tunx_hdr = False
        for _hl in raw.splitlines():
            _hs = _hl.strip()
            if _hs == 'TUNNEL X COORDINATE': _in_tunx = True; continue
            if not _in_tunx: continue
            if 'MIN_X' in _hs: _tunx_hdr = True; continue
            if _tunx_hdr and _hs:
                _parts = _hs.split()
                if len(_parts) >= 4:
                    _tail = ' '.join(_parts[3:])
                    _rm = _re_fdb.search(
                        r'([-+]?[0-9]+[.]?[0-9]*)\s*-\s*([-+]?[0-9]+[.]?[0-9]*)',
                        _tail)
                    if _rm:
                        fdb_fire_pt = (float(_rm.group(1)) + float(_rm.group(2))) / 2.0
                    else:
                        _sm = _re_fdb.search(r'[-+]?[0-9]+[.]?[0-9]*', _tail)
                        if _sm: fdb_fire_pt = float(_sm.group())
                break

        for line in raw.splitlines():
            line = line.strip()
            if not line or line.startswith('!') or line.startswith('#'):
                continue
            if 'DATA START' in line.upper():
                in_data = True; col_map = None; continue
            if 'DATA END' in line.upper():
                break
            if not in_data or all(c in '*|-= \t' for c in line):
                continue

            parts = line.split()
            try:
                nums = [float(p) for p in parts]
            except ValueError:
                up = [p.upper() for p in parts]
                col_map = {}
                for i, h in enumerate(up):
                    if 'TIME' in h:                        col_map['time']   = i
                    elif h in ('X', 'X-COOR', 'XCOOR'):   col_map['x']      = i
                    elif 'SOOT' in h:                      col_map['soot']   = i
                    elif 'CO2' in h:                       col_map['co2']    = i
                    elif 'CO' in h and 'CO2' not in h:     col_map['co']     = i
                    elif 'TEMP' in h:                      col_map['temp']   = i
                    elif 'RADI' in h:                      col_map['radi']   = i
                    elif 'OXY' in h or h == 'O2':          col_map['oxygen'] = i
                continue

            if len(nums) < 2:
                continue
            if col_map is None:
                col_map = {'time':0,'x':1,'soot':2,'co2':3,'co':4,'temp':5,'radi':6,'oxygen':7}

            def _g(k, d=0.0):
                idx = col_map.get(k)
                return nums[idx] if idx is not None and idx < len(nums) else d

            rows.append((_g('time'), _g('x'), _g('soot'), _g('co2'),
                         _g('co'), _g('temp', 20.0), _g('radi'), _g('oxygen', 21.0)))

        if not rows:
            return None

        import numpy as np
        arr = np.array(rows)
        times_u  = np.unique(arr[:, 0])
        x_coords = np.unique(arr[:, 1])
        nt, nx   = len(times_u), len(x_coords)

        t_map = {t: i for i, t in enumerate(times_u)}
        x_map = {x: i for i, x in enumerate(x_coords)}

        def _fill(col, default):
            A = np.full((nt, nx), default, dtype=float)
            for row in arr:
                ti = t_map.get(row[0]); xi = x_map.get(row[1])
                if ti is not None and xi is not None:
                    A[ti, xi] = row[col]
            return A

        temp_2d = _fill(5, 20.0)
        co_2d   = _fill(4, 0.0)
        soot_2d = _fill(2, 0.0)
        co2_2d  = _fill(3, 0.04)
        o2_2d   = _fill(7, 21.0)
        radi_2d = _fill(6, 0.0)

        # Walking velocity: free-flow reduced by CO exposure
        walk_2d = np.clip(1.2 * (1.0 - np.clip(co_2d / 35000.0, 0, 1)), 0.1, 1.2)

        # Cumulative FED along time axis
        dt_arr = np.diff(times_u, prepend=times_u[0])
        dt_arr[0] = dt_arr[1] if nt > 1 else 1.0
        fed_rate = (np.where(co_2d > 0, (co_2d ** 1.036) / 35000.0, 0.0)
                  + np.where(o2_2d < 21.0, ((21.0 - o2_2d) / 11.0) ** 3 / 60.0, 0.0)
                  + np.where(temp_2d > 20.0, (temp_2d ** 3.4) / 5e7, 0.0))
        fed_2d = np.cumsum(fed_rate * dt_arr[:, None] / 60.0, axis=0)

        return {
            'times':       times_u,
            'x_coords':    x_coords,
            'temperature': temp_2d,
            'co':          co_2d,
            'soot':        soot_2d * 1e6,
            'co2':         co2_2d,
            'o2':          o2_2d,
            'radiation':   radi_2d,
            'walk_vel':    walk_2d,
            'fed':         fed_2d,
            'fdb_fire_pt': fdb_fire_pt,
        }

    def _t5_build_man_data(self, t_idx):
        """Build occupant positions for Man Position at the given time step.

        Uses a VB-style Monte Carlo model (matching the EVC/AAA.xlsm logic):
        - Occupants are placed randomly at t=0 using a uniform distribution
          along the tunnel (or re-seeded from EVC geometry if available).
        - Each occupant accumulates FED using the FDB hazard data.
        - Walk velocity is reduced by CO / soot exposure (mirrors EVC walk-speed table).
        - Occupants choose evacuation direction away from the fire source (FIRE PT).
        - When FED >= 0.3 the occupant is incapacitated (cannot self-rescue).
        - When FED >= 1.0 the occupant is fatally affected.
        - Escaped occupants (reached an exit) are removed from the scatter.
        - State is stored in self._t5_mc_state so successive calls to
          _t5_build_man_data() advance the same population through time.
        """
        import numpy as np

        d = self._t5_fdb_data
        if d is None:
            self._t5_man_data = []
            self._t5_mc_state = None
            return

        xs     = d['x_coords']
        times  = d['times']
        tunnel_len, exits, fire_pts = self._t5_get_evc_geometry()
        if tunnel_len <= 0:
            tunnel_len = float(xs[-1]) if len(xs) else 410.0

        # ── Initialise occupant population at t=0 ──────────────────────────
        N_OCC  = 120          # number of virtual occupants (mirrors VB maxiter)
        RNG_SEED = 42

        # Rebuild population whenever we jump back to t=0 or state missing
        if t_idx == 0 or not hasattr(self, '_t5_mc_state') or self._t5_mc_state is None:
            rng = np.random.default_rng(RNG_SEED)

            # Uniform initial positions — exclude a 10 m band around fire
            # Use the user-selected fire point (self._t5_active_fp) as the
            # active fire position — determines evacuation direction and
            # occupant seeding exclusion zone, matching the VB FIRE PT logic.
            _fp_idx = getattr(self, '_t5_active_fp', 0)
            if fire_pts:
                _fp_idx = min(_fp_idx, len(fire_pts) - 1)
                fire_x = float(fire_pts[_fp_idx])
            else:
                fire_x = tunnel_len / 2.0
            pos_raw = rng.uniform(0.0, tunnel_len, N_OCC * 3)
            # reject positions within 10 m of fire source
            pos_raw = pos_raw[np.abs(pos_raw - fire_x) > 10.0][:N_OCC]
            if len(pos_raw) < N_OCC:          # fallback — just use uniform
                pos_raw = rng.uniform(0.0, tunnel_len, N_OCC)

            # Evacuation direction: move away from the fire (towards nearest exit)
            evac_dir = np.where(pos_raw < fire_x, -1.0, +1.0)   # -1 = towards 0, +1 = towards end

            # Reaction-time delay (seconds) — random uniform 0–180 s (VB: 대응시간)
            react_delay = rng.uniform(0, 180, N_OCC)

            self._t5_mc_state = {
                'pos':         pos_raw.copy(),        # current x position (m)
                'evac_dir':    evac_dir,              # ±1
                'fed':         np.zeros(N_OCC),       # cumulative FED
                'incap':       np.zeros(N_OCC, bool), # FED >= 0.3
                'fatal':       np.zeros(N_OCC, bool), # FED >= 1.0
                'escaped':     np.zeros(N_OCC, bool), # reached an exit
                'react_delay': react_delay,
                'last_t_idx':  -1,
                'exits':       exits if exits else [0.0, tunnel_len],
                'fire_x':      fire_x,
                'tunnel_len':  tunnel_len,
            }

        st = self._t5_mc_state

        # ── Advance simulation from last processed index to t_idx ──────────
        start_idx = max(0, st['last_t_idx'] + 1)
        if t_idx < st['last_t_idx']:
            # Rewind — rebuild from scratch (slider moved backward)
            self._t5_mc_state = None
            self._t5_build_man_data(t_idx)
            return

        # Helper: interpolate FDB quantity at an arbitrary x position
        def interp_at(arr_row, x_query):
            """Linear interpolation of a 1-D FDB row at position x_query."""
            return float(np.interp(x_query, xs, arr_row,
                                   left=arr_row[0], right=arr_row[-1]))

        for ti in range(start_idx, t_idx + 1):
            if ti == 0:
                continue
            dt = float(times[ti] - times[ti - 1])
            if dt <= 0:
                continue

            active = ~st['escaped'] & ~st['fatal']

            # FED increment for each active occupant
            for j in np.where(active)[0]:
                px = st['pos'][j]
                co_j   = interp_at(d['co'][ti],   px)
                o2_j   = interp_at(d['o2'][ti],   px)
                temp_j = interp_at(d['temperature'][ti], px)
                radi_j = interp_at(d['radiation'][ti], px)

                # FED rate — same model as _t5_parse_fdb_spatial / VB EVC FED
                fed_co   = (co_j ** 1.036) / 35000.0 if co_j > 0 else 0.0
                fed_o2   = ((21.0 - o2_j) / 11.0) ** 3 / 60.0 if o2_j < 21.0 else 0.0
                fed_heat = (temp_j ** 3.4) / 5e7 if temp_j > 20.0 else 0.0
                fed_radi = radi_j / 2.5e3 if radi_j > 0 else 0.0
                dfed = (fed_co + fed_o2 + fed_heat + fed_radi) * dt / 60.0
                st['fed'][j] = min(st['fed'][j] + dfed, 1.2)   # cap at 1.2

            # Update incapacitation / fatality flags
            st['incap'] |= (st['fed'] >= 0.3) & active
            st['fatal'] |= (st['fed'] >= 1.0) & active

            # Move occupants that are not incapacitated and past their reaction delay
            t_now = float(times[ti])
            for j in np.where(active & ~st['incap'])[0]:
                if t_now < st['react_delay'][j]:
                    continue          # still in reaction-time window

                px = st['pos'][j]

                # Walk velocity from FDB (reduced by hazard) — VB 최소이동속도 = 0.45 m/s
                wv = interp_at(d['walk_vel'][ti], px)
                wv = max(0.45, wv)   # VB min walk speed

                # Elderly ratio: ~14% (VB 노약자 비율)  → 0.6 m/s cap
                # (use occupant index parity as a deterministic proxy)
                if j % 7 == 0:
                    wv = min(wv, 0.6)

                step = wv * dt * st['evac_dir'][j]
                st['pos'][j] = px + step

            # Check exit reached
            exit_pts = np.array(st['exits'])
            for j in np.where(active)[0]:
                px = st['pos'][j]
                if np.any(np.abs(px - exit_pts) < 3.0) or px < -5.0 or px > tunnel_len + 5.0:
                    st['escaped'][j] = True

        st['last_t_idx'] = t_idx

        # ── Build point list for Man Position scatter ───────────────────────
        # Encode status as y-position within tunnel height band:
        #   Active/safe  : y in [4.5, 6.5]  (blue)
        #   Incapacitated: y in [1.5, 3.0]  (orange)
        #   Fatal        : y in [0.1, 0.5]  (red)  – stays at last position
        #   Escaped      : not drawn
        pts = []
        rng2 = np.random.default_rng(t_idx + 1)
        for j in range(N_OCC):
            if st['escaped'][j]:
                continue
            px = float(np.clip(st['pos'][j], 0.0, tunnel_len))
            if st['fatal'][j]:
                py = rng2.uniform(0.1, 0.5)
                status = 'fatal'
            elif st['incap'][j]:
                py = rng2.uniform(1.5, 3.0)
                status = 'incap'
            else:
                py = rng2.uniform(4.5, 6.5)
                status = 'active'
            pts.append((px, py, status))

        self._t5_man_data = pts

    def _t5_redraw_man(self):
        """Refresh Man Position panel using EVC tunnel length.

        Occupant dots are colour-coded by Monte Carlo evacuation status:
          Blue   — active / evacuating safely
          Orange — incapacitated (FED >= 0.3, cannot self-rescue)
          Red    — fatal (FED >= 1.0)
        Height bands encode status so dots spread vertically and are readable
        even at small panel sizes.
        """
        import numpy as np
        d    = getattr(self, "_t5_fdb_data",   None)
        pts  = getattr(self, "_t5_man_data",   []) or []
        xmin = self.t5_xmin_sb.value()
        xmax = self.t5_xmax_sb.value()
        t_val = (d['times'][self._t5_time_idx]
                 if d is not None and len(d['times']) > 0 else 0.0)

        tunnel_len, exits, fire_pts = self._t5_get_evc_geometry()

        # Tally occupant counts for title
        n_active = sum(1 for p in pts if len(p) > 2 and p[2] == 'active')
        n_incap  = sum(1 for p in pts if len(p) > 2 and p[2] == 'incap')
        n_fatal  = sum(1 for p in pts if len(p) > 2 and p[2] == 'fatal')
        n_esc    = (120 - len(pts)) if d is not None else 0

        if self._t5_gl_available:
            counts     = {'active': n_active, 'incap': n_incap,
                          'fatal': n_fatal, 'escaped': n_esc}
            active_fp  = getattr(self, '_t5_active_fp', 0)
            act_idx_gl = min(active_fp, len(fire_pts) - 1) if fire_pts else 0
            dyn_fdb_fp = float(fire_pts[act_idx_gl]) if fire_pts else None
            self.t5_gl.update_data(pts, xmin, xmax, 7.0, exits, fire_pts, t_val,
                                   counts=counts, active_fp=active_fp,
                                   fdb_fire_pt=dyn_fdb_fp)
        else:
            ax = self.t5_man_ax
            ax.clear()
            ax.set_facecolor('#d6eaf8')
            ax.set_title(
                f"Man Position  T = {t_val:.0f} s  |  "
                f"Active:{n_active}  Incap:{n_incap}  Fatal:{n_fatal}  Escaped:{n_esc}"
                f"  |  L = {tunnel_len:.0f} m",
                fontsize=8, fontweight='bold')
            ax.set_xlabel("Tunnel Position (m)", fontsize=8)
            ax.set_ylabel("Status Band",         fontsize=8)
            ax.set_xlim(xmin, xmax); ax.set_ylim(-0.5, 8.0)

            # Horizontal zone bands — no label= so they never appear in legend
            ax.axhspan(4.5, 6.5, alpha=0.08, color='#1a78c2')
            ax.axhspan(1.5, 3.0, alpha=0.10, color='#e67e22')
            ax.axhspan(0.1, 0.5, alpha=0.12, color='#c0392b')
            ax.axhline(3.5, color='#999', lw=0.5, ls=':')
            ax.axhline(1.0, color='#999', lw=0.5, ls=':')

            # Exit lines
            for ex in exits:
                if xmin <= ex <= xmax:
                    ax.axvline(ex, color='#27ae60', lw=1.5, ls='--', alpha=0.8)
                    ax.text(ex, 7.25, 'Exit', ha='center', va='bottom',
                            fontsize=6, color='#27ae60', fontweight='bold')

            # ── EVC fire point markers ──────────────────────────────────
            active_fp  = getattr(self, '_t5_active_fp', 0)
            act_fp_idx = min(active_fp, len(fire_pts) - 1) if fire_pts else 0
            act_fp_x   = float(fire_pts[act_fp_idx]) if fire_pts else None
            for i, fx in enumerate(fire_pts):
                if xmin <= fx <= xmax:
                    is_active = (i == act_fp_idx)
                    if is_active:
                        ax.scatter([fx], [0.3], marker='^', s=160,
                                   c='#e74c3c', zorder=6, edgecolors='#7b0000', linewidths=1.2)
                    else:
                        ax.scatter([fx], [0.3], marker='^', s=60,
                                   facecolors='none', edgecolors='#e74c3c',
                                   linewidths=1.0, zorder=5, alpha=0.5)
                    label_color  = '#c0392b' if is_active else '#aaa'
                    label_weight = 'bold'    if is_active else 'normal'
                    ax.text(fx, 0.62, f"P{i+1}", ha='center', va='bottom',
                            fontsize=7, color=label_color, fontweight=label_weight)

            # ── Gold ◆ diamond on selected Pn (dynamic, always = act_fp_x) ─
            if act_fp_x is not None and xmin <= act_fp_x <= xmax:
                ax.scatter([act_fp_x], [0.3], marker='D', s=130,
                           c='#FFD700', edgecolors='#2c3e50',
                           linewidths=1.5, zorder=7, alpha=0.95)
                ax.text(act_fp_x, -0.1, '◆FDB',
                        ha='center', va='top', fontsize=5,
                        color='#2c3e50', fontweight='bold',
                        bbox=dict(boxstyle='round,pad=0.15',
                                  fc='#FFD700', ec='#2c3e50',
                                  lw=0.6, alpha=0.88),
                        zorder=8)
                ax.axvline(act_fp_x, color='#FFD700', lw=1.1,
                           ls=':', alpha=0.65, zorder=3)

            lw_man = getattr(self.t5_lw_sb, 'value', lambda: 1.0)()
            dot_s  = max(8, int(lw_man * 25))

            # Scatter by status category — no legend labels (legend is the external strip)
            if pts:
                def _scatter_group(status, color):
                    sub = [(p[0], p[1]) for p in pts
                           if xmin <= p[0] <= xmax
                           and (len(p) > 2 and p[2] == status)]
                    if sub:
                        ax.scatter([p[0] for p in sub], [p[1] for p in sub],
                                   s=dot_s, c=color, alpha=0.85, zorder=4)

                _scatter_group('active', '#1a3a8c')
                _scatter_group('incap',  '#e67e22')
                _scatter_group('fatal',  '#c0392b')

            # Y-axis custom ticks — keep for spatial reference, no legend needed
            ax.set_yticks([0.3, 2.25, 5.5])
            ax.set_yticklabels(['Fatal', 'Incap.', 'Active'], fontsize=7)

            # NO ax.legend() call — legend lives in the external Row 3 strip
            ax.grid(True, lw=0.4, alpha=0.4)
            self.t5_man_canvas.draw_idle()

    def _t5_redraw_mon(self, t_idx):
        """Refresh all 8 Monitoring Point subplots (4×2 grid).

        X axis : tunnel position in metres (0 → tunnel_len).

        Profile alignment:
          The FDB fire source is at fdb_fire_pt (from header).
          When a different fire point Pn is selected, the profile is
          shifted so the peak aligns with act_fx:
              xs_plot = xs_raw - fdb_fire_pt + act_fx

          Out-of-range regions (where xs_plot falls outside [0, tunnel_len])
          are set to NaN so they render as blank — no ghost artefacts from
          the previous fire point position or the default starting position.

        Twin-axis cleanup:
          All orphaned twinx() siblings are fully removed before each redraw
          to prevent accumulated ghost lines from previous fire point selections.
        """
        import numpy as np
        import matplotlib.patches as mpatches
        from matplotlib.patches import Ellipse
        from matplotlib.path import Path

        d = getattr(self, "_t5_fdb_data", None)
        if d is None:
            return

        t_val  = d['times'][t_idx]
        t_max  = float(d['times'][-1]) if len(d['times']) > 1 else 1.0
        t_frac = float(t_val) / t_max if t_max > 0 else 0.0

        self.t5_time_lbl.setText(f"T = {t_val:.0f} s")
        self.t5_time_text.setText(f"T = {t_val:.0f} s")

        tunnel_len, exits, fire_pts = self._t5_get_evc_geometry()
        xs_raw    = d['x_coords']
        active_fp = getattr(self, '_t5_active_fp', 0)
        fdb_fp    = d.get('fdb_fire_pt')

        # ── Selected fire point X ────────────────────────────────────────────
        if fire_pts:
            act_idx = min(active_fp, len(fire_pts) - 1)
            act_fx  = float(fire_pts[act_idx])
        else:
            act_idx = 0
            act_fx  = fdb_fp

        # ── Coordinate shift so FDB peak aligns with selected Pn ────────────
        if fdb_fp is not None and act_fx is not None:
            shift   = act_fx - fdb_fp
            xs_plot = xs_raw + shift
        else:
            shift   = 0.0
            xs_plot = xs_raw

        # ── Dense display grid over the full tunnel ──────────────────────────
        N_DISP    = max(len(xs_raw), 300)
        x_display = np.linspace(0.0, float(tunnel_len), N_DISP)

        # Valid FDB data range after shifting
        xs_lo = float(xs_plot[0])
        xs_hi = float(xs_plot[-1])

        def _shifted_profile(arr_row):
            """Shift + interpolate arr_row onto x_display.
            Values outside the shifted FDB range are NaN so they are invisible
            — this completely eliminates ghost artefacts from the old position.
            """
            vals = np.interp(x_display, xs_plot, arr_row.astype(float),
                             left=np.nan, right=np.nan)
            # Also NaN any display points outside valid range (guards rounding)
            vals[x_display < xs_lo] = np.nan
            vals[x_display > xs_hi] = np.nan
            return vals

        def _norm_masked(arr):
            """Normalise ignoring NaN."""
            valid = arr[np.isfinite(arr)]
            if len(valid) == 0 or valid.max() - valid.min() < 1e-12:
                return np.zeros_like(arr)
            mn, mx = valid.min(), valid.max()
            return (arr - mn) / (mx - mn)

        lw = getattr(self.t5_lw_sb, 'value', lambda: 1.0)()
        ms = max(1.0, lw * 2.5)

        BLUE     = '#1565C0'
        AMBER    = '#E67E22'
        PINK     = '#D81B60'
        GOLD     = '#FFD700'
        DARK     = '#2c3e50'
        RED_EDGE = '#c0392b'

        _RAD_ALPHAS = [0.35, 0.26, 0.18, 0.12, 0.07]
        _RAD_FRACS  = [0.04, 0.08, 0.13, 0.19, 0.26]

        def _clear_ax_fully(ax):
            """Remove all twinx siblings then cla() the primary axis.
            Prevents ghost lines accumulating across fire point changes.
            """
            fig = ax.get_figure()
            # Collect all axes that share x with this one (twinx siblings)
            siblings = [a for a in fig.axes
                        if a is not ax and a.get_shared_x_axes().joined(a, ax)]
            for sib in siblings:
                sib.remove()
            ax.cla()

        def _draw_radiation_circles(ax, fx):
            ylo, yhi = ax.get_ylim()
            yr    = yhi - ylo
            tl    = tunnel_len if tunnel_len > 0 else 400.0
            scale = max(0.05, t_frac ** 0.5)
            for alpha, rf in zip(_RAD_ALPHAS, _RAD_FRACS):
                rx = rf * tl * scale
                ry = rf * yr * scale * 2.5
                ax.add_patch(Ellipse(
                    (fx, ylo + yr * 0.5), width=rx * 2, height=ry * 2,
                    facecolor=AMBER, edgecolor=AMBER, linewidth=0.6,
                    alpha=alpha * (0.4 + 0.6 * scale), zorder=2, clip_on=True))

        def _draw_evc_triangle(ax, fx, is_active, label):
            ylo, yhi = ax.get_ylim()
            yr  = yhi - ylo
            y_t = ylo + yr * 0.06
            if is_active:
                ax.scatter([fx], [y_t], marker='^', s=120,
                           c='#e74c3c', edgecolors='#7b0000',
                           linewidths=1.2, zorder=8, clip_on=True)
                ax.text(fx, y_t + yr * 0.04, label, fontsize=6,
                        color=RED_EDGE, fontweight='bold',
                        ha='center', va='bottom', zorder=9, clip_on=True)
            else:
                ax.axvline(fx, color='#e74c3c', lw=0.5, ls='--',
                           alpha=0.28, zorder=3)
                ax.text(fx, ylo + yr * 0.01, label, fontsize=5,
                        color='#e74c3c', alpha=0.5,
                        ha='center', va='bottom', zorder=4, clip_on=True)

        def _draw_fdb_diamond(ax, fx):
            ylo, yhi = ax.get_ylim()
            yr  = yhi - ylo
            tl  = tunnel_len if tunnel_len > 0 else 400.0
            y_d = ylo + yr * 0.02
            hs  = tl * 0.011
            hh  = yr * 0.045
            ax.add_patch(mpatches.Polygon(
                [[fx, y_d - hh], [fx - hs, y_d],
                 [fx, y_d + hh], [fx + hs, y_d]],
                closed=True, facecolor=GOLD, edgecolor=DARK,
                linewidth=1.3, zorder=10, clip_on=True))
            ax.axvline(fx, color=GOLD, lw=1.0, ls=':', alpha=0.65, zorder=5)
            ax.text(fx, y_d + hh + yr * 0.005, '◆FDB',
                    fontsize=5, color=DARK, fontweight='bold',
                    ha='center', va='bottom', zorder=11, clip_on=True)

        # ── Draw all 8 subplots ──────────────────────────────────────────────
        for (idx, title, key, unit) in self._t5_subplot_cfg:
            ax = self.t5_mon_axes_flat.flat[idx]

            # ── Full cleanup: remove orphaned twin axes, then clear primary ──
            _clear_ax_fully(ax)

            # Create fresh twin axis for normalised line
            ax2 = ax.twinx()

            is_radi  = (key == 'radiation')
            line_col = AMBER if is_radi else BLUE

            # Shifted + NaN-masked profiles
            row_data  = _shifted_profile(d[key][t_idx])
            norm_data = _norm_masked(row_data)

            # Marker density: ~60 dots regardless of N_DISP
            mevery = max(1, N_DISP // 60)

            ax.plot(x_display, row_data,  color=line_col, lw=lw,
                    marker='o', ms=ms, zorder=3, markevery=mevery)
            ax2.plot(x_display, norm_data, color=PINK, lw=max(0.5, lw * 0.7),
                     ls='--', marker='s', ms=max(1, ms * 0.7), zorder=2,
                     markevery=mevery)

            for ex in exits:
                ax.axvline(ex, color='#27ae60', lw=0.7, ls=':', alpha=0.6)

            # ── Axes limits set before patches ──────────────────────────────
            ax.set_xlim(0.0, float(tunnel_len))
            ax.set_title(title, fontsize=9, fontweight='bold', pad=4)
            ax.set_facecolor('#fffbf0' if is_radi else '#ffffff')
            ax.tick_params(axis='y', labelsize=8, colors=line_col)
            ax.tick_params(axis='x', labelsize=8)
            ax.set_xlabel("Tunnel Position (m)", fontsize=8)
            if unit:
                ax.set_ylabel(unit, fontsize=8, color=line_col)
            ax.yaxis.label.set_color(line_col)
            ax.grid(True, lw=0.4, alpha=0.45)

            ax2.set_ylim(0.0, 1.0)
            ax2.tick_params(labelsize=7, colors=PINK)
            ax2.set_ylabel("norm", fontsize=7, color=PINK)

            # ── Radiation expanding circles (bottom layer) ───────────────────
            if is_radi and act_fx is not None:
                _draw_radiation_circles(ax, act_fx)

            # ── Inactive fire point ghost lines ──────────────────────────────
            for fi, fx in enumerate(fire_pts):
                if fi != act_idx:
                    _draw_evc_triangle(ax, fx, is_active=False,
                                       label=f'P{fi+1}')

            # ── Active EVC triangle ──────────────────────────────────────────
            if act_fx is not None:
                _draw_evc_triangle(ax, act_fx, is_active=True,
                                   label=f'P{act_idx+1}')

            # ── Gold ◆ diamond exactly on active fire point (top layer) ──────
            if act_fx is not None:
                _draw_fdb_diamond(ax, act_fx)

        # ── Suptitle ─────────────────────────────────────────────────────────
        _act_lbl   = (f"P{act_idx+1} @ X={act_fx:.1f} m"
                      if act_fx is not None else "—")
        _shift_lbl = (f"shift {shift:+.1f} m"
                      if fdb_fp is not None else "no FDB header")
        _hdr_lbl   = (f"FDB src: {fdb_fp:.1f} m"
                      if fdb_fp is not None else "")
        self.t5_mon_fig.suptitle(
            f"Monitoring Point  —  T = {t_val:.0f} s"
            f"  |  Selected: {_act_lbl}  ({_shift_lbl})"
            f"  |  {_hdr_lbl}"
            f"  |  L = {tunnel_len:.0f} m",
            fontsize=9, fontweight='bold')
        self.t5_mon_canvas.draw_idle()


    # ── Reset + thickness ─────────────────────────────────────────────

    def _t5_clear_all_traces(self):
        """Stop the timer, wipe internal data, and blank both canvases.
        Uses ax.cla() — never destroys or recreates figure objects,
        so widgets always stay in the layout."""
        # Stop any running simulation
        if hasattr(self, '_t5_timer') and self._t5_timer.isActive():
            self._t5_timer.stop()

        # Wipe internal state
        self._t5_fdb_data    = None
        self._t5_time_idx    = 0
        self._t5_man_data    = []
        self._t5_mc_state    = None
        self._t5_active_fp   = 0
        self._t5_sim_running = False
        self._t5_sim_paused  = False

        # Hide all fire-point radio buttons and deselect
        for rb in getattr(self, '_t5_fp_radios', []):
            rb.setVisible(False)
            rb.setChecked(False)

        # Reset slider / scrollbar / labels
        for w in (self.t5_time_slider, self.t5_mon_scroll):
            w.blockSignals(True)
            w.setMaximum(0); w.setValue(0)
            w.blockSignals(False)
        self.t5_time_lbl.setText("T = 0 s")
        self.t5_time_text.setText("T = 0 s")

        # Reset playback buttons
        self.t5_sim_btn.setEnabled(True)
        self.t5_pause_btn.setEnabled(False)
        self.t5_pause_btn.setText("⏸ Pause")
        self.t5_stop_btn.setEnabled(False)

        # ── Man Position: clear canvas ──────────────────────────────────
        if self._t5_gl_available:
            self.t5_gl.update_data([], 0, self.t5_xmax_sb.value(), 7.0, [], [], 0.0,
                                   counts={'active':0,'incap':0,'fatal':0,'escaped':0},
                                   active_fp=0, fdb_fire_pt=None)
        elif hasattr(self, 't5_man_ax'):
            self.t5_man_ax.cla()
            self.t5_man_ax.set_facecolor('#d6eaf8')
            self.t5_man_ax.set_title(
                "Man Position  (Refresh or Load a FDB file to begin)",
                fontsize=9, color='#666')
            self.t5_man_ax.set_xlabel("Tunnel Position (m)", fontsize=8)
            self.t5_man_ax.set_ylabel("Tunnel Height (m)",   fontsize=8)
            self.t5_man_ax.grid(True, lw=0.4, alpha=0.4)
            self.t5_man_canvas.draw_idle()

        # ── Monitoring Point: fully clear all 8 subplots ───────────────
        # Remove every twinx() sibling before cla() so no ghost lines
        # survive a fire point switch or a full reset.
        if hasattr(self, 't5_mon_axes_flat'):
            for (i, title, key, unit) in self._t5_subplot_cfg:
                ax  = self.t5_mon_axes_flat.flat[i]
                fig = ax.get_figure()
                # Remove all twinx siblings (they are extra Axes on the figure)
                for sib in [a for a in fig.axes
                            if a is not ax
                            and a.get_shared_x_axes().joined(a, ax)]:
                    sib.remove()
                ax.cla()
                ax.set_title(title, fontsize=9, fontweight='bold', pad=4)
                ax.set_facecolor('#ffffff')
                ax.tick_params(labelsize=8)
                ax.set_xlabel("Tunnel Position (m)", fontsize=8)
                if unit:
                    ax.set_ylabel(unit, fontsize=8)
                ax.grid(True, lw=0.4, alpha=0.5)
            self.t5_mon_fig.suptitle("")
            self.t5_mon_canvas.draw_idle()

    def _t5_refresh(self):
        """Clear all graph traces and reload the current FDB from frame 0.
        Keeps the FDB path, Xmin/Xmax, speed and thickness settings."""
        fdb_path = self.t5_fdb_le.text().strip()
        if not fdb_path:
            self.t5_status.setText(
                "⚠  No FDB file loaded — nothing to refresh.  Use Browse + Load first.")
            return

        self.t5_status.setText("🔄  Refreshing … clearing traces and reloading FDB …")
        QApplication.processEvents()

        # Wipe all canvases and internal state
        self._t5_clear_all_traces()

        # Reload the same file from frame 0
        self._t5_load_fdb()

        self.t5_status.setText(
            f"🔄  Refreshed — {Path(fdb_path).name} reloaded from T = 0")

    def _t5_reset(self):
        """Full blank-slate reset: clears all data AND the FDB path.
        Use when starting a completely new simulation session."""
        self._t5_clear_all_traces()

        # Also wipe the file path and restore default range controls
        self.t5_fdb_le.clear()
        self.t5_xmin_sb.setValue(0.0)
        self.t5_xmax_sb.setValue(4200.0)
        self.t5_lw_sb.setValue(1.0)
        self.t5_speed_sb.setValue(1)

        self.t5_status.setText(
            "↺  Reset complete — all data cleared.  Browse and Load a new .fdb file to begin.")

    def _t5_on_thickness_changed(self, _val):
        """Re-draw both panels when thickness spinbox changes."""
        if getattr(self, '_t5_fdb_data', None) is None:
            return
        self._t5_redraw_man()
        self._t5_redraw_mon(self._t5_time_idx)

    # ── Simulation (Simulate / Pause / Stop) ──────────────────────────────

    def _t5_sim_start(self):
        """Start or resume continuous time-step animation."""
        d = self._t5_fdb_data
        if d is None:
            QMessageBox.warning(self, "No Data", "Load a FDB file first.")
            return

        if self._t5_sim_paused:
            # Resume from current position
            self._t5_sim_paused = False
            self.t5_pause_btn.setText("\u23f8 Pause")
        else:
            # Fresh start from current slider position
            pass

        self._t5_sim_running = True
        interval = max(100, int(500 / self.t5_speed_sb.value()))
        self._t5_timer.setInterval(interval)
        self._t5_timer.start()

        self.t5_sim_btn.setEnabled(False)
        self.t5_pause_btn.setEnabled(True)
        self.t5_stop_btn.setEnabled(True)
        self.t5_status.setText(
            f"Simulating \u2026  speed {self.t5_speed_sb.value()}\u00d7  "
            f"({self._t5_timer.interval()} ms/tick)")

    def _t5_sim_pause(self):
        """Pause or resume the animation."""
        if self._t5_sim_paused:
            # Resume
            self._t5_sim_paused = False
            self._t5_timer.start()
            self.t5_pause_btn.setText("\u23f8 Pause")
            self.t5_sim_btn.setEnabled(False)
            self.t5_status.setText("Simulating \u2026 (resumed)")
        else:
            # Pause
            self._t5_sim_paused = True
            self._t5_timer.stop()
            self.t5_pause_btn.setText("\u25b6 Resume")
            self.t5_sim_btn.setEnabled(True)
            d = self._t5_fdb_data
            t_val = d['times'][self._t5_time_idx] if d else 0
            self.t5_status.setText(f"Paused at T = {t_val:.0f} s  —  press Resume or Simulate to continue")

    def _t5_sim_stop(self):
        """Stop and reset to first frame."""
        self._t5_timer.stop()
        self._t5_sim_running = False
        self._t5_sim_paused  = False

        self.t5_sim_btn.setEnabled(True)
        self.t5_pause_btn.setEnabled(False)
        self.t5_pause_btn.setText("\u23f8 Pause")
        self.t5_stop_btn.setEnabled(False)

        # Rewind to frame 0
        self.t5_time_slider.setValue(0)
        self.t5_status.setText("Stopped.  Slider reset to T = 0.")

    def _t5_sim_tick(self):
        """Called every timer interval — advance one (or more) time step(s)."""
        d = self._t5_fdb_data
        if d is None:
            self._t5_sim_stop(); return

        n_times = len(d['times'])
        steps   = self.t5_speed_sb.value()
        nxt     = self._t5_time_idx + steps

        if nxt >= n_times:
            # Reached end — stop automatically
            nxt = n_times - 1
            self.t5_time_slider.setValue(nxt)
            self._t5_sim_stop()
            self.t5_status.setText(
                f"Simulation complete.  Final T = {d['times'][nxt]:.0f} s")
            return

        # Advance slider (triggers _t5_on_time_changed → redraws both panels)
        self.t5_time_slider.setValue(nxt)

    # ── Time navigation ────────────────────────────────────────────────────

    def _t5_on_time_changed(self, val):
        """Slider moved — redraw both panels."""
        d = self._t5_fdb_data
        if d is None:
            return
        self._t5_time_idx = val
        self.t5_mon_scroll.blockSignals(True)
        self.t5_mon_scroll.setValue(val)
        self.t5_mon_scroll.blockSignals(False)
        self._t5_build_man_data(val)
        self._t5_redraw_man()
        self._t5_redraw_mon(val)

    def _t5_on_mon_scroll(self, val):
        """Bottom-panel scrollbar moved — sync with main slider."""
        self.t5_time_slider.blockSignals(True)
        self.t5_time_slider.setValue(val)
        self.t5_time_slider.blockSignals(False)
        self._t5_on_time_changed(val)

    def _t5_select_time_dialog(self):
        """Pop a dialog for typing an exact time value."""
        d = self._t5_fdb_data
        if d is None:
            return
        import numpy as np
        t_now = d['times'][self._t5_time_idx]
        t_min = float(d['times'][0])
        t_max = float(d['times'][-1])
        val, ok = QInputDialog.getDouble(
            self, "Select Time",
            f"Enter time (s)  [{t_min:.0f} \u2013 {t_max:.0f}]:",
            t_now, t_min, t_max, 1)
        if ok:
            import numpy as np
            idx = int(np.argmin(np.abs(d['times'] - val)))
            self.t5_time_slider.setValue(idx)

    def _t5_export_csv(self):
        """Export current time-step spatial data as CSV."""
        import numpy as np
        d = self._t5_fdb_data
        if d is None:
            QMessageBox.warning(self, "No Data", "Load a FDB file first.")
            return
        t_idx = self._t5_time_idx
        t_val = d['times'][t_idx]
        path, _ = QFileDialog.getSaveFileName(
            self, "Export CSV",
            str(Path(self.project_dir) / f"mon_pt_T{t_val:.0f}s.csv")
            if self.project_dir else "",
            "CSV Files (*.csv)")
        if not path:
            return
        xs   = d['x_coords']
        keys = ['temperature','co','soot','co2','o2','radiation','walk_vel','fed']
        hdrs = ['X_m','Pt_No','Temp_degC','CO_ppm','Soot_mg_m3',
                'CO2_pct','O2_pct','Radi_kW_m2','WalkVel_m_s','FED']
        try:
            with open(path, 'w', newline='', encoding='utf-8') as f:
                f.write(','.join(hdrs) + '\n')
                for xi, x in enumerate(xs):
                    row = [f"{x:.3f}", str(xi + 1)] + [
                        f"{d[k][t_idx, xi]:.6g}" for k in keys]
                    f.write(','.join(row) + '\n')
            self.t5_status.setText(
                f"\u2705 Exported: {Path(path).name}  (T = {t_val:.0f} s, {len(xs)} pts)")
        except Exception as exc:
            QMessageBox.warning(self, "Export Error", str(exc))

    def create_tab6_risk_calculation(self):
        """Tab 6 — Post-Result Processing.

        Sub-tabs mirror the relevant sheets in _FNCV_ROAD.xlsm:
          1. EVC Result        (EVCResultStart / EVC Result sheet6)
          2. EVC_Result_BF     (sheet7 — AVG rows, decoded scenario columns)
          3. EVC_Result_BF2    (sheet8 — ResultBF2Table pivot)
          4. Standard Scenario (표준시나리오 sheet10 — SenarioTable, RP weights)
          5. Raw Scenario      (Raw_Senario sheet12 — per-row frequency/risk)
          6. Raw FNC           (Raw_FNC sheet13 — FN curve step data)
          7. FN Curve          (FNCurve2 sheet11 — chart + CalAvg controls)
        """
        import json, sqlite3, math
        from pathlib import Path

        # ── Outer tab widget ─────────────────────────────────────────────────
        outer = QWidget()
        outer_layout = QVBoxLayout(outer)
        outer_layout.setContentsMargins(4, 4, 4, 4)
        outer_layout.setSpacing(4)

        # ── Title bar ────────────────────────────────────────────────────────
        _hdr = QLabel("📊  Post-Result Processing")
        _hdr.setStyleSheet(
            "font-size:15px;font-weight:bold;color:#2c3e50;padding:6px 8px;"
            "background:#d5e8f8;border-radius:4px;"
        )
        outer_layout.addWidget(_hdr)

        # ── Global control row ────────────────────────────────────────────────
        ctrl_row = QHBoxLayout()
        ctrl_row.setSpacing(8)

        _lbl_db = QLabel("DB:")
        _lbl_db.setStyleSheet("font-weight:bold;font-size:11px;")
        ctrl_row.addWidget(_lbl_db)

        self.t6_db_le = QLineEdit()
        self.t6_db_le.setReadOnly(True)
        self.t6_db_le.setPlaceholderText("Project database auto-detected …")
        self.t6_db_le.setStyleSheet("font-size:11px;")
        ctrl_row.addWidget(self.t6_db_le, 1)

        _load_db = QPushButton("🔄 Load Results")
        _load_db.setStyleSheet(
            "QPushButton{background:#27ae60;color:white;font-weight:bold;"
            "border-radius:3px;padding:4px 10px;}"
        )
        _load_db.clicked.connect(self._t6_load_all)
        ctrl_row.addWidget(_load_db)

        _export_xl = QPushButton("📤 Export Excel")
        _export_xl.setStyleSheet(
            "QPushButton{background:#16a085;color:white;font-weight:bold;"
            "border-radius:3px;padding:4px 10px;}"
        )
        _export_xl.clicked.connect(self._t6_export_excel)
        ctrl_row.addWidget(_export_xl)

        _recalc = QPushButton("⚡ Recalculate FN")
        _recalc.setStyleSheet(
            "QPushButton{background:#8e44ad;color:white;font-weight:bold;"
            "border-radius:3px;padding:4px 10px;}"
        )
        _recalc.clicked.connect(self._t6_recalculate_fn)
        ctrl_row.addWidget(_recalc)

        _clear_db = QPushButton("🗑 Clear Evacuation DB")
        _clear_db.setStyleSheet(
            "QPushButton{background:#c0392b;color:white;font-weight:bold;"
            "border-radius:3px;padding:4px 10px;}"
            "QPushButton:hover{background:#a93226;}"
        )
        _clear_db.clicked.connect(self._t6_clear_evacuation_db)
        ctrl_row.addWidget(_clear_db)

        outer_layout.addLayout(ctrl_row)

        # ── RP weights + exmax/exmin row ──────────────────────────────────────
        param_row = QHBoxLayout()
        param_row.setSpacing(10)

        param_row.addWidget(QLabel("Zone weights RP(1..6):"))
        self.t6_rp_inputs = []
        for _k in range(6):
            _sp = QDoubleSpinBox()
            _sp.setRange(0, 1); _sp.setValue(1/6 if _k < 6 else 0)
            _sp.setDecimals(4); _sp.setSingleStep(0.01)
            _sp.setFixedWidth(72)
            _sp.setToolTip(
                f"RP({_k+1}) = zone_{_k+1}_length / tunnel_length  "
                f"(from 터널교통량등제원!M73:R73)"
            )
            param_row.addWidget(QLabel(f"P{_k+1}:"))
            param_row.addWidget(_sp)
            self.t6_rp_inputs.append(_sp)

        param_row.addSpacing(16)
        param_row.addWidget(QLabel("exMAX:"))
        self.t6_exmax = QSpinBox()
        self.t6_exmax.setRange(0, 10); self.t6_exmax.setValue(0)
        self.t6_exmax.setFixedWidth(50)
        self.t6_exmax.setToolTip("Exclude this many highest EV-time runs before CalAvg")
        param_row.addWidget(self.t6_exmax)

        param_row.addWidget(QLabel("exMIN:"))
        self.t6_exmin = QSpinBox()
        self.t6_exmin.setRange(0, 10); self.t6_exmin.setValue(0)
        self.t6_exmin.setFixedWidth(50)
        self.t6_exmin.setToolTip("Exclude this many lowest EV-time runs before CalAvg")
        param_row.addWidget(self.t6_exmin)

        param_row.addSpacing(16)
        param_row.addWidget(QLabel("Base freq (evt/yr):"))
        self.t6_base_freq = QDoubleSpinBox()
        self.t6_base_freq.setRange(1e-9, 1.0)
        self.t6_base_freq.setValue(0.001)
        self.t6_base_freq.setDecimals(8)
        self.t6_base_freq.setFixedWidth(110)
        param_row.addWidget(self.t6_base_freq)

        param_row.addStretch()
        outer_layout.addLayout(param_row)

        # ── ECAR table (per-scenario annual frequency, 7×2×5) ─────────────────
        # Mirrors VB ECAR(nHrr, nTRC, nWDC) loaded from the SenarioTable sheet.
        # Each cell is the annual frequency for that (HRR, Traffic, Wind) combo.
        # Default = base_freq; user can override per cell.
        # ECAR table — only the HRR classes that actually appear in
        # FNCV_ROAD's SenarioTable.  VB Module1.bas declares
        # CARKIND(1..7) = ("PC1","PC2","SMB","SMT","020","030","100") but
        # SMB/SMT have no SenarioTable entries and never contribute to the
        # Risk Index in practice.  Showing empty rows for them in the UI
        # was confusing, so they are excluded here.  The full VB-index
        # mapping is preserved separately in _t6_HRR_VB_IDX for the
        # rare case a legacy filename mentions SMB or SMT.
        self._t6_HRR_LIST  = ["PC1", "PC2", "020", "030", "100"]
        self._t6_TRC_LIST  = ["NORMAL", "CONGEST"]
        self._t6_WDC_LIST  = ["NVC", "NV0", "FV0", "FVM", "FVP"]
        # VB Select Case indices (1-based, matches PDF) — kept for any code
        # path that needs the original 7-slot CARKIND mapping:
        self._t6_HRR_VB_IDX = {"PC1": 1, "PC2": 2, "SMB": 3, "SMT": 4,
                               "020": 5, "030": 6, "100": 7}
        self._t6_HRR_IDX = {h: i + 1 for i, h in enumerate(self._t6_HRR_LIST)}
        self._t6_TRC_IDX = {t: i + 1 for i, t in enumerate(self._t6_TRC_LIST)}
        self._t6_WDC_IDX = {w: i + 1 for i, w in enumerate(self._t6_WDC_LIST)}

        ecar_grp = QGroupBox(
            "ECAR table — annual frequency per (HRR × Traffic × Wind) scenario "
            "(VB SenarioTable, sheet col 3)"
        )
        ecar_grp.setStyleSheet("QGroupBox{font-size:11px;font-weight:bold;}")
        ecar_vbox = QVBoxLayout(ecar_grp)
        ecar_vbox.setContentsMargins(6, 6, 6, 6)

        _ecar_help = QLabel(
            "Frequency = ECAR(HRR, Traffic, Wind) × RP(pos) ÷ MAXITER. "
            "Edit cells to override the Base freq for individual scenarios. "
            "Empty cells use Base freq."
        )
        _ecar_help.setWordWrap(True)
        _ecar_help.setStyleSheet("color:#555;font-size:10px;padding:2px;")
        ecar_vbox.addWidget(_ecar_help)

        # Build column headers as TRC × WDC pairs: 2 traffic groups × 5 wind = 10 cols
        _ecar_cols = [f"{t[:4]}/{w}"
                      for t in self._t6_TRC_LIST for w in self._t6_WDC_LIST]
        self.t6_ecar_tbl = QTableWidget(len(self._t6_HRR_LIST), len(_ecar_cols))
        self.t6_ecar_tbl.setHorizontalHeaderLabels(_ecar_cols)
        self.t6_ecar_tbl.setVerticalHeaderLabels(self._t6_HRR_LIST)
        self.t6_ecar_tbl.setAlternatingRowColors(True)
        # Compact rows; tooltip per cell so users know what each represents.
        self.t6_ecar_tbl.verticalHeader().setDefaultSectionSize(20)
        self.t6_ecar_tbl.horizontalHeader().setDefaultSectionSize(78)
        self.t6_ecar_tbl.setMaximumHeight(180)
        for r, hrr in enumerate(self._t6_HRR_LIST):
            for c, (trc, wdc) in enumerate(
                [(t, w) for t in self._t6_TRC_LIST for w in self._t6_WDC_LIST]
            ):
                _it = QTableWidgetItem("")    # blank → uses base_freq
                _it.setTextAlignment(Qt.AlignCenter)
                _it.setToolTip(
                    f"ECAR({hrr}, {trc}, {wdc}) — annual events/yr.\n"
                    f"VB indices: nHrr={self._t6_HRR_IDX[hrr]}, "
                    f"nTRC={self._t6_TRC_IDX[trc]}, nWDC={self._t6_WDC_IDX[wdc]}"
                )
                self.t6_ecar_tbl.setItem(r, c, _it)
        ecar_vbox.addWidget(self.t6_ecar_tbl)

        # ECAR action row: import from base_freq, clear, recalculate
        _ecar_btns = QHBoxLayout()
        _ecar_btns.addStretch()

        _btn_load_ss = QPushButton("Load from Standard Scenario")
        _btn_load_ss.setFixedHeight(22)
        _btn_load_ss.setStyleSheet(
            "QPushButton{background:#3498db;color:white;border-radius:3px;"
            "padding:2px 8px;}"
            "QPushButton:hover{background:#2980b9;}"
        )
        _btn_load_ss.setToolTip(
            "Pull per-scenario annual frequencies from the Standard Scenario "
            "event tree (mirrors VB SenarioTable col 3).  Cells are tinted "
            "light green to show they came from the event tree."
        )
        _btn_load_ss.clicked.connect(
            lambda: (self._t6_load_ecar_from_standard_scenario(),
                     self._t6_recalculate())
        )
        _ecar_btns.addWidget(_btn_load_ss)

        # ── FN-curve frequency-basis alignment ──────────────────────────────
        # The Python↔VB F-N disparity factorises as a constant fire-occurrence
        # ratio times a conditional-split residual.  Both live in this ECAR
        # table, NOT in the consequence engine.  The button below uniformly
        # rescales the table so the total annual fire frequency matches a
        # chosen basis while preserving the event tree's own scenario split.
        _btn_scale = QPushButton("Scale total → target…")
        _btn_scale.setFixedHeight(22)
        _btn_scale.setToolTip(
            "Uniformly rescale every ECAR cell so the TOTAL annual fire "
            "frequency equals a target value (e.g. the VB tunnel's "
            "0.0217 fires/yr).  Removes the constant fire-occurrence gap "
            "while preserving this event tree's own scenario split."
        )
        _btn_scale.clicked.connect(self._t6_scale_ecar_to_target)
        _ecar_btns.addWidget(_btn_scale)

        _btn_fill = QPushButton("Fill all with Base freq")
        _btn_fill.setFixedHeight(22)
        _btn_fill.setToolTip(
            "Populate every empty cell with the current Base freq value."
        )
        _btn_fill.clicked.connect(self._t6_ecar_fill_with_base)
        _ecar_btns.addWidget(_btn_fill)

        _btn_clear = QPushButton("Clear ECAR table")
        _btn_clear.setFixedHeight(22)
        _btn_clear.setToolTip("Empty every ECAR cell — all scenarios revert to Base freq.")
        _btn_clear.clicked.connect(self._t6_ecar_clear)
        _ecar_btns.addWidget(_btn_clear)

        _btn_recalc = QPushButton("Recalculate Risk Index")
        _btn_recalc.setFixedHeight(22)
        _btn_recalc.setToolTip(
            "Re-run the Raw_Senario / FN-Curve population using the current "
            "ECAR table and RP weights."
        )
        _btn_recalc.clicked.connect(self._t6_recalculate)
        _ecar_btns.addWidget(_btn_recalc)

        ecar_vbox.addLayout(_ecar_btns)
        outer_layout.addWidget(ecar_grp)

        # ── Inner sub-tab widget ──────────────────────────────────────────────
        self.t6_subtabs = QTabWidget()
        self.t6_subtabs.setStyleSheet(
            "QTabWidget::pane{border:1px solid #bdc3c7;border-top:2px solid #2980b9;}"
            "QTabBar::tab{padding:5px 12px;font-size:11px;}"
            "QTabBar::tab:selected{background:#2980b9;color:white;font-weight:bold;}"
        )
        outer_layout.addWidget(self.t6_subtabs, 1)

        # ── Status bar ────────────────────────────────────────────────────────
        self.t6_status = QLabel("Click 'Load Results' to populate all sub-tabs.")
        self.t6_status.setStyleSheet(
            "color:#555;padding:2px 6px;font-size:11px;"
            "background:#f8f9fa;border-top:1px solid #dee2e6;"
        )
        outer_layout.addWidget(self.t6_status)

        # ════════════════════════════════════════════════════════════════════
        # Sub-tab 1 — EVC Result  (mirrors sheet6 EVCResultStart)
        # ════════════════════════════════════════════════════════════════════
        st1 = QWidget()
        st1_vbox = QVBoxLayout(st1)
        st1_vbox.setContentsMargins(4, 4, 4, 4)

        _st1_info = QLabel(
            "EVC simulation results — all runs + AVG rows.  "
            "Mirrors the 'EVC Result' sheet (EVCResultStart, exMAX=X1, exMIN=V1)."
        )
        _st1_info.setWordWrap(True)
        _st1_info.setStyleSheet("color:#555;font-size:11px;padding:4px;")
        st1_vbox.addWidget(_st1_info)

        self.t6_evc_result_tbl = QTableWidget(0, 16)
        self.t6_evc_result_tbl.setHorizontalHeaderLabels([
            "File / Scenario", "Run#",
            "EV Time (s)", "Evacuees",
            "FED≥0.1", "FED≥0.2", "FED≥0.3", "FED≥0.4",
            "FED≥0.5", "FED≥0.6", "FED≥0.7", "FED≥0.8",
            "FED≥0.9", "FED≥1.0",
            "EQ Fatal", "EV Min / Max"
        ])
        self.t6_evc_result_tbl.horizontalHeader().setStretchLastSection(True)
        self.t6_evc_result_tbl.setAlternatingRowColors(True)
        self.t6_evc_result_tbl.setEditTriggers(QTableWidget.NoEditTriggers)
        self.t6_evc_result_tbl.setSelectionBehavior(QTableWidget.SelectRows)
        st1_vbox.addWidget(self.t6_evc_result_tbl, 1)
        self.t6_subtabs.addTab(st1, "EVC Result")

        # ════════════════════════════════════════════════════════════════════
        # Sub-tab 2 — EVC_Result_BF  (mirrors sheet7)
        # ════════════════════════════════════════════════════════════════════
        st2 = QWidget()
        st2_vbox = QVBoxLayout(st2)
        st2_vbox.setContentsMargins(4, 4, 4, 4)

        _st2_info = QLabel(
            "AVG rows decoded by scenario — mirrors EVC_Result_BF (sheet7). "
            "Columns: File, EV Time, Evacuees, FED 0.1–1.0, EQ Fatal, "
            "Fire Position, HRR, Traffic, Fan/Wind."
        )
        _st2_info.setWordWrap(True)
        _st2_info.setStyleSheet("color:#555;font-size:11px;padding:4px;")
        st2_vbox.addWidget(_st2_info)

        self.t6_bf_tbl = QTableWidget(0, 19)
        self.t6_bf_tbl.setHorizontalHeaderLabels([
            "File", "EV Time", "Evacuees",
            "FED≥0.1", "FED≥0.2", "FED≥0.3", "FED≥0.4",
            "FED≥0.5", "FED≥0.6", "FED≥0.7", "FED≥0.8",
            "FED≥0.9", "FED≥1.0",
            "EQ Fatal", "EV Min", "EV Max",
            "Fire Pos", "HRR", "Traffic / Wind"
        ])
        self.t6_bf_tbl.horizontalHeader().setStretchLastSection(True)
        self.t6_bf_tbl.setAlternatingRowColors(True)
        self.t6_bf_tbl.setEditTriggers(QTableWidget.NoEditTriggers)
        self.t6_bf_tbl.setSelectionBehavior(QTableWidget.SelectRows)
        st2_vbox.addWidget(self.t6_bf_tbl, 1)
        self.t6_subtabs.addTab(st2, "EVC_Result_BF")

        # ════════════════════════════════════════════════════════════════════
        # Sub-tab 3 — EVC_Result_BF2  (mirrors sheet8 ResultBF2Table)
        # ════════════════════════════════════════════════════════════════════
        st3 = QWidget()
        st3_vbox = QVBoxLayout(st3)
        st3_vbox.setContentsMargins(4, 4, 4, 4)

        _st3_info = QLabel(
            "Pivot table by HRR × Traffic × Fan/Wind with CalAvg values — "
            "mirrors EVC_Result_BF2 (ResultBF2Table, sheet8)."
        )
        _st3_info.setWordWrap(True)
        _st3_info.setStyleSheet("color:#555;font-size:11px;padding:4px;")
        st3_vbox.addWidget(_st3_info)

        self.t6_bf2_tbl = QTableWidget(0, 9)
        self.t6_bf2_tbl.setHorizontalHeaderLabels([
            "HRR", "Traffic", "Fan/Wind",
            "CalAvg EV Time", "CalAvg Evacuees",
            "CalAvg FED≥0.1", "CalAvg FED≥0.3",
            "CalAvg FED≥1.0", "CalAvg EQ Fatal"
        ])
        self.t6_bf2_tbl.horizontalHeader().setStretchLastSection(True)
        self.t6_bf2_tbl.setAlternatingRowColors(True)
        self.t6_bf2_tbl.setEditTriggers(QTableWidget.NoEditTriggers)
        st3_vbox.addWidget(self.t6_bf2_tbl, 1)
        self.t6_subtabs.addTab(st3, "EVC_Result_BF2")

        # Standard Scenario UI has moved to main Tab 7 (Risk Calculations).
        # Keep this table for Tab 6 data-loading/export compatibility.
        # Layout mirrors VB's SenarioTable (표준시나리오!O10:Z59) exactly:
        # one row per (scenario id, smoke code) with col3 = Freq1 (ECAR, no
        # RP), col4 = return period, col6 = RP-weighted T, cols 7-12 = the six
        # DISTINCT per-position averaged fatalities P1..P6 (CallFatalities
        # writes nFatal(j, nHrr, ntra, nfwc) into U:Z; T = Σ _rpᵢ·Pᵢ).
        _NFIRE_MAX = 6
        _st4_cols = ["Scenario", "Fan/Wind", "Frequency (ECAR)", "Return Yr",
                     "EQ Fatal (Σ RPi·Pi)"] + \
                    [f"Fatal P{i+1}" for i in range(_NFIRE_MAX)]
        self.t6_scenario_tbl = QTableWidget(0, len(_st4_cols))
        self.t6_scenario_tbl.setHorizontalHeaderLabels(_st4_cols)
        self.t6_scenario_tbl.horizontalHeader().setStretchLastSection(True)
        self.t6_scenario_tbl.setAlternatingRowColors(True)
        self.t6_scenario_tbl.setEditTriggers(QTableWidget.NoEditTriggers)

        # ════════════════════════════════════════════════════════════════════
        # Sub-tab 5 — Raw Scenario  (mirrors sheet12 Raw_Senario)
        # ════════════════════════════════════════════════════════════════════
        st5 = QWidget()
        st5_vbox = QVBoxLayout(st5)
        st5_vbox.setContentsMargins(4, 4, 4, 4)

        _st5_info = QLabel(
            "Per-iteration raw rows with frequency and risk index — "
            "mirrors Raw_Senario (sheet12).  "
            "Risk Index = Frequency × EQ Fatal."
        )
        _st5_info.setWordWrap(True)
        _st5_info.setStyleSheet("color:#555;font-size:11px;padding:4px;")
        st5_vbox.addWidget(_st5_info)

        # Sort toolbar
        _raw_sen_col_names = [
            "Fire Pos", "HRR", "Traffic", "Fan/Wind", "Iter#",
            "EV Time",
            "FED>=0.1", "FED>=0.2", "FED>=0.3", "FED>=0.4", "FED>=0.5",
            "FED>=0.6", "FED>=0.7", "FED>=0.8", "FED>=0.9", "FED>=1.0",
            "Evacuees", "EQ Fatal",
            "Frequency", "Risk Index"
        ]
        _sort_row = QHBoxLayout()
        _sort_row.addWidget(QLabel("Sort by:"))
        self.t6_raw_sen_sort_col = QComboBox()
        self.t6_raw_sen_sort_col.addItems(_raw_sen_col_names)
        self.t6_raw_sen_sort_col.setCurrentIndex(19)  # default: Risk Index
        _sort_row.addWidget(self.t6_raw_sen_sort_col)
        self.t6_raw_sen_sort_btn = QPushButton("\u2191  Sort Ascending")
        self.t6_raw_sen_sort_btn.setFixedWidth(160)
        self.t6_raw_sen_sort_btn.clicked.connect(self._t6_raw_sen_do_sort)
        _sort_row.addWidget(self.t6_raw_sen_sort_btn)
        _sort_row.addStretch()
        st5_vbox.addLayout(_sort_row)
        self._t6_raw_sen_sort_asc = True

        self.t6_raw_sen_tbl = QTableWidget(0, 20)
        self.t6_raw_sen_tbl.setHorizontalHeaderLabels(_raw_sen_col_names)
        self.t6_raw_sen_tbl.horizontalHeader().setStretchLastSection(True)
        self.t6_raw_sen_tbl.setAlternatingRowColors(True)
        self.t6_raw_sen_tbl.setEditTriggers(QTableWidget.NoEditTriggers)
        st5_vbox.addWidget(self.t6_raw_sen_tbl, 1)

        # Summary row
        _sum_row = QHBoxLayout()
        _sum_row.addWidget(QLabel("Total Risk Index:"))
        self.t6_total_risk_lbl = QLabel("—")
        self.t6_total_risk_lbl.setStyleSheet(
            "font-weight:bold;font-size:13px;color:#c0392b;"
        )
        _sum_row.addWidget(self.t6_total_risk_lbl)
        _sum_row.addStretch()
        st5_vbox.addLayout(_sum_row)
        self.t6_subtabs.addTab(st5, "Raw Scenario")

        # ════════════════════════════════════════════════════════════════════
        # Sub-tab 7 — FN Curve  (layout mirrors fn_curve_subtab_widget.py)
        #   full-width control panel at top
        #   QSplitter:  left 1/3 = sorted data table  |  right 2/3 = chart
        # ════════════════════════════════════════════════════════════════════
        st7 = QWidget()
        st7_vbox = QVBoxLayout(st7)
        st7_vbox.setContentsMargins(4, 4, 4, 4)
        st7_vbox.setSpacing(4)

        # ── Full-width toolbar (spans both the table and chart columns) ────
        _tb_frame = QFrame()
        _tb_frame.setFrameShape(QFrame.NoFrame)
        _tb_frame.setStyleSheet(
            "QFrame { background:#eef1f4; border-bottom:1px solid #cdd4dc; }"
        )
        _tb_v = QVBoxLayout(_tb_frame)
        _tb_v.setContentsMargins(6, 4, 6, 4)
        _tb_v.setSpacing(3)
        st7_vbox.addWidget(_tb_frame, 0)

        # Row 0: Title / X-label / Y-label
        _lbl_row = QHBoxLayout()
        _lbl_row.setSpacing(6)
        _lbl_row.addWidget(QLabel("Title:"))
        self.t6_fn_title_edit = QLineEdit("F-N Curve  (Quantitative Risk Assessment)")
        self.t6_fn_title_edit.setMinimumWidth(180)
        self.t6_fn_title_edit.editingFinished.connect(self._t6_draw_fn_chart)
        _lbl_row.addWidget(self.t6_fn_title_edit, 1)
        _lbl_row.addWidget(QLabel("X label:"))
        self.t6_fn_xlabel_edit = QLineEdit("Number of Fatalities  N")
        self.t6_fn_xlabel_edit.setMinimumWidth(140)
        self.t6_fn_xlabel_edit.editingFinished.connect(self._t6_draw_fn_chart)
        _lbl_row.addWidget(self.t6_fn_xlabel_edit, 1)
        _lbl_row.addWidget(QLabel("Y label:"))
        self.t6_fn_ylabel_edit = QLineEdit("Cumulative Frequency  F(≥N)  [events / year]")
        self.t6_fn_ylabel_edit.setMinimumWidth(160)
        self.t6_fn_ylabel_edit.editingFinished.connect(self._t6_draw_fn_chart)
        _lbl_row.addWidget(self.t6_fn_ylabel_edit, 1)
        # Curve construction selector — both are VB constructions:
        #   Per-iteration  = Raw_FNC / FN_CURVE_CREATE3 (each MC iteration a
        #                    step at ECAR×RP/MAXITER)
        #   Per-scenario   = FNCurve2 / Fatal2FNSheet (one step per
        #                    position×scenario at full ECAR×RP, N = average
