    # ── Tab 6 data-loading helpers ────────────────────────────────────────────

    def _t6_load_all(self):
        """Load all results from DB and populate every sub-tab."""
        import json, sqlite3
        from pathlib import Path

        db_path = self._get_project_db_path()
        self.t6_db_le.setText(str(db_path))

        if not db_path.exists():
            self.t6_status.setText(
                f"⚠  Database not found: {db_path.name}  — run a batch simulation first."
            )
            return

        try:
            con = sqlite3.connect(str(db_path))
            con.row_factory = sqlite3.Row
            cur = con.cursor()

            # ── Check table exists ────────────────────────────────────────
            cur.execute(
                "SELECT name FROM sqlite_master WHERE type='table' "
                "AND name='batch_evc_results'"
            )
            if not cur.fetchone():
                con.close()
                self.t6_status.setText(
                    "⚠  batch_evc_results table not found — "
                    "run a batch EVC simulation first."
                )
                return

            # ── Load rows ─────────────────────────────────────────────────
            cur.execute(
                "SELECT * FROM batch_evc_results ORDER BY saved_at DESC, id ASC"
            )
            rows = [dict(r) for r in cur.fetchall()]
            con.close()

        except Exception as _e:
            self.t6_status.setText(f"⚠  DB error: {_e}")
            return

        if not rows:
            self.t6_status.setText("No EVC results in database.")
            return

        self._t6_raw_rows = rows
        # Each populate step is isolated: a failure in one sub-tab (e.g. an
        # optional tab whose widgets are absent in this build) must not abort
        # the others. Previously an exception in _t6_populate_fncurve2 would
        # prevent _t6_draw_fn_chart from running, leaving the FN Curve tab
        # blank.
        for _step in (
            self._t6_populate_evc_result,
            self._t6_populate_bf,
            self._t6_populate_bf2,
            self._t6_populate_scenario,
            self._t6_populate_raw_scenario,
            self._t6_populate_fncurve2,
        ):
            try:
                _step(rows)
            except Exception as _e:
                import traceback
                print(f"[Results] {_step.__name__} failed: {_e}")
                traceback.print_exc()
        try:
            self._t6_draw_fn_chart()
        except Exception as _e:
            import traceback
            print(f"[Results] _t6_draw_fn_chart failed: {_e}")
            traceback.print_exc()

        # Compute row breakdown for status display
        _total_run_rows = 0
        for _rec in rows:
            import json as _json_st
            try:
                _runs_st = _json_st.loads(_rec.get("runs_json") or "[]")
                _total_run_rows += len(_runs_st)
            except Exception:
                pass
        _total_avg_rows = len(rows)
        _total_t6_rows = _total_run_rows + _total_avg_rows
        # Keep Standard Scenario P1-P6/Fatalities aligned with live EVC results.
        self._t6_sync_standard_scenario_fatalities(rows)
        self.t6_status.setText(
            f"✅  Loaded {len(rows)} scenario(s) from {db_path.name}.  "
            f"EVC Result: {_total_run_rows} runs + {_total_avg_rows} AVG = {_total_t6_rows} rows."
        )

    def _t6_parse_evc_name(self, evc_name: str):
        """Decode fire position, HRR code, traffic, and fan/wind from a filename stem.

        Mirrors EVCRESULTArrangement() in module1.vb.  The fan/wind code is read
        verbatim from the filename — no FVM↔FVP swap.  The earlier version of
        this function did swap FVM/FVP under the mistaken belief that VB does;
        verification against module1.bas (sub EVCRESULTArrangement, lines that
        set imsi4$ from the filename) showed FVM maps to "FVM" and FVP maps to
        "FVP" with no transposition.  The swap caused Standard_Scenario rows to
        show the wrong Fan/Wind label even though the underlying ECAR lookups
        were correct (FVM and FVP usually carry identical ECAR values, which
        masked the bug numerically but not visually).
        """
        import re
        n = evc_name.upper()
        # Fire position: _P1_ … _P6_ or _P1 at end of stem
        pos_m = re.search(r'_P(\d)(?:_|$)', n)
        pos = int(pos_m.group(1)) if pos_m else 0

        hrr = "?"
        for code in ("PC1", "PC2", "SMB", "SMT", "020", "030", "100"):
            if code in n:
                hrr = code; break

        traffic = "CONGEST" if "CONG" in n else ("NORMAL" if "NORM" in n else "?")

        # Order matters — test FVM/FVP/FV0 before falling through to NV* so a
        # filename like "020NFV0_P1" doesn't accidentally match a shorter code.
        wind = "?"
        if "FVM" in n:   wind = "FVM"
        elif "FVP" in n: wind = "FVP"
        elif "FV0" in n: wind = "FV0"
        elif "NV0" in n: wind = "NV0"
        elif "NVC" in n: wind = "NVC"

        return pos, hrr, traffic, wind

    def _t6_build_standard_scenario_fatality_map(self, rows):
        """Build (scenario_id, smoke_control) -> [P1..P6] from EVC AVG rows.

        Uses `avg_eq_fatal` at each fire position as the P-value for that
        scenario, weighted by n_run when duplicate sessions exist.
        """
        import json

        acc = {}  # key -> {sum:[6], wt:[6]}

        for rec in rows or []:
            pos, hrr, traffic, wind = self._t6_parse_evc_name(rec.get("evc_name", ""))
            if pos < 1 or pos > 6:
                continue
            if hrr in ("?", "SMB", "SMT"):
                continue

            trc_letter = "N" if traffic == "NORMAL" else ("C" if traffic == "CONGEST" else "")
            if not trc_letter:
                continue

            # smoke_control in Standard Scenario uses traffic letter prefix.
            if wind in ("NVC", "NV0", "FV0", "FVM", "FVP"):
                smoke = f"{trc_letter}{wind}"
            else:
                continue

            scenario_id = f"{hrr}{trc_letter}"
            key = (scenario_id, smoke)

            try:
                eq = float(rec.get("avg_eq_fatal") or 0.0)
            except Exception:
                eq = 0.0

            n_run = int(rec.get("n_run") or 0)
            if n_run <= 0:
                try:
                    n_run = len(json.loads(rec.get("runs_json") or "[]"))
                except Exception:
                    n_run = 1
            n_run = max(n_run, 1)

            entry = acc.setdefault(key, {"sum": [0.0] * 6, "wt": [0.0] * 6})
            entry["sum"][pos - 1] += eq * n_run
            entry["wt"][pos - 1] += n_run

        out = {}
        for key, entry in acc.items():
            vals = []
            for s, w in zip(entry["sum"], entry["wt"]):
                vals.append((s / w) if w > 0 else 0.0)
            out[key] = vals
        return out

    def _t6_sync_standard_scenario_fatalities(self, rows):
        """Push live P1-P6 fatalities from Tab 6 data into Standard Scenario table."""
        ssw = getattr(self, "standard_scenario_widget", None)
        if ssw is None or not hasattr(ssw, "set_fatalities_from_evc_map"):
            return
        try:
            p_map = self._t6_build_standard_scenario_fatality_map(rows)
            if p_map:
                ssw.set_fatalities_from_evc_map(p_map)
        except Exception:
            pass

    def _t6_populate_evc_result(self, rows):
        """Sheet 6 — EVC Result: all runs + AVG row per scenario."""
        import json
        tbl = self.t6_evc_result_tbl
        tbl.setRowCount(0)

        def _ci(txt, bold=False, bg=None):
            it = QTableWidgetItem(str(txt))
            it.setTextAlignment(Qt.AlignCenter)
            if bold:
                f = it.font(); f.setBold(True); it.setFont(f)
            if bg:
                it.setBackground(bg)
            return it

        _avg_bg = QColor(255, 255, 200)
        _sep_bg = QColor(218, 228, 242)

        for rec in rows:
            try:
                runs_raw = json.loads(rec.get("runs_json") or "[]")
            except Exception:
                runs_raw = []

            fed_avg = []
            try:
                fed_avg = json.loads(rec.get("fed_avg_json") or "[]")
            except Exception:
                pass

            # Individual runs
            for run in runs_raw:
                ri = tbl.rowCount(); tbl.insertRow(ri)
                tbl.setItem(ri, 0, _ci(rec["evc_name"]))
                tbl.setItem(ri, 1, _ci(run.get("run_no", run.get("run", "?"))))
                tbl.setItem(ri, 2, _ci(f"{run.get('ev_time', 0):.1f}"))
                tbl.setItem(ri, 3, _ci(f"{run.get('evacuees', 0):.0f}"))
                for _fi, _fv in enumerate(run.get("fed", [0]*10)):
                    if _fi < 10:
                        tbl.setItem(ri, 4 + _fi, _ci(f"{_fv:.0f}"))
                tbl.setItem(ri, 14, _ci(f"{run.get('eq_fatal', 0):.3f}"))
                tbl.setItem(ri, 15, _ci(""))

            # AVG row
            ri = tbl.rowCount(); tbl.insertRow(ri)
            tbl.setItem(ri, 0, _ci(rec["evc_name"], bold=True, bg=_avg_bg))
            tbl.setItem(ri, 1, _ci("AVG", bold=True, bg=_avg_bg))
            tbl.setItem(ri, 2, _ci(f"{rec['avg_ev_time']:.1f}", bold=True, bg=_avg_bg))
            tbl.setItem(ri, 3, _ci(f"{rec['avg_evacuees']:.1f}", bold=True, bg=_avg_bg))
            for _fi, _fv in enumerate(fed_avg[:10]):
                tbl.setItem(ri, 4 + _fi, _ci(f"{_fv:.1f}", bold=True, bg=_avg_bg))
            tbl.setItem(ri, 14, _ci(f"{rec['avg_eq_fatal']:.3f}", bold=True, bg=_avg_bg))
            ev_min = rec.get("ext_min") or 0
            ev_max = rec.get("ext_max") or 0
            tbl.setItem(ri, 15,
                _ci(f"{ev_min:.1f} / {ev_max:.1f}", bold=True, bg=_avg_bg))

        # Count rows for status display
        _n_run_rows = tbl.rowCount() - len(rows)  # individual run rows (before AVGs added below)
        tbl.resizeColumnsToContents()

    def _t6_populate_bf(self, rows):
        """Sheet 7 — EVC_Result_BF: AVG rows with decoded scenario columns."""
        import json
        tbl = self.t6_bf_tbl
        tbl.setRowCount(0)

        def _ci(txt, bold=False, bg=None):
            it = QTableWidgetItem(str(txt))
            it.setTextAlignment(Qt.AlignCenter)
            if bold:
                f = it.font(); f.setBold(True); it.setFont(f)
            if bg:
                it.setBackground(bg)
            return it

        for rec in rows:
            pos, hrr, traffic, wind = self._t6_parse_evc_name(rec["evc_name"])
            fed_avg = []
            try:
                fed_avg = json.loads(rec.get("fed_avg_json") or "[]")
            except Exception:
                pass

            ri = tbl.rowCount(); tbl.insertRow(ri)
            tbl.setItem(ri, 0,  _ci(rec["evc_name"]))
            tbl.setItem(ri, 1,  _ci(f"{rec['avg_ev_time']:.1f}"))
            tbl.setItem(ri, 2,  _ci(f"{rec['avg_evacuees']:.1f}"))
            for _fi, _fv in enumerate(fed_avg[:10]):
                tbl.setItem(ri, 3 + _fi, _ci(f"{_fv:.1f}"))
            tbl.setItem(ri, 13, _ci(f"{rec['avg_eq_fatal']:.3f}"))
            ev_min = rec.get("ext_min") or 0
            ev_max = rec.get("ext_max") or 0
            tbl.setItem(ri, 14, _ci(f"{ev_min:.1f}"))
            tbl.setItem(ri, 15, _ci(f"{ev_max:.1f}"))
            tbl.setItem(ri, 16, _ci(f"P{pos}" if pos else "?"))
            tbl.setItem(ri, 17, _ci(hrr))
            tbl.setItem(ri, 18, _ci(f"{traffic} / {wind}"))

        tbl.resizeColumnsToContents()

    def _t6_populate_bf2(self, rows):
        """Sheet 8 — EVC_Result_BF2: CalAvg pivot by HRR × Traffic × Wind."""
        import json
        from collections import defaultdict

        tbl = self.t6_bf2_tbl
        tbl.setRowCount(0)

        exmax = self.t6_exmax.value()
        exmin = self.t6_exmin.value()

        def _calAvg(vals):
            """Trimmed mean matching VB CalAvg()."""
            sv = sorted(vals)
            lo = exmin; hi = len(sv) - exmax
            sub = sv[lo:hi] if lo < hi else sv
            return (sum(sub) / len(sub)) if sub else 0.0

        # Group by (hrr, traffic, wind)
        groups = defaultdict(list)
        for rec in rows:
            _, hrr, traffic, wind = self._t6_parse_evc_name(rec["evc_name"])
            key = (hrr, traffic, wind)
            groups[key].append(rec)

        def _ci(txt):
            it = QTableWidgetItem(str(txt))
            it.setTextAlignment(Qt.AlignCenter)
            return it

        for (hrr, traffic, wind), grp in sorted(groups.items()):
            ri = tbl.rowCount(); tbl.insertRow(ri)
            tbl.setItem(ri, 0, _ci(hrr))
            tbl.setItem(ri, 1, _ci(traffic))
            tbl.setItem(ri, 2, _ci(wind))
            tbl.setItem(ri, 3,
                _ci(f"{_calAvg([r['avg_ev_time'] for r in grp]):.1f}"))
            tbl.setItem(ri, 4,
                _ci(f"{_calAvg([r['avg_evacuees'] for r in grp]):.1f}"))

            # FED columns — parse from fed_avg_json
            fed_lists = []
            for rec in grp:
                try:
                    fl = json.loads(rec.get("fed_avg_json") or "[]")
                    fed_lists.append(fl)
                except Exception:
                    pass

            for col_off, fed_idx in enumerate([0, 2, 9]):  # 0.1, 0.3, 1.0
                vals = [fl[fed_idx] for fl in fed_lists if len(fl) > fed_idx]
                tbl.setItem(ri, 5 + col_off,
                    _ci(f"{_calAvg(vals):.1f}" if vals else "—"))

            tbl.setItem(ri, 8,
                _ci(f"{_calAvg([r['avg_eq_fatal'] for r in grp]):.4f}"))

        tbl.resizeColumnsToContents()

    def _t6_get_ecar(self, hrr: str, traffic: str, wind: str) -> float:
        """Return ECAR(nHrr, nTRC, nWDC) — the annual frequency for one
        (HRR × Traffic × Wind) scenario.

        Mirrors the VB ECAR(7, 2, 5) array loaded from SenarioTable col 3.
        Looks up the corresponding cell in `self.t6_ecar_tbl`; an empty or
        non-numeric cell falls back to `self.t6_base_freq.value()`.

        Special case: SMB and SMT have no SenarioTable entries in
        FNCV_ROAD.xlsm and never contribute to the Risk Index in VB
        (ECAR(3,*,*) and ECAR(4,*,*) sit at zero throughout).  We return
        0.0 for those HRR codes regardless of the base_freq spinbox value
        so a non-zero base_freq cannot accidentally inflate the Risk Index
        for legacy SMB/SMT scenario files.

        Unknown HRR / traffic / wind labels (e.g. "?" from a malformed
        filename) fall back to base_freq so the calculation is defined
        for legacy data.
        """
        base = float(self.t6_base_freq.value())
        # VB-parity: SMB and SMT contribute zero, never base_freq.
        if hrr in ("SMB", "SMT"):
            return 0.0
        try:
            r = self._t6_HRR_LIST.index(hrr)
        except (ValueError, AttributeError):
            return base
        try:
            t = self._t6_TRC_LIST.index(traffic)
        except (ValueError, AttributeError):
            return base
        try:
            w = self._t6_WDC_LIST.index(wind)
        except (ValueError, AttributeError):
            return base
        # Column layout: traffic-major, wind-minor
        col = t * len(self._t6_WDC_LIST) + w
        try:
            it = self.t6_ecar_tbl.item(r, col)
            if it is None:
                return base
            txt = it.text().strip()
            if not txt:
                return base
            return float(txt)
        except (ValueError, AttributeError):
            return base

    def _t6_get_irp(self, evc_name: str) -> int:
        """Decode `irp` (the fire-position index, 1..6) from an evc filename.

        Mirrors VB CalnFillFreq's read of column 1 of Raw_senario.  Returns 0
        when the filename has no `_P{n}_` token, which makes the row use the
        unweighted scenario frequency (matches VB's behaviour when irp=0).
        """
        pos, _hrr, _trc, _wdc = self._t6_parse_evc_name(evc_name)
        return pos

    def _t6_load_ecar_from_standard_scenario(self) -> int:
        """Pull per-scenario annual frequencies from StandardScenarioWidget into
        the ECAR table.

        Mirrors VB Module1.CalnFillFreq's load step:

            Set DataRange = Range("SenarioTable")
            ECAR(nHrr, TRC, iWC) = .Cells(i, 3)

        but reads from the live Python event-tree widget instead of the
        spreadsheet's named range.  Each SubScenario carries:
            scenario_id  — e.g. "020C"  (HRR + traffic-letter)
            smoke_control — e.g. "CFVP" (traffic-letter + wind code)
            freq_per_yr  — the ECAR value (annual events/yr)

        The mapping covers PC1, PC2, 020, 030, 100 — every HRR class that
        appears in the SenarioTable.  SMB and SMT are intentionally absent
        from the ECAR table (see _t6_HRR_LIST notes) because the workbook
        has no SenarioTable entries for them and they never contribute to
        the Risk Index in practice.

        Returns
        -------
        int
            Number of cells populated.  Zero if the widget is missing,
            unreachable, or contains no usable SubScenarios.
        """
        ssw = getattr(self, "standard_scenario_widget", None)
        if ssw is None:
            return 0
        data = getattr(ssw, "_data", None)
        if not data:
            return 0

        # Walk every VehicleType → VehicleFireType → FireScenario branch
        # and pick up the SubScenarios at the leaves.
        subs = []
        for vt in data:
            for ft in getattr(vt, "fire_types", []) or []:
                # 🔧 VB-PARITY FIX (frequency double-count): alias fire types
                # (GV "20MW" → BUS-20, ST "30MW" → GV-30) are DISPLAY mirrors
                # of the cross-class "downgraded fire" term that the parent
                # class node ALREADY contains — 표준시나리오 F33 = bus large
                # fires + GV·(1−LFR.030) small fires, F43 = truck large fires
                # + ST·(1−LFR.100) small fires. Accumulating the alias leaves
                # on top of the parent's leaves counted the downgrade term
                # TWICE, inflating ECAR by exactly 1.751× (020 class) and
                # 1.079× (030 class) versus the workbook Q-column — verified
                # against 제연무_FNCV_ROAD.xlsm named ranges, where skipping
                # the alias leaves reproduces every Q value and the FNCurve2
                # PLL (6.9985e-05) to 5 significant digits. The 100 class has
                # no alias and already matched (ratio 1.000).
                if getattr(ft, "alias_to", None) is not None:
                    continue
                for branch in (getattr(ft, "normal", None),
                               getattr(ft, "congest", None)):
                    if branch is None:
                        continue
                    for ss in getattr(branch, "sub_scenarios", []) or []:
                        subs.append(ss)
        if not subs:
            return 0

        # Map scenario_id (e.g. "020C") + smoke_control (e.g. "CFVP")
        # to the VB-style (HRR, Traffic, Wind) keys used by the ECAR table.
        #
        # Bug fix: the SenarioTable in FNCV_ROAD.xlsm holds the TOTAL annual
        # frequency per (HRR, Traffic, Wind) — i.e. summed across every
        # vehicle type that can produce that HRR class.  The earlier
        # implementation overwrote the cell on each SubScenario, so when two
        # vehicle types both fed into (say) 020N (Bus 20MW + General Cargo
        # 20MW), only the last write survived and the ECAR for that scenario
        # was understated by ~40%.  We now accumulate into a dict first and
        # write the totals into the table after the walk completes.
        accum = {}  # (r, c) -> running total
        for ss in subs:
            sid = (getattr(ss, "scenario_id", "") or "").upper()
            smk = (getattr(ss, "smoke_control", "") or "").upper()
            freq = getattr(ss, "freq_per_yr", None)
            if not sid or not smk or freq is None or freq < 0:
                continue

            # Decode scenario_id → (hrr_label, traffic_letter)
            if sid.startswith(("PC1", "PC2")):
                hrr_label = sid[:3]
                trc_letter = sid[3:4]
            elif sid[:3] in ("020", "030", "100"):
                hrr_label = sid[:3]
                trc_letter = sid[3:4]
            else:
                continue

            # smoke_control = traffic_letter + wind_code (3 chars).
            # The first char must agree with scenario_id's traffic letter;
            # accept either way to be robust to widget ordering quirks.
            if len(smk) < 4:
                continue
            wind_code = smk[1:4]   # "NVC", "NV0", "FV0", "FVM", "FVP"

            # Resolve to ECAR table indices.
            if hrr_label not in self._t6_HRR_LIST:
                continue
            trc_label = "NORMAL" if trc_letter == "N" else (
                "CONGEST" if trc_letter == "C" else None)
            if trc_label not in self._t6_TRC_LIST:
                continue
            if wind_code not in self._t6_WDC_LIST:
                continue

            r = self._t6_HRR_LIST.index(hrr_label)
            c = (self._t6_TRC_LIST.index(trc_label) * len(self._t6_WDC_LIST)
                 + self._t6_WDC_LIST.index(wind_code))

            accum[(r, c)] = accum.get((r, c), 0.0) + float(freq)

        # Now write totals back to the table.
        n_filled = 0
        tbl = self.t6_ecar_tbl
        tbl.blockSignals(True)
        try:
            for (r, c), total in accum.items():
                it = tbl.item(r, c)
                if it is None:
                    it = QTableWidgetItem("")
                    it.setTextAlignment(Qt.AlignCenter)
                    tbl.setItem(r, c, it)
                it.setText(f"{total:.6E}")
                # Light-green tint marks "auto-filled from event tree" so
                # users can see at a glance which cells were defaulted vs
                # manually overridden.
                it.setBackground(QColor(232, 245, 232))
                n_filled += 1
        finally:
            tbl.blockSignals(False)

        # Surface a status message if we have a status label, but never crash
        # if Tab 6 layout hasn't been built yet.
        try:
            self.t6_status.setText(
                f"ECAR table loaded from Standard Scenario "
                f"({n_filled} of {len(self._t6_HRR_LIST) * len(self._t6_TRC_LIST) * len(self._t6_WDC_LIST)} cells)."
            )
        except Exception:
            pass
        return n_filled

    # ── FN-curve frequency-basis alignment helpers ────────────────────────────
    def _t6_ecar_table_to_map(self):
        """Snapshot the ECAR table into {(hrr, traffic, wind): freq}.

        Only explicitly-filled, positive cells are included (empty cells fall
        back to base_freq at lookup time and are not part of the scenario
        frequency basis being aligned).
        """
        out = {}
        tbl = self.t6_ecar_tbl
        for r, hrr in enumerate(self._t6_HRR_LIST):
            for t_i, trc in enumerate(self._t6_TRC_LIST):
                for w_i, wdc in enumerate(self._t6_WDC_LIST):
                    c = t_i * len(self._t6_WDC_LIST) + w_i
                    it = tbl.item(r, c)
                    if it is None:
                        continue
                    txt = it.text().strip()
                    if not txt:
                        continue
                    try:
                        v = float(txt)
                    except ValueError:
                        continue
                    if v > 0.0:
                        out[(hrr, trc, wdc)] = v
        return out

    def _t6_ecar_map_to_table(self, ecar_map, tint=None) -> int:
        """Write {(hrr, traffic, wind): freq} into the ECAR table.

        Cells not present in the map are CLEARED so the table is an exact
        image of the loaded basis (mirrors VB, where ECAR slots without a
        SenarioTable row stay zero).  Returns the number of cells written.
        """
        tbl = self.t6_ecar_tbl
        n = 0
        tbl.blockSignals(True)
        try:
            for r, hrr in enumerate(self._t6_HRR_LIST):
                for t_i, trc in enumerate(self._t6_TRC_LIST):
                    for w_i, wdc in enumerate(self._t6_WDC_LIST):
                        c = t_i * len(self._t6_WDC_LIST) + w_i
                        it = tbl.item(r, c)
                        if it is None:
                            it = QTableWidgetItem("")
                            it.setTextAlignment(Qt.AlignCenter)
                            tbl.setItem(r, c, it)
                        v = ecar_map.get((hrr, trc, wdc))
                        if v is not None and v > 0.0:
                            it.setText(f"{v:.6E}")
                            if tint is not None:
                                it.setBackground(tint)
                            n += 1
                        else:
                            it.setText("")
        finally:
            tbl.blockSignals(False)
        return n


    def _t6_scale_ecar_to_target(self) -> None:
        """Uniformly rescale the ECAR table so Σ frequencies == target.

        Frequency-level alignment only: removes the constant fire-occurrence
        gap (~16.6× in the Gopo↔VB comparison) while keeping this event
        tree's own conditional scenario split.  The 1.1–4.2× split residual
        remains unless the exact SenarioTable basis is loaded instead.
        """
        from PyQt5.QtWidgets import QInputDialog, QMessageBox
        py_map = self._t6_ecar_table_to_map()
        cur = sum(py_map.values())
        if cur <= 0.0:
            QMessageBox.warning(
                self, "Nothing to scale",
                "The ECAR table has no positive frequencies. Load it from "
                "the Standard Scenario event tree first.")
            return
        target, ok = QInputDialog.getDouble(
            self, "Scale total fire frequency",
            f"Current total: {cur:.4E} fires/yr.\n"
            "Enter the TARGET total annual fire frequency\n"
            "(e.g. the VB tunnel's whole-tunnel value):",
            cur, 1e-12, 1e3, 6)
        if not ok or target <= 0.0:
            return
        k = target / cur
        scaled = {key: v * k for key, v in py_map.items()}
        n = self._t6_ecar_map_to_table(scaled, tint=QColor(255, 243, 224))
        self._t6_recalculate()
        try:
            self.t6_status.setText(
                f"ECAR rescaled ×{k:.4f}: total fire freq {cur:.4E} → "
                f"{target:.4E}/yr ({n} cells, amber tint). Scenario split "
                f"preserved.")
        except Exception:
            pass

    def _t6_ecar_fill_with_base(self) -> None:
        """Populate every empty ECAR cell with the current Base freq value."""
        base = float(self.t6_base_freq.value())
        tbl = self.t6_ecar_tbl
        tbl.blockSignals(True)
        try:
            for r in range(tbl.rowCount()):
                for c in range(tbl.columnCount()):
                    it = tbl.item(r, c)
                    if it is None:
                        it = QTableWidgetItem("")
                        it.setTextAlignment(Qt.AlignCenter)
                        tbl.setItem(r, c, it)
                    if not it.text().strip():
                        it.setText(f"{base:.6E}")
        finally:
            tbl.blockSignals(False)
        self._t6_recalculate()

    def _t6_ecar_clear(self) -> None:
        """Empty every ECAR cell so all scenarios revert to base_freq."""
        tbl = self.t6_ecar_tbl
        tbl.blockSignals(True)
        try:
            for r in range(tbl.rowCount()):
                for c in range(tbl.columnCount()):
                    it = tbl.item(r, c)
                    if it is not None:
                        it.setText("")
        finally:
            tbl.blockSignals(False)
        self._t6_recalculate()

    def _t6_recalculate(self) -> None:
        """Re-run Raw_Senario / FN-Curve population using current ECAR + RP."""
        rows = getattr(self, "_t6_raw_rows", None)
        if not rows:
            try:
                self._t6_load_all()
            except Exception:
                pass
            return
        try:
            self._t6_populate_scenario(rows)
            self._t6_populate_raw_scenario(rows)
            self._t6_populate_fncurve2(rows)
            self._t6_draw_fn_chart()
            self._t6_sync_standard_scenario_fatalities(rows)
        except Exception as _e:
            try:
                self.t6_status.setText(f"⚠  Recalculate error: {_e}")
            except Exception:
                pass

    def _t6_get_rp_weights(self):
        """Read RP(1..6) from the header spinboxes; normalise to sum=1."""
        vals = [sp.value() for sp in self.t6_rp_inputs]
        total = sum(vals)
        if total <= 0:
            return [1/6] * 6
        return [v / total for v in vals]

    def _t6_populate_scenario(self, rows):
        """Sheet 10 — SenarioTable, in the exact VB layout.

        VB (CallFatalities + 표준시나리오) keeps ONE row per
        (scenario id × smoke code): col 3 = Freq1 (the ECAR annual frequency,
        no RP), col 4 = return period, col 6 = T (the RP-weighted expectation
        as a live formula Σ _rpᵢ·Pᵢ), cols 7–12 = the six DISTINCT
        per-position trimmed-average fatalities nFatal(j, …) = P1..P6.

        The previous Python layout emitted one row per position with the
        position's eq duplicated across all six P columns and "Frequency×RP"
        equal to "Frequency", which made column-for-column workbook diffs
        against the VB reference impossible.  This version groups the
        per-position records into the VB shape.  RP appears on exactly one
        side: NOT in this sheet's Frequency column (matching VB col 3); it is
        applied inside the Σ RPᵢ·Pᵢ expectation and, separately, in the FN /
        Raw_Senario machinery as ECAR×RP/MAXITER.
        """
        tbl = self.t6_scenario_tbl
        tbl.setRowCount(0)
        rp = self._t6_get_rp_weights()

        def _ci(txt, bold=False, bg=None):
            it = QTableWidgetItem(str(txt))
            it.setTextAlignment(Qt.AlignCenter)
            if bold:
                f = it.font(); f.setBold(True); it.setFont(f)
            if bg:
                it.setBackground(bg)
            return it

        # Group per-position records into scenarios.  `rows` is ordered
        # saved_at DESC, so the FIRST record seen for a (scenario, position)
        # is the latest session — keep it and skip older duplicates, mirroring
        # VB where EVC_Result_BF holds exactly one AVG row per deck.
        scen = {}          # (hrr, traffic, wind) -> {pos: avg_eq_fatal}
        order = []
        for rec in rows:
            pos, hrr, traffic, wind = self._t6_parse_evc_name(rec["evc_name"])
            key = (hrr, traffic, wind)
            if key not in scen:
                scen[key] = {}
                order.append(key)
            if 1 <= pos <= 6 and pos not in scen[key]:
                scen[key][pos] = float(rec.get("avg_eq_fatal") or 0.0)

        for key in order:
            hrr, traffic, wind = key
            pvals = [scen[key].get(i + 1, 0.0) for i in range(6)]
            ecar = self._t6_get_ecar(hrr, traffic, wind)
            # T column — VB CallFatalities writes
            #   "=_rp1*rc[1]+_rp2*rc[2]+...+_rp6*rc[6]"
            weighted = sum(r * p for r, p in zip(rp, pvals))

            t_letter = "N" if str(traffic).upper().startswith("N") else "C"
            sid = f"{hrr}{t_letter}"
            smk = f"{t_letter}{wind}"

            ri = tbl.rowCount(); tbl.insertRow(ri)
            tbl.setItem(ri, 0, _ci(sid))
            tbl.setItem(ri, 1, _ci(smk))
            tbl.setItem(ri, 2, _ci(f"{ecar:.4E}"))
            tbl.setItem(ri, 3, _ci(f"{1/ecar:.1f}" if ecar > 0 else "∞"))
            tbl.setItem(ri, 4, _ci(f"{weighted:.4f}", bold=True,
                                   bg=QColor(255, 255, 220)))
            for _pi in range(6):
                tbl.setItem(ri, 5 + _pi, _ci(f"{pvals[_pi]:.3f}"))

        tbl.resizeColumnsToContents()

    def _t6_build_maxiter_index(self, rows):
        """Build a per-scenario MAXITER lookup — VB-EXACT semantics.

        VB CalnFillFreq detects MAXITER by walking the contiguous scenario
        block in Raw_senario column 5 (the iteration counter) and taking the
        LARGEST iteration number found:

            If MAXITER < nIter Then MAXITER = nIter

        It does NOT count rows.  Consequence, reproduced here deliberately:
        when a workbook (or this app's results DB) accumulates duplicate
        sessions — e.g. two batches of iterations 1..5 for the same scenario —
        MAXITER stays 5 while the rows double, so every row keeps frequency
        ECAR×RP/5 and the scenario's summed frequency mass DOUBLE-COUNTS
        (Σ row-freq = 2×ECAR).  This matches the VB program bit for bit,
        including on contaminated data.

        Mapping to this app's storage: each session is one DB row whose
        runs_json holds runs numbered run_no = 1..n_run (numbering restarts
        every session, exactly like pasting another 1..5 block under the
        previous one in Raw_senario).  The VB column-max therefore equals
        the maximum run_no observed across ALL DB rows sharing the same
        evc_name (falling back to n_iter / n_run / parsed length when
        run_no is absent).

        The previous behaviour — summing parsed iterations across sessions
        so that Σ row-freq = ECAR is conserved — remains available by
        setting  self.fn_maxiter_mode = 'conserve'  (default 'vb_max').
        Use 'conserve' only when you explicitly want stale duplicate
        sessions to NOT inflate the FN curve; 'vb_max' is what the VB
        workbook produces on the same data.

        Returns
        -------
        dict[str, int]
            Mapping from `evc_name` → MAXITER (>= 1).
        """
        import json
        mode = getattr(self, 'fn_maxiter_mode', 'vb_max')
        acc = {}
        self._t6_maxiter_declared = {}   # evc_name → Σ n_run (diagnostic)
        for rec in rows:
            name = rec.get("evc_name") or ""
            if not name:
                continue
            try:
                runs = json.loads(rec.get("runs_json") or "[]")
            except Exception:
                runs = []
            n_parsed = len(runs)
            # largest iteration number in this session's block (VB col-5 walk)
            blk_max = 0
            for _r in runs:
                try:
                    blk_max = max(blk_max, int(_r.get("run_no") or 0))
                except (TypeError, ValueError, AttributeError):
                    pass
            for _k in ("n_iter", "n_run"):
                try:
                    blk_max = max(blk_max, int(rec.get(_k) or 0))
                except (TypeError, ValueError):
                    pass
            blk_max = max(blk_max, n_parsed)

            if mode == 'conserve':
                acc[name] = acc.get(name, 0) + int(n_parsed)
            else:  # 'vb_max' — VB CalnFillFreq: max across the whole block
                acc[name] = max(acc.get(name, 0), int(blk_max))

            try:
                n_decl = int(rec.get("n_run") or 0)
            except (TypeError, ValueError):
                n_decl = 0
            self._t6_maxiter_declared[name] = (
                self._t6_maxiter_declared.get(name, 0) + max(n_decl, n_parsed))
        # Guarantee at least 1 to avoid divide-by-zero downstream
        return {k: max(v, 1) for k, v in acc.items()}

    def _t6_populate_raw_scenario(self, rows):
        """Sheet 12 — Raw_Senario: per-iteration rows with Frequency and Risk Index."""
        import json
        tbl = self.t6_raw_sen_tbl
        tbl.setRowCount(0)
        rp = self._t6_get_rp_weights()
        base_freq = self.t6_base_freq.value()
        total_risk = 0.0
        # VB-EXACT MAXITER: the block's maximum iteration number per
        # evc_name (VB CalnFillFreq column-5 walk) — see
        # _t6_build_maxiter_index for semantics and the 'conserve' mode.
        maxiter_by_name = self._t6_build_maxiter_index(rows)

        class _SortableItem(QTableWidgetItem):
            """QTableWidgetItem that sorts numerically when UserRole data is set."""
            def __lt__(self, other):
                v_self  = self.data(Qt.UserRole)
                v_other = other.data(Qt.UserRole)
                if v_self is not None and v_other is not None:
                    try:
                        return float(v_self) < float(v_other)
                    except (TypeError, ValueError):
                        pass
                return super().__lt__(other)

        def _ci(txt, bg=None):
            it = _SortableItem(str(txt))
            it.setTextAlignment(Qt.AlignCenter)
            if bg:
                it.setBackground(bg)
            try:
                it.setData(Qt.UserRole, float(txt))
            except (TypeError, ValueError):
                pass
            return it

        for rec in rows:
            pos, hrr, traffic, wind = self._t6_parse_evc_name(rec["evc_name"])
            # VB CalnFillFreq:  Frequency = ECAR(nHrr, nTRC, nWDC) × RP(irp) ÷ MAXITER
            # ECAR is a 7×2×5 lookup keyed on the same (HRR, Traffic, Wind)
            # codes the PDF documents.  irp is the fire-position index (1..6).
            ecar = self._t6_get_ecar(hrr, traffic, wind)
            freq_scenario = ecar * rp[pos - 1] if 1 <= pos <= 6 else ecar

            try:
                runs_raw = json.loads(rec.get("runs_json") or "[]")
            except Exception:
                runs_raw = []

            # VB CalnFillFreq (VB-EXACT): MAXITER is the LARGEST iteration
            # number in the scenario block (column-5 max), looked up across
            # all DB rows sharing this evc_name.  Duplicate sessions keep
            # MAXITER at the per-session count while rows multiply, so the
            # frequency mass double-counts exactly as the VB workbook does.
            # Set self.fn_maxiter_mode = 'conserve' for the conserving
            # alternative (sum of parsed iterations).
            n_runs = max(maxiter_by_name.get(rec.get("evc_name") or "", 0),
                         len(runs_raw), 1)

            for run in runs_raw:
                run_no  = run.get("run_no", run.get("run", "?"))
                ev_time = run.get("ev_time", 0)
                evac    = run.get("evacuees", 0)
                _eq_raw = run.get("eq_fatal")
                eq_f    = float(_eq_raw) if _eq_raw is not None else 0.0

                # VB CalnFillFreq: freq_per_iter = ECAR × RP(pos) / maxiter
                freq_iter = freq_scenario / n_runs if n_runs > 0 else 0

                # All runs are shown (mirrors EVC Result sub-tab which includes
                # every individual run without filtering).  Risk Index is still
                # computed for every row; runs with very small EQ Fatal naturally
                # contribute near-zero to the total.
                risk_idx  = freq_iter * eq_f
                total_risk += risk_idx

                ri = tbl.rowCount(); tbl.insertRow(ri)
                fed_list = run.get("fed", [])
                tbl.setItem(ri, 0, _ci(f"P{pos}"))
                tbl.setItem(ri, 1, _ci(hrr))
                tbl.setItem(ri, 2, _ci(traffic))
                tbl.setItem(ri, 3, _ci(wind))
                tbl.setItem(ri, 4, _ci(run_no))
                tbl.setItem(ri, 5, _ci(f"{ev_time:.1f}"))
                for _fi in range(10):
                    _fv = int(fed_list[_fi]) if _fi < len(fed_list) else 0
                    tbl.setItem(ri, 6 + _fi, _ci(_fv))
                tbl.setItem(ri, 16, _ci(f"{evac:.0f}"))
                tbl.setItem(ri, 17, _ci(f"{eq_f:.4f}"))
                tbl.setItem(ri, 18, _ci(f"{freq_iter:.4E}"))
                tbl.setItem(ri, 19, _ci(f"{risk_idx:.4E}",
                    bg=(QColor(255, 220, 220) if risk_idx > 1e-7 else None)))

        self.t6_total_risk_lbl.setText(f"{total_risk:.6E}  events·fatalities / yr")
        tbl.resizeColumnsToContents()
        # Reset sort button label after re-population
        self._t6_raw_sen_sort_asc = True
        self.t6_raw_sen_sort_btn.setText("\u2191  Sort Ascending")
        # Store for FN chart
        self._t6_total_risk = total_risk

    def _t6_raw_sen_do_sort(self):
        """Toggle sort direction and sort the Raw Scenario table by the selected column.

        Implemented as a pure-Python row sort so that:
        - entire rows always move together as a unit
        - numeric columns (EV Time, FED counts, Frequency, Risk Index …) sort by
          value rather than lexicographically
        - background colours (e.g. highlighted Risk Index cells) are preserved
        """
        self._t6_raw_sen_sort_asc = not self._t6_raw_sen_sort_asc
        ascending = self._t6_raw_sen_sort_asc
        self.t6_raw_sen_sort_btn.setText(
            "\u2191  Sort Ascending" if ascending else "\u2193  Sort Descending"
        )
        col  = self.t6_raw_sen_sort_col.currentIndex()
        tbl  = self.t6_raw_sen_tbl
        n_rows = tbl.rowCount()
        n_cols = tbl.columnCount()

        # 1. Snapshot every cell: (text, QBrush, UserRole-float-or-None)
        snapshot = []
        for r in range(n_rows):
            cells = []
            for c in range(n_cols):
                item = tbl.item(r, c)
                if item:
                    cells.append((item.text(),
                                  item.background(),
                                  item.data(Qt.UserRole)))
                else:
                    cells.append(("", None, None))
            snapshot.append(cells)

        # 2. Build sort key for each row using the target column.
        #    Rows with a numeric UserRole sort numerically; others sort as text.
        def _sort_key(cells):
            text, _bg, num = cells[col]
            if num is not None:
                return (0, num, "")       # numeric primary
            return (1, 0.0, text.lower()) # text fallback

        snapshot.sort(key=_sort_key, reverse=not ascending)

        # 3. Rewrite the table with the sorted rows (preserves backgrounds).
        tbl.setRowCount(0)
        for cells in snapshot:
            ri = tbl.rowCount()
            tbl.insertRow(ri)
            for c, (text, bg, num) in enumerate(cells):
                it = QTableWidgetItem(text)
                it.setTextAlignment(Qt.AlignCenter)
                if bg is not None and bg.style() != Qt.NoBrush:
                    it.setBackground(bg)
                if num is not None:
                    it.setData(Qt.UserRole, num)
                tbl.setItem(ri, c, it)

    def _t6_populate_raw_fnc(self, rows):
        """Sheet 13 — Raw_FNC: sorted FN step data (mirrors FN_CURVE_CREATE3 VB sub)."""
        import json
        tbl = self.t6_raw_fnc_tbl
        tbl.setRowCount(0)
        rp = self._t6_get_rp_weights()
        base_freq = self.t6_base_freq.value()
        # Same VB-faithful MAXITER lookup used by Raw_Senario.
        maxiter_by_name = self._t6_build_maxiter_index(rows)

        # Build step rows exactly as VB FN_CURVE_CREATE3:
        # sort by eq_fatal descending, compute cumulative frequency
        step_rows = []
        for rec in rows:
            pos, hrr, traffic, wind = self._t6_parse_evc_name(rec["evc_name"])
            # Same ECAR lookup as Raw_Senario — keeps the FN curve consistent
            # with the per-row Risk Index.
            ecar = self._t6_get_ecar(hrr, traffic, wind)
            freq_scenario = ecar * rp[pos - 1] if 1 <= pos <= 6 else ecar

            # VB-parity: NORMAL+NV0 scenarios have ECAR=0 in the SenarioTable.
            # Skip zero-frequency scenarios entirely — same guard used by
            # _t6_populate_raw_scenario (VB_SKIP_ZERO_FREQ).  Without this,
            # NV0 runs enter the loop, produce freq_iter=0, and can leak into
            # step_rows when the inner check is bypassed by floating-point edge
            # cases (e.g. -0.0 or denormal underflow).
            if freq_scenario <= 0.0:
                continue

            try:
                runs_raw = json.loads(rec.get("runs_json") or "[]")
            except Exception:
                runs_raw = []

            # Accumulated MAXITER across every session for this evc_name —
            # see _t6_build_maxiter_index for rationale.
            n_runs = max(maxiter_by_name.get(rec.get("evc_name") or "", 0),
                         len(runs_raw), 1)

            for run in runs_raw:
                eq_f    = float(run.get("eq_fatal") or 0)
                ev_time = run.get("ev_time", 0)
                evac    = run.get("evacuees", 0)
                # Business rule: EQ Fatal < 0.1 → zeroed and excluded from FN curve.
                if eq_f < 0.1:
                    continue
                freq_iter = freq_scenario / n_runs if n_runs > 0 else 0.0
                # Skip rows with zero or negative frequency.
                if freq_iter <= 0:
                    continue
                step_rows.append({
                    "pos": pos, "hrr": hrr, "traffic": traffic, "wind": wind,
                    "ev_time": ev_time, "evacuees": evac,
                    "eq_fatal": eq_f, "freq": freq_iter,
                    "name": rec["evc_name"],
                })

        # Final safety filter — remove any row that still has EQ Fatal < 0.1
        # or zero frequency (guards against None/type edge cases above).
        step_rows = [r for r in step_rows if r["eq_fatal"] >= 0.1 and r["freq"] > 0]

        # Sort by eq_fatal descending (matches VB FN_CURVE_CREATE3 xlDescending sort)
        step_rows.sort(key=lambda r: -r["eq_fatal"])

        # Compute cumulative frequency F(>=N)
        # For a given N, F(>=N) is the sum of frequencies of all events with fatalities >= N.
        # Since step_rows is sorted by eq_fatal DESCENDING:
        # For the first row (max N), F(>=N) = its own freq.
        # For the second row, F(>=N) = its own freq + first row's freq.
        cumul = 0.0
        fn_pts = []   # [(n_fatal, cumul_freq)]
        for step in step_rows:
            cumul += step["freq"]
            step["cumul_freq"] = cumul
            fn_pts.append((step["eq_fatal"], cumul))

        # Store only unique (N, F) pairs for plotting to avoid vertical segments at same N
        unique_fn_pts = []
        if fn_pts:
            # Group by eq_fatal
            from collections import defaultdict
            n_map = defaultdict(float)
            for step in step_rows:
                n_map[step["eq_fatal"]] += step["freq"]
            
            # Now calculate cumulative frequency on unique N values
            sorted_unique_n = sorted(n_map.keys(), reverse=True)
            curr_cumul = 0.0
            for n in sorted_unique_n:
                curr_cumul += n_map[n]
                unique_fn_pts.append((n, curr_cumul))

        self._t6_fn_pts = unique_fn_pts   # store for chart
        self._t6_step_rows_sorted = step_rows  # store for data table (left panel)

        # ── Frequency-conservation diagnostic ─────────────────────────────
        # Report (a) the per-iteration curve top F(N≥0.1), (b) the
        # scenario-level total Σ ECAR×RP over fatal scenarios (what the VB
        # FNCurve2/Fatal2FNSheet construction charts), and (c) the session
        # coverage — how badly the OLD declared-n_run denominator would have
        # deflated the curve.  If the Python↔VB FN curves show a constant
        # vertical offset, these three numbers identify the mechanism
        # immediately.
        try:
            top_iter = unique_fn_pts[-1][1] if unique_fn_pts else 0.0
            seen_scen = set()
            top_scen = 0.0
            for rec in rows:
                pos, hrr, traffic, wind = self._t6_parse_evc_name(rec["evc_name"])
                if (rec.get("avg_eq_fatal") or 0.0) < 0.1:
                    continue
                key = rec["evc_name"]
                if key in seen_scen:
                    continue
                seen_scen.add(key)
                ecar = self._t6_get_ecar(hrr, traffic, wind)
                rp_w = rp[pos - 1] if 1 <= pos <= 6 else 1.0
                if ecar * rp_w > 0:
                    top_scen += ecar * rp_w
            decl = sum((getattr(self, "_t6_maxiter_declared", {}) or {}).values())
            parsed = sum(maxiter_by_name.values())
            cov = (decl / parsed) if parsed > 0 else 1.0
            msg = (f"FN diag — per-iteration top F(N≥0.1): {top_iter:.4E}/yr;  "
                   f"per-scenario (FNCurve2) top: {top_scen:.4E}/yr;  "
                   f"session coverage: declared {decl} vs parsed {parsed} "
                   f"iterations (old denominator deflated curve ×{cov:.1f}).")
            self._t6_fn_diag = msg
            if cov > 1.05:
                self.t6_status.setText("⚠  " + msg)
        except Exception:
            self._t6_fn_diag = ""

        def _ci(txt, bg=None):
            it = QTableWidgetItem(str(txt))
            it.setTextAlignment(Qt.AlignCenter)
            if bg:
                it.setBackground(bg)
            return it

        for step in step_rows:
            # Display-level guard: skip any row that still has zero/negative
            # frequency or EQ Fatal below the 0.1 threshold (belt-and-suspenders
            # against any data that slipped through the upstream filters).
            if step['freq'] <= 0.0 or step['eq_fatal'] < 0.1:
                continue
            ri = tbl.rowCount(); tbl.insertRow(ri)
            tbl.setItem(ri, 0, _ci(f"P{step['pos']}"))
            tbl.setItem(ri, 1, _ci(f"{step['hrr']}"))
            tbl.setItem(ri, 2, _ci(f"{step['traffic']} / {step['wind']}"))
            tbl.setItem(ri, 3, _ci(f"{step['evacuees']:.0f}"))
            tbl.setItem(ri, 4, _ci(f"{step['ev_time']:.1f}"))
            tbl.setItem(ri, 5, _ci(f"{step['freq']:.4E}"))
            tbl.setItem(ri, 6, _ci(f"{step['eq_fatal']:.4f}"))
            tbl.setItem(ri, 7, _ci(f"{step['cumul_freq']:.4E}"))

        tbl.resizeColumnsToContents()

    # ════════════════════════════════════════════════════════════════════════
    # FN Curve2  (replica of the FNCurve2 worksheet, VB Fatal2FNSheet logic)
    # ════════════════════════════════════════════════════════════════════════
    def _t6_vk_for_hrr(self, hrr: str) -> float:
        """Vehicle-km denominator for the Frequency/veh-km column, by HRR class.

        Mirrors the VB FNCurve2 'F = E / VK.xxx' normalisation:
          PC  -> VK.PC,  020 -> VK.HRR020,  030 -> VK.HRR030,  100 -> VK.HRR100.
        Pulled from the StandardScenarioWidget's fire-size factors (which load
        VK.PC / VK.HRRxxx from the workbook). Falls back to VB defaults.
        """
        ssw = getattr(self, "standard_scenario_widget", None)
        factors = getattr(ssw, "_fire_size_factors", None) if ssw else None
        # Defaults match standard_scenario_widget.FireSizeWorkbookFactors.default()
        vk_pc = 2759393.065
        vk_hrr = {10: 2759393.065, 20: 287594.45, 30: 70309.27475, 100: 2346.16525}
        if factors is not None:
            try:
                vk_pc = float(factors.vk_pc) or vk_pc
                vk_hrr = {int(k): float(v) for k, v in (factors.vk_hrr or {}).items()} or vk_hrr
            except Exception:
                pass
        if hrr in ("PC1", "PC2", "PC"):
            return vk_pc
        if hrr == "020":
            return vk_hrr.get(20, 287594.45)
        if hrr == "030":
            return vk_hrr.get(30, 70309.27475)
        if hrr == "100":
            return vk_hrr.get(100, 2346.16525)
        return vk_pc

    def _t6_populate_fncurve2(self, rows):
        """Replicate the FNCurve2 worksheet's per-fire-scenario detail block.

        Implements the VB Fatal2FNSheet writer for each (fire-position × scenario)
        combination:
            Frequency /yr     = ECAR(HRR, Traffic, Wind) × RP(fire-pos)
            Frequency /veh-km = (ECAR / VK_class)        × RP(fire-pos)
            Return Year       = 1 / Frequency/yr   (blank if Frequency == 0)
            Fatalities        = scenario EQ_Fatal (averaged over runs)
            Risk Index        = Fatalities × Frequency/yr
        Then sorts by Fatalities descending and computes the cumulative
        frequency column, exactly as FN_CURVE_CREATE2 does.
        """
        import json
        # Guard: some builds do not construct the optional "FN Curve2" sub-tab.
        # If its widgets are absent, no-op rather than raising AttributeError
        # (which would otherwise abort the whole _t6_load_all sequence and
        # leave later tabs — e.g. the FN Curve chart — unpopulated).
        if not hasattr(self, "t6_fnc2_tbl"):
            return
        tbl = self.t6_fnc2_tbl
        tbl.setRowCount(0)
        rp = self._t6_get_rp_weights()
        maxiter_by_name = self._t6_build_maxiter_index(rows)

        scen_rows = []
        for rec in rows:
            pos, hrr, traffic, wind = self._t6_parse_evc_name(rec["evc_name"])
            ecar = self._t6_get_ecar(hrr, traffic, wind)
            rp_w = rp[pos - 1] if 1 <= pos <= 6 else 1.0

            # Frequency/yr = ECAR × RP(pos)  (VB Fatal2FNSheet: Freq1(j) × RP(i))
            freq_yr = ecar * rp_w
            # VB-parity: skip zero-frequency scenarios (NORMAL+NV0), matching the
            # Raw Scenario tab and VB's displayed FNCurve2 block.
            if freq_yr <= 0.0:
                continue
            # Frequency/veh-km = (ECAR / VK_class) × RP(pos)  (Freq2(j) × RP(i))
            vk = self._t6_vk_for_hrr(hrr)
            freq_vk = (ecar / vk * rp_w) if vk else 0.0

            # ── Fatalities & Risk Index (VB CalnFillFreq / Fatal2FNSheet) ────
            # Raw Scenario computes risk per iteration as:
            #     Σ_iter [ (ECAR×RP / maxiter) × eq_iter ]
            #   = ECAR×RP × ( Σ_iter eq_iter / maxiter )
            # where maxiter is the TOTAL iteration count across every DB row
            # that shares this scenario's evc_name (not just this row's runs).
            # FN Curve2 must use the same normalisation so its Total Risk Index
            # matches the Raw Scenario tab. Previously it divided by this row's
            # run count only and multiplied by the full ECAR×RP, which
            # over-counted scenarios that span more than one DB row.
            try:
                runs_raw = json.loads(rec.get("runs_json") or "[]")
            except Exception:
                runs_raw = []

            # Per-iteration EQ Fatal with the same 0.1 cutoff Raw Scenario uses
            # (a zero-fatality iteration must contribute zero risk).
            eq_vals = [(r.get("eq_fatal", 0) or 0.0) for r in runs_raw]
            eq_cut  = [e if e >= 0.1 else 0.0 for e in eq_vals]

            # maxiter = full iteration count for this scenario across all rows.
            n_runs = max(maxiter_by_name.get(rec.get("evc_name") or "", 0),
                         len(eq_vals), 1)

            # Displayed Fatalities = expected deaths if this fire occurs =
            # within-scenario mean (NOT divided by maxiter), so the column still
            # reads as a physical fatality count.
            if eq_vals:
                fatalities = sum(eq_vals) / len(eq_vals)
            else:
                fatalities = rec.get("avg_eq_fatal", 0) or 0.0
            if abs(fatalities) < 5e-5:
                fatalities = 0.0

            # Business rule (EXCLUSION): a scenario whose (averaged) Fatalities
            # is below 0.1 is excluded entirely — not displayed and not summed
            # into the Risk Index / PLL. (Zero-frequency rows were already
            # skipped above.) Keeps this tab consistent with the Raw FNC table
            # and the FN curve.
            if fatalities < 0.1:
                continue

            # Risk Index = ECAR×RP × ( Σ eq_iter / maxiter )  — VB-faithful,
            # identical to the Raw Scenario per-iteration accumulation.
            fatalities_for_risk = (sum(eq_cut) / n_runs) if n_runs > 0 else 0.0
            return_year = (1.0 / freq_yr) if freq_yr > 0 else None
            risk_index = freq_yr * fatalities_for_risk

            scen_rows.append({
                "pos": pos,
                "scenario": f"{hrr}-{wind}",
                "desc": f"{hrr} {traffic} / {wind}",
                "freq_yr": freq_yr,
                "freq_vk": freq_vk,
                "return_year": return_year,
                "fatalities": fatalities,
                "risk_index": risk_index,
            })

        # Sort by Fatalities descending (VB FN_CURVE_CREATE2 xlDescending on R-col)
        scen_rows.sort(key=lambda r: -r["fatalities"])

        # Cumulative frequency (S-column: running sum of Frequency/yr)
        cumul = 0.0
        total_risk = 0.0
        for r in scen_rows:
            cumul += r["freq_yr"]
            r["cumul_freq"] = cumul
            total_risk += r["risk_index"]

        # Keep detailed scenario rows for FN table fallback when Raw_FNC is disabled.
        self._t6_fn_rows_scen = list(scen_rows)

        # Store the per-scenario FN points (N = scenario-average fatalities,
        # F = running Σ ECAR×RP) so the FN Curve tab can draw the VB
        # FNCurve2/Fatal2FNSheet construction when "Per-scenario" is selected
        # as the curve source.  Collapse duplicate N values like the
        # per-iteration path does.
        try:
            from collections import defaultdict as _dd
            _nmap = _dd(float)
            for r in scen_rows:
                _nmap[r["fatalities"]] += r["freq_yr"]
            _pts = []
            _c = 0.0
            for _n in sorted(_nmap.keys(), reverse=True):
                _c += _nmap[_n]
                _pts.append((_n, _c))
            self._t6_fn_pts_scen = _pts
        except Exception:
            self._t6_fn_pts_scen = []

        def _ci(txt, right=False, bg=None):
            it = QTableWidgetItem(str(txt))
            it.setTextAlignment(Qt.AlignRight | Qt.AlignVCenter if right
                                else Qt.AlignCenter)
            if bg:
                it.setBackground(bg)
            return it

        for r in scen_rows:
            ri = tbl.rowCount(); tbl.insertRow(ri)
            tbl.setItem(ri, 0, _ci(f"P{r['pos']}"))
            tbl.setItem(ri, 1, _ci(r["scenario"]))
            tbl.setItem(ri, 2, _ci(r["desc"]))
            tbl.setItem(ri, 3, _ci(f"{r['freq_yr']:.4E}", right=True))
            tbl.setItem(ri, 4, _ci(f"{r['freq_vk']:.4E}", right=True))
            tbl.setItem(ri, 5, _ci("" if r["return_year"] is None
                                   else f"{r['return_year']:,.1f}", right=True))
            tbl.setItem(ri, 6, _ci(f"{r['fatalities']:.1f}", right=True))
            ri_bg = QColor(255, 220, 220) if r["risk_index"] > 1e-7 else None
            tbl.setItem(ri, 7, _ci(f"{r['risk_index']:.4E}", right=True, bg=ri_bg))
            tbl.setItem(ri, 8, _ci(f"{r['cumul_freq']:.4E}", right=True))

        tbl.resizeColumnsToContents()
        self.t6_fnc2_total_lbl.setText(
            f"Total Risk Index (PLL):  {total_risk:.6E}  events·fatalities / yr")

    def _t6_rebuild_fncurve2(self):
        """Rebuild button handler — re-reads the loaded rows and repopulates."""
        if not hasattr(self, "t6_fnc2_total_lbl"):
            return  # FN Curve2 sub-tab not present in this build
        rows = getattr(self, "_t6_raw_rows", None)
        if not rows:
            self.t6_fnc2_total_lbl.setText(
                "Total Risk Index (PLL):  —  (load results first)")
            return
        self._t6_populate_fncurve2(rows)

    def _t6_draw_fn_chart(self):
        """Sheet 11 — FNCurve2: draw the log-log FN staircase chart (mirrors UI 1)."""
        import math
        if not getattr(self, '_t6_has_canvas', False):
            return

        # Ensure scenario-based FN data is available for chart/table fallbacks.
        if not getattr(self, '_t6_fn_rows_scen', None):
            _rows = getattr(self, '_t6_raw_rows', None)
            if _rows:
                try:
                    self._t6_populate_fncurve2(_rows)
                except Exception:
                    pass

        # ── Populate the left-panel sorted-scenarios table ────────────────
        if hasattr(self, 't6_fn_pts_tbl'):
            _tbl = self.t6_fn_pts_tbl
            _tbl.setRowCount(0)
            _step_rows = getattr(self, '_t6_step_rows_sorted', [])
            _used_step_rows = False
            for _sr in _step_rows:
                # Exclusion rule (display guard): never show a row whose
                # frequency is <= 0 or whose EQ Fatal is < 0.1, consistent with
                # the Raw FNC table and the risk-index total.
                if float(_sr.get('freq', 0) or 0) <= 0.0 or \
                   float(_sr.get('eq_fatal', 0) or 0) < 0.1:
                    continue
                _ri = _tbl.rowCount(); _tbl.insertRow(_ri)
                def _ci(v):
                    _it = QTableWidgetItem(str(v))
                    _it.setTextAlignment(Qt.AlignCenter)
                    return _it
                _tbl.setItem(_ri, 0, _ci(f"P{_sr.get('pos','')}"))
                _tbl.setItem(_ri, 1, _ci(_sr.get('name', _sr.get('hrr','?'))))
                _tbl.setItem(_ri, 2, _ci(f"{float(_sr.get('eq_fatal',0)):.4f}"))
                _tbl.setItem(_ri, 3, _ci(f"{float(_sr.get('freq',0)):.4E}"))
                _tbl.setItem(_ri, 4, _ci(f"{float(_sr.get('cumul_freq',0)):.4E}"))
                _used_step_rows = True

            # Fallback: if Raw_FNC step rows are unavailable, show the
            # per-scenario FNCurve2 rows so Pos/Scenario/Frequency remain visible.
            if not _used_step_rows:
                _scen_rows = list(getattr(self, '_t6_fn_rows_scen', []) or [])
                for _r in _scen_rows:
                    _ri = _tbl.rowCount(); _tbl.insertRow(_ri)
                    def _ci(v):
                        _it = QTableWidgetItem(str(v))
                        _it.setTextAlignment(Qt.AlignCenter)
                        return _it
                    _tbl.setItem(_ri, 0, _ci(f"P{int(_r.get('pos', 0) or 0)}"))
                    _tbl.setItem(_ri, 1, _ci(str(_r.get('scenario', ''))))
                    _tbl.setItem(_ri, 2, _ci(f"{float(_r.get('fatalities', 0) or 0):.4f}"))
                    _tbl.setItem(_ri, 3, _ci(f"{float(_r.get('freq_yr', 0) or 0):.4E}"))
                    _tbl.setItem(_ri, 4, _ci(f"{float(_r.get('cumul_freq', 0) or 0):.4E}"))

        # ── Select curve source (Per-iteration Raw_FNC vs Per-scenario
        #    FNCurve2/Fatal2FNSheet) ─────────────────────────────────────────
        _src_scen = False
        try:
            _src_scen = (getattr(self, "t6_fn_source_combo", None) is not None
                         and self.t6_fn_source_combo.currentIndex() == 1)
        except Exception:
            _src_scen = False
        if _src_scen:
            # FNCurve2 points may not have been built yet for this load.
            if not getattr(self, "_t6_fn_pts_scen", None):
                rows_for_scen = getattr(self, "_t6_raw_rows", None)
                if rows_for_scen:
                    try:
                        self._t6_populate_fncurve2(rows_for_scen)
                    except Exception:
                        pass
            _fn_pts_active = list(getattr(self, "_t6_fn_pts_scen", []) or [])
        else:
            _fn_pts_active = list(getattr(self, "_t6_fn_pts", []) or [])

        # Raw_FNC points may be unavailable in builds where that sub-tab/pipeline
        # is disabled. Fall back to the FNCurve2 scenario points so the chart
        # remains usable.
        if not _fn_pts_active:
            _fn_pts_active = list(getattr(self, "_t6_fn_pts_scen", []) or [])

        if not _fn_pts_active:
            # No data yet — show hint
            self.t6_fn_ax.cla()
            self.t6_fn_ax.set_xlabel(
                getattr(self, 't6_fn_xlabel_edit', None) and
                self.t6_fn_xlabel_edit.text() or "Number of Fatalities  N", fontsize=11)
            self.t6_fn_ax.set_ylabel(
                getattr(self, 't6_fn_ylabel_edit', None) and
                self.t6_fn_ylabel_edit.text() or "Cumulative Frequency  F(≥N)  [events/year]",
                fontsize=11)
            self.t6_fn_ax.text(0.5, 0.5, "No data — load results and click  🔁  Redraw",
                               transform=self.t6_fn_ax.transAxes,
                               ha='center', va='center', fontsize=13, color='#7f8c8d',
                               bbox=dict(boxstyle='round,pad=0.5', fc='#ecf0f1', alpha=0.8))
            self.t6_fn_canvas.draw()
            return

        # ── Build staircase ───────────────────────────────────────────────
        plot_pts = sorted(_fn_pts_active, key=lambda p: p[0])
        xs, ys = [], []
        if plot_pts:
            for i, (n_curr, f_curr) in enumerate(plot_pts):
                if i == 0:
                    xs.append(0.1 if n_curr > 0.1 else max(1e-3, n_curr * 0.9))
                    ys.append(f_curr)
                xs.append(n_curr); ys.append(f_curr)
                if i < len(plot_pts) - 1:
                    n_next, f_next = plot_pts[i + 1]
                    xs.append(n_next); ys.append(f_curr)
                    xs.append(n_next); ys.append(f_next)
                else:
                    xs.append(n_curr * 1.2); ys.append(f_curr)

        ax = self.t6_fn_ax
        ax.cla()

        # ── Axis range ────────────────────────────────────────────────────
        _auto = getattr(self, 't6_fn_auto_axes_cb', None) and self.t6_fn_auto_axes_cb.isChecked()
        if _auto or not xs:
            x_left  = (min(xs) * 0.7) if xs else 0.1
            x_right = (max(xs) * 1.4) if xs else 100.0
            _ys_pos = [y for y in ys if y > 0]
            y_bot   = (min(_ys_pos) * 0.1) if _ys_pos else 1e-12
            y_top   = (max(ys) * 10.0) if ys else 1.0
        else:
            x_left  = float(self.t6_fn_x_start.value()) if hasattr(self, 't6_fn_x_start') else 1.0
            x_right = float(self.t6_fn_x_stop.value())  if hasattr(self, 't6_fn_x_stop')  else 1e4
            y_bot   = float(self.t6_fn_y_start.value()) if hasattr(self, 't6_fn_y_start') else 1e-9
            y_top   = float(self.t6_fn_y_stop.value())  if hasattr(self, 't6_fn_y_stop')  else 1.0
            if x_right <= x_left:  x_right = x_left * 10.0
            if y_top   <= y_bot:   y_top   = y_bot  * 10.0

        # ── ALARP bands ───────────────────────────────────────────────────
        if getattr(self, 't6_show_alarp_cb', None) and self.t6_show_alarp_cb.isChecked():
            _xb = [x_left, x_right]
            _fu = self.t6_alarp_upper.value()
            _fl = self.t6_alarp_lower.value()
            if _fu > _fl:
                ax.fill_between(_xb, [_fu]*2, [max(y_top, 1.0)]*2,
                                alpha=0.12, color='#e74c3c',
                                label=f'Intolerable (>{_fu:.0E}/yr)')
                ax.fill_between(_xb, [_fl]*2, [_fu]*2,
                                alpha=0.10, color='#f39c12', label='ALARP region')
                ax.fill_between(_xb, [min(y_bot, 1e-14)]*2, [_fl]*2,
                                alpha=0.10, color='#27ae60',
                                label=f'Broadly acceptable (<{_fl:.0E}/yr)')

        # ── HSE criterion lines: F = anchor / N ───────────────────────────
        if getattr(self, 't6_fn_show_hse_cb', None) and self.t6_fn_show_hse_cb.isChecked():
            _anch_hi = self.t6_fn_hse_high.value()
            _anch_lo = self.t6_fn_hse_low.value()
            _xl = [x_left, x_right]
            for _anch, _col, _lbl in (
                (_anch_hi, '#c0392b', f'HSE High Level (F = {_anch_hi:.0E}/N)'),
                (_anch_lo, '#16a085', f'HSE Low Level (F = {_anch_lo:.0E}/N)'),
            ):
                ax.plot(_xl, [_anch / x_left, _anch / x_right],
                        linestyle='--', color=_col, linewidth=1.6,
                        alpha=0.85, label=_lbl)

        # ── FN staircase ──────────────────────────────────────────────────
        if xs and ys:
            ax.plot(xs, ys, '-', color='#2c3e50', linewidth=2.0, label='F-N curve')

        # ── Scenario knots ────────────────────────────────────────────────
        if _fn_pts_active and getattr(self, 't6_show_knots_cb', None) and self.t6_show_knots_cb.isChecked():
            _kx = [p[0] for p in _fn_pts_active]
            _ky = [p[1] for p in _fn_pts_active]
            ax.plot(_kx, _ky, 'o', color='#c0392b', markersize=5, label='Scenario knots')

        ax.set_xscale('log'); ax.set_yscale('log')
        ax.set_xlabel(
            self.t6_fn_xlabel_edit.text() if hasattr(self, 't6_fn_xlabel_edit')
            else "Number of Fatalities  N", fontsize=11)
        ax.set_ylabel(
            self.t6_fn_ylabel_edit.text() if hasattr(self, 't6_fn_ylabel_edit')
            else "Cumulative Frequency  F(≥N)  [events/year]", fontsize=11)
        ax.set_title(
            self.t6_fn_title_edit.text() if hasattr(self, 't6_fn_title_edit')
            else "F-N Curve  (Quantitative Risk Assessment)",
            fontsize=13, fontweight='bold')
        if getattr(self, 't6_show_grid_cb', None) and self.t6_show_grid_cb.isChecked():
            ax.grid(True, which='both', lw=0.5, alpha=0.5)
        else:
            ax.grid(False)
        ax.set_xlim(x_left, x_right)
        ax.set_ylim(y_bot, y_top)

        # Legend with drag support
        _loc = getattr(self, '_t6_fn_legend_loc', 'upper right')
        if isinstance(_loc, tuple):
            _legend = ax.legend(fontsize=9, framealpha=0.85,
                                loc='upper left', bbox_to_anchor=_loc,
                                bbox_transform=self.t6_fn_fig.transFigure)
        else:
            _legend = ax.legend(fontsize=9, framealpha=0.85, loc=_loc)
        try:
            _legend.set_draggable(True, use_blit=False)
            def _drag_release(_evt, _leg=_legend):
                try:
                    _bbox = _leg.get_window_extent()
                    _inv  = self.t6_fn_fig.transFigure.inverted()
                    _x0, _y0 = _inv.transform((_bbox.x0, _bbox.y1))
                    self._t6_fn_legend_loc = (float(_x0), float(_y0))
                except Exception:
                    pass
            self.t6_fn_canvas.mpl_connect('button_release_event', _drag_release)
        except Exception:
            pass

        self.t6_fn_fig.tight_layout()
        self.t6_fn_canvas.draw()

    def _t6_recalculate_fn(self):
        """Recalculate everything with current RP weights / exmax / exmin."""
        if not hasattr(self, '_t6_raw_rows') or not self._t6_raw_rows:
            self._t6_load_all()
            return
        rows = self._t6_raw_rows
        self._t6_populate_bf2(rows)
        self._t6_populate_scenario(rows)
        self._t6_populate_raw_scenario(rows)
        self._t6_populate_fncurve2(rows)
        self._t6_draw_fn_chart()
        self.t6_status.setText("✅  Recalculated with updated RP weights / exmax / exmin.")

    def _t6_clear_evacuation_db(self):
        """Delete all batch_evc_results from the project database for a clean run."""
        import sqlite3
        from pathlib import Path

        db_path = self._get_project_db_path()
        if not db_path.exists():
            QMessageBox.information(self, "No Database",
                                    "No project database found — nothing to clear.")
            return

        reply = QMessageBox.question(
            self, "Clear Evacuation Results",
            f"This will permanently delete ALL evacuation batch results from:\n"
            f"{db_path.name}\n\n"
            f"This cannot be undone. Continue?",
            QMessageBox.Yes | QMessageBox.No, QMessageBox.No
        )
        if reply != QMessageBox.Yes:
            return

        try:
            con = sqlite3.connect(str(db_path))
            cur = con.cursor()
            cur.execute("DELETE FROM batch_evc_results")
            deleted = cur.rowcount
            con.commit()
            con.close()
        except Exception as _e:
            QMessageBox.warning(self, "DB Error", f"Failed to clear results: {_e}")
            return

        # Clear all Tab 6 sub-tab tables
        for tbl_attr in ('t6_evc_result_tbl', 't6_bf_tbl', 't6_bf2_tbl',
                          't6_scenario_tbl', 't6_raw_scenario_tbl'):
            tbl = getattr(self, tbl_attr, None)
            if tbl:
                tbl.setRowCount(0)
        if hasattr(self, '_t6_raw_rows'):
            self._t6_raw_rows = []

        self.t6_status.setText(
            f"🗑  Cleared {deleted} record(s) from {db_path.name}. Ready for a clean run."
        )
        self.statusBar().showMessage(
            f"🗑  Evacuation results cleared from {db_path.name}.", 8000
        )

    def _t6_save_fn_png(self):
        """Save the FN curve chart as a PNG file."""
        if not getattr(self, '_t6_has_canvas', False):
            return
        path, _ = QFileDialog.getSaveFileName(
            self, "Save FN Curve", "fn_curve.png",
            "PNG Images (*.png);;All Files (*.*)"
        )
        if path:
            try:
                self.t6_fn_fig.savefig(path, dpi=150, bbox_inches='tight')
                self.t6_status.setText(f"✅  Chart saved: {path}")
            except Exception as _e:
                self.t6_status.setText(f"⚠  Save failed: {_e}")

    def _t6_export_excel(self):
        """Export all sub-tab tables to an Excel workbook (.xlsx)."""
        try:
            import openpyxl
        except ImportError:
            QMessageBox.warning(
                self, "Missing Library",
                "openpyxl is required for Excel export.\n"
                "Install it with:  pip install openpyxl"
            )
            return

        path, _ = QFileDialog.getSaveFileName(
            self, "Export to Excel", "QRA_PostResults.xlsx",
            "Excel Files (*.xlsx);;All Files (*.*)"
        )
        if not path:
            return

        try:
            from openpyxl import Workbook
            from openpyxl.styles import Font, PatternFill, Alignment

            def _parse_scientific(text: str):
                import re
                if not text:
                    return None
                m = re.search(r"([-+]?\d+(?:\.\d+)?(?:[Ee][-+]?\d+)?)", str(text))
                if not m:
                    return None
                try:
                    return float(m.group(1))
                except ValueError:
                    return None

            def _summary_value_from_label(widget):
                if widget is None:
                    return None
                return _parse_scientific(widget.text())

            wb = Workbook()
            ws = wb.active; ws.title = "EVC_Result"

            def _write_table(ws, tbl_widget, sheet_name):
                ws.title = sheet_name
                # Header
                hdr_font = Font(bold=True, color="FFFFFF")
                hdr_fill = PatternFill("solid", fgColor="2980B9")
                for ci in range(tbl_widget.columnCount()):
                    cell = ws.cell(row=1, column=ci + 1,
                                   value=tbl_widget.horizontalHeaderItem(ci).text()
                                   if tbl_widget.horizontalHeaderItem(ci) else "")
                    cell.font = hdr_font; cell.fill = hdr_fill
                    cell.alignment = Alignment(horizontal='center')
                # Data
                for ri in range(tbl_widget.rowCount()):
                    for ci in range(tbl_widget.columnCount()):
                        item = tbl_widget.item(ri, ci)
                        ws.cell(row=ri + 2, column=ci + 1,
                                value=item.text() if item else "")

            tables = [
                (self.t6_evc_result_tbl,  "EVC_Result"),
                (self.t6_bf_tbl,           "EVC_Result_BF"),
                (self.t6_bf2_tbl,          "EVC_Result_BF2"),
                (self.t6_scenario_tbl,     "Standard_Scenario"),
                (self.t6_raw_sen_tbl,      "Raw_Senario"),
            ]
            _write_table(ws, tables[0][0], tables[0][1])
            for tbl_w, sname in tables[1:]:
                _write_table(wb.create_sheet(), tbl_w, sname)

            # Summary cells on the same results sheet.
            # Place them to the right of the main results table so they do not
            # interfere with the exported table layout.
            summary_col = max(6, tables[0][0].columnCount() + 2)
            summary_fill = PatternFill("solid", fgColor="EAF2F8")
            label_fill = PatternFill("solid", fgColor="D6EAF8")
            label_font = Font(bold=True, color="1F2D3D")
            value_font = Font(bold=True, color="C0392B")

            summaries = [
                ("Risk Index", _summary_value_from_label(getattr(self, "t6_total_risk_lbl", None))),
                ("PLL", _summary_value_from_label(getattr(self, "t6_fnc2_total_lbl", None))),
            ]
            for row_offset, (label, value) in enumerate(summaries, start=1):
                label_cell = ws.cell(row=row_offset, column=summary_col, value=label)
                label_cell.font = label_font
                label_cell.fill = label_fill
                label_cell.alignment = Alignment(horizontal="center")

                value_cell = ws.cell(
                    row=row_offset,
                    column=summary_col + 1,
                    value=("" if value is None else value),
                )
                value_cell.font = value_font
                value_cell.fill = summary_fill
                value_cell.alignment = Alignment(horizontal="center")

            # FN chart image if available
            if getattr(self, '_t6_has_canvas', False):
                import io
                buf = io.BytesIO()
                self.t6_fn_fig.savefig(buf, format='png', dpi=120,
                                       bbox_inches='tight')
                buf.seek(0)
                from openpyxl.drawing.image import Image as XLImage
                ws_fn = wb.create_sheet("FN_Curve")
                img = XLImage(buf)
                ws_fn.add_image(img, "A1")

            wb.save(path)
            self.t6_status.setText(f"✅  Exported to Excel: {path}")
            QMessageBox.information(self, "Export Complete",
                                    f"Results exported to:\n{path}")

        except Exception as _ex:
            self.t6_status.setText(f"⚠  Export error: {_ex}")
            QMessageBox.warning(self, "Export Error", str(_ex))

    def create_tab7_results(self):
        """Tab 7: Results and Visualization with Sub-tabs"""
        tab = QWidget()
        scroll = QScrollArea()
        scroll.setWidgetResizable(True)
        scroll.setWidget(tab)
        layout = QVBoxLayout()
        tab.setLayout(layout)
        
        header_label = QLabel("📋 Risk Calculations")
        header_label.setStyleSheet("font-size: 16px; font-weight: bold; color: #2c3e50; padding: 10px;")
        layout.addWidget(header_label)

        # Create sub-tabs widget
        self.t7_sub_tabs = QTabWidget()
        self.t7_sub_tabs.setStyleSheet("""
            QTabBar::tab {
                background: #ecf0f1;
                padding: 8px 16px;
                margin-right: 2px;
                border-radius: 4px 4px 0 0;
            }
            QTabBar::tab:selected {
                background: #3498db;
                color: white;
                font-weight: bold;
            }
            QTabBar::tab:hover {
                background: #34495e;
                color: white;
            }
        """)
        
        # Sub-tab 1: Tunnel Traffic Volume (before Standard Scenario)
        tunnel_traffic_tab = QWidget()
        tunnel_traffic_layout = QVBoxLayout()
        tunnel_traffic_tab.setLayout(tunnel_traffic_layout)
        try:
            from tunnel_traffic_widget import TunnelTrafficWidget
            self.tunnel_traffic_widget = TunnelTrafficWidget()
            tunnel_traffic_layout.addWidget(self.tunnel_traffic_widget)
        except Exception as _e_tt:
            _tt_err = QLabel(
                f"⚠  Could not load TunnelTrafficWidget: {_e_tt}\n"
                "Ensure tunnel_traffic_widget.py and tunnel_traffic_sheet.json are in the same directory."
            )
            _tt_err.setWordWrap(True)
            _tt_err.setStyleSheet("color:#c0392b;font-size:11px;padding:8px;")
            tunnel_traffic_layout.addWidget(_tt_err)
        
        self.t7_sub_tabs.addTab(tunnel_traffic_tab, "Tunnel Traffic Volume")
        
        # Sub-tab 2: Standard Scenario
        std_scenario_tab = QWidget()
        std_scenario_layout = QVBoxLayout()
        std_scenario_tab.setLayout(std_scenario_layout)
        try:
            from standard_scenario_widget import StandardScenarioWidget
            self.standard_scenario_widget = StandardScenarioWidget()
            std_scenario_layout.addWidget(self.standard_scenario_widget)
        except Exception as _e_ss:
            _std_err = QLabel(
                f"⚠  Could not load StandardScenarioWidget: {_e_ss}\n"
                "Ensure standard_scenario_widget.py is in the same directory."
            )
            _std_err.setWordWrap(True)
            _std_err.setStyleSheet("color:#c0392b;font-size:11px;padding:8px;")
            std_scenario_layout.addWidget(_std_err)

        # Wire Standard Scenario factors to Tunnel Traffic pre-calculated values
        # (mirrors FNCV_ROAD worksheet dependency direction).
        try:
            if hasattr(self, "tunnel_traffic_widget") and hasattr(self, "standard_scenario_widget"):
                if hasattr(self.tunnel_traffic_widget, "precalculatedValuesChanged"):
                    self.tunnel_traffic_widget.precalculatedValuesChanged.connect(
                        self.standard_scenario_widget.set_fire_size_factors_from_tunnel
                    )
                    # Also refresh the Tab 6 ECAR table whenever the upstream
                    # traffic factors change — this keeps the risk-index
                    # calculation in lock-step with whatever's currently shown
                    # on the Standard Scenario event tree.
                    def _t6_refresh_after_factors_change(*_args, **_kwargs):
                        try:
                            if hasattr(self, "t6_ecar_tbl"):
                                self._t6_load_ecar_from_standard_scenario()
                                # Recalculate Raw_Senario / FN curve only if
                                # Tab 6 has data loaded; otherwise no-op.
                                if getattr(self, "_t6_raw_rows", None):
                                    self._t6_recalculate()
                        except Exception:
                            pass
                    self.tunnel_traffic_widget.precalculatedValuesChanged.connect(
                        _t6_refresh_after_factors_change
                    )
                if hasattr(self.tunnel_traffic_widget, "get_standard_scenario_factors"):
                    _initial = self.tunnel_traffic_widget.get_standard_scenario_factors()
                    self.standard_scenario_widget.set_fire_size_factors_from_tunnel(_initial)
                    # Initial fill of the ECAR table — best-effort, silent on
                    # failure (Tab 6 may not have been built yet).
                    try:
                        if hasattr(self, "t6_ecar_tbl"):
                            self._t6_load_ecar_from_standard_scenario()
                    except Exception:
                        pass
                # If Tab 6 rows already exist, sync P1-P6/fatalities immediately.
                if getattr(self, "_t6_raw_rows", None):
                    self._t6_sync_standard_scenario_fatalities(self._t6_raw_rows)
        except Exception:
            pass

        # ── Auto-populate D3/G3/J3 in Tunnel Traffic Volume from Tunnel Info ──
        # Reads Length (m→km), Gradient (%), Perimeter (m) from the Tunnel
        # Basic Specifications panel in EVC/FED Analysis → Tunnel Info and
        # pushes them live into the corresponding editable cells every time
        # any of those three fields changes.
        try:
            def _push_tunnel_info_to_traffic(*_args):
                ttw = getattr(self, "tunnel_traffic_widget", None)
                if ttw is None or not hasattr(ttw, "set_tunnel_info_cells"):
                    return
                try:
                    length   = float(self.tbi_length.text().strip()    or 0)
                    gradient = float(self.tbi_gradient.text().strip()   or 0)
                    perimeter = float(self.tbi_road_width.text().strip() or 0)
                    ttw.set_tunnel_info_cells(length, gradient, perimeter)
                except (ValueError, AttributeError):
                    pass

            self.tbi_length.textChanged.connect(_push_tunnel_info_to_traffic)
            self.tbi_gradient.textChanged.connect(_push_tunnel_info_to_traffic)
            self.tbi_road_width.textChanged.connect(_push_tunnel_info_to_traffic)
            # Initial push so values are correct immediately on startup.
            _push_tunnel_info_to_traffic()
        except Exception:
            pass

        # ── Auto-populate E8:K8 and E11:K11 from Traffic Volume & Vehicle Specs ──
        # Row 0 ("+Dir") → E8:K8 and Row 6 ("Occupants") → E11:K11 in the
        # Tunnel Traffic Volume sheet.  Updates fire whenever either row changes.
        try:
            _VOL_N_COLS = 7   # Car … Special  (columns E through K)
            _ROW_PLUS_DIR  = 0
            _ROW_MINUS_DIR = 1
            _ROW_OCCUPANTS = 6
            _EVAC_OCCUPANTS_COL = 3

            def _read_veh_row(row_idx: int):
                """Return list of 7 text values from tbi_veh_table for row_idx."""
                vals = []
                for ci in range(_VOL_N_COLS):
                    it = self.tbi_veh_table.item(row_idx, ci)
                    vals.append(it.text().strip() if it else "0")
                return vals

            def _sync_occupants_to_dependents(*_args):
                occupants = _read_veh_row(_ROW_OCCUPANTS)

                # Keep the evac-parameter occupants column aligned with the
                # Traffic Volume & Vehicle Specs occupants row so both views
                # use the same per-vehicle occupant basis.
                evac_tbl = getattr(self, "evac_veh_table", None)
                if evac_tbl is not None:
                    evac_tbl.blockSignals(True)
                    try:
                        for ri, val in enumerate(occupants[:evac_tbl.rowCount()]):
                            itm = evac_tbl.item(ri, _EVAC_OCCUPANTS_COL)
                            if itm is None:
                                itm = QTableWidgetItem(str(val))
                                itm.setTextAlignment(Qt.AlignCenter)
                                evac_tbl.setItem(ri, _EVAC_OCCUPANTS_COL, itm)
                            else:
                                itm.setText(str(val))
                    finally:
                        evac_tbl.blockSignals(False)

                if hasattr(self, "_calc_speed_table"):
                    self._calc_speed_table()
                if hasattr(self, "_calc_lane_distribution"):
                    self._calc_lane_distribution()

            def _push_traffic_volume_to_tunnel(*_args):
                ttw = getattr(self, "tunnel_traffic_widget", None)
                if ttw is None or not hasattr(ttw, "set_traffic_volume_cells"):
                    return
                try:
                    plus_dir  = _read_veh_row(_ROW_PLUS_DIR)
                    minus_dir = _read_veh_row(_ROW_MINUS_DIR)
                    occupants = _read_veh_row(_ROW_OCCUPANTS)

                    def _to_float(v):
                        try:
                            return float(str(v).strip())
                        except (TypeError, ValueError):
                            return 0.0

                    is_twoway = bool(
                        hasattr(self, "tbi_radio_twoway")
                        and self.tbi_radio_twoway.isChecked()
                    )
                    traffic_volume = [
                        (_to_float(p) + _to_float(m)) if is_twoway else _to_float(p)
                        for p, m in zip(plus_dir, minus_dir)
                    ]

                    ttw.set_traffic_volume_cells(traffic_volume, occupants)
                except Exception:
                    pass

            self.tbi_veh_table.cellChanged.connect(
                lambda r, _c: _push_traffic_volume_to_tunnel()
                if r in (_ROW_PLUS_DIR, _ROW_MINUS_DIR, _ROW_OCCUPANTS) else None
            )
            self.tbi_veh_table.cellChanged.connect(
                lambda r, _c: _sync_occupants_to_dependents()
                if r == _ROW_OCCUPANTS else None
            )
            self.tbi_traffic_btn_group.idClicked.connect(_push_traffic_volume_to_tunnel)
            # Initial push on startup.
            _push_traffic_volume_to_tunnel()
            _sync_occupants_to_dependents()
        except Exception:
            pass
        
        self.t7_sub_tabs.addTab(std_scenario_tab, "Standard Scenario")

        # Sub-tab 3: FN-Curve (from FNCV_ROAD.xlsm / FNCurve2)
        fn_curve_tab = QWidget()
        fn_curve_layout = QVBoxLayout()
        fn_curve_tab.setLayout(fn_curve_layout)
        try:
            from fn_curve_subtab_widget import FNCurveSubTabWidget
            self.fn_curve_subtab_widget = FNCurveSubTabWidget()
            fn_curve_layout.addWidget(self.fn_curve_subtab_widget)
        except Exception as _e_fnc:
            _fnc_err = QLabel(
                f"⚠  Could not load FN-Curve sub-tab: {_e_fnc}\n"
                "Ensure fn_curve_subtab_widget.py and FNCV_ROAD.xlsm are in the same directory."
            )
            _fnc_err.setWordWrap(True)
            _fnc_err.setStyleSheet("color:#c0392b;font-size:11px;padding:8px;")
            fn_curve_layout.addWidget(_fnc_err)

        self.t7_sub_tabs.addTab(fn_curve_tab, "FN-Curve")
        
        layout.addWidget(self.t7_sub_tabs)
        
        # Results summary
        summary_group = QGroupBox("QRA Results Summary")
        summary_group.setStyleSheet("QGroupBox { font-weight: bold; }")
        summary_layout = QVBoxLayout()
        summary_group.setLayout(summary_layout)
        
        self.results_text = QTextEdit()
        self.results_text.setReadOnly(True)
        self.results_text.setPlaceholderText("Complete QRA results will appear here after all analysis steps...")
        self.results_text.setStyleSheet("background-color: #f8f9fa; font-family: 'Courier New'; font-size: 11px;")
        summary_layout.addWidget(self.results_text)
        
        layout.addWidget(summary_group)
        
        # Visualization and Export buttons
        button_group = QGroupBox("Visualization and Export")
        button_group.setStyleSheet("QGroupBox { font-weight: bold; }")
        button_layout = QHBoxLayout()
        button_group.setLayout(button_layout)
        
        self.view_fn_curve_btn = QPushButton("📈 View F-N Curve")
        self.view_fn_curve_btn.clicked.connect(self.view_fn_curve)
        self.view_fn_curve_btn.setStyleSheet("QPushButton { background-color: #27ae60; color: white; padding: 10px; }")
        
        self.export_excel_btn = QPushButton("📊 Export to Excel")
        self.export_excel_btn.clicked.connect(self.export_to_excel)
        self.export_excel_btn.setStyleSheet("QPushButton { background-color: #16a085; color: white; padding: 10px; }")
        
        self.export_pdf_btn = QPushButton("📄 Export to PDF")
        self.export_pdf_btn.clicked.connect(self.export_to_pdf)
        self.export_pdf_btn.setStyleSheet("QPushButton { background-color: #2980b9; color: white; padding: 10px; }")
        
        button_layout.addWidget(self.view_fn_curve_btn)
        button_layout.addWidget(self.export_excel_btn)
        button_layout.addWidget(self.export_pdf_btn)
        
        layout.addWidget(button_group)
        
        layout.addStretch()
        
        self.tabs.addTab(scroll, "Risk Calculations")
        
        # Initialize FDS version-dependent UI state
        self.on_fds_version_changed()
    
    # ==================== Event Handlers ====================
    
    def browse_home_directory(self):
        """Browse for home directory"""
        directory = QFileDialog.getExistingDirectory(
            self, "Select Home Directory", str(Path.home())
        )
        if directory:
            self.home_dir_input.setText(directory)
    
    def update_directory_preview(self):
        """Update directory structure preview"""
        project_name = self.project_name_input.text().strip()
        home_dir = self.home_dir_input.text().strip()
        
        if project_name and home_dir:
            full_path = str(Path(home_dir) / project_name)
            self.full_path_display.setText(full_path)
            self.create_project_btn.setEnabled(True)
        else:
            self.full_path_display.setText("")
            self.create_project_btn.setEnabled(False)
        
        # Update tree
        self.dir_tree.clear()
        if project_name:
            root = QTreeWidgetItem(self.dir_tree)
            root.setText(0, f"📁 {project_name}/")
            root.setExpanded(True)
            
            # Database name based on project name (lowercase)
            db_name = project_name.lower().replace(' ', '_') + ".db"
            
            folders = [
                ("📂 fds_inputs/", ["020/", "030/", "100/"]),
                ("📂 fdb_files/", []),
                ("📂 ascii_files/", []),
                ("📂 evc_files/", []),
                ("📂 fed_results/", []),
                ("📂 graphs/", []),
                ("📂 logs/", []),
                (f"📄 {db_name}", None),
                ("📄 run_all_simulations.bat", None)
            ]
            
            for folder, subfolders in folders:
                child = QTreeWidgetItem(root)
                child.setText(0, folder)
                if subfolders:
                    child.setExpanded(True)
                    for sub in subfolders:
                        subchild = QTreeWidgetItem(child)
                        subchild.setText(0, f"  {sub}")
    
    def create_project(self):
        """Create new project"""
        project_name = self.project_name_input.text().strip()
        home_dir = self.home_dir_input.text().strip()
        
        if not project_name or not home_dir:
            QMessageBox.warning(self, "Missing Information",
                              "Please enter both project name and home directory.")
            return
        
        self.project_dir = str(Path(home_dir) / project_name)
        
        try:
            # Create directory structure
            dirs = [
                "fds_inputs/020",
                "fds_inputs/030",
                "fds_inputs/100",
                "fdb_files",
                "ascii_files",
                "evc_files",
                "fed_results",
                "graphs",
                "logs"
            ]
            
            self.dir_progress_bar.setValue(0)
            self.dir_status_text.append(f"Creating project: {self.project_dir}")
            
            Path(self.project_dir).mkdir(parents=True, exist_ok=True)
            
            for i, d in enumerate(dirs):
                (Path(self.project_dir) / d).mkdir(parents=True, exist_ok=True)
                progress = int((i + 1) / len(dirs) * 100)
                self.dir_progress_bar.setValue(progress)
                self.dir_status_text.append(f"✓ Created: {d}")
            
            # Create batch script
            batch_file = Path(self.project_dir) / "run_all_simulations.bat"
            batch_file.write_text("@echo off\necho FDS simulations batch script\npause\n")
            self.dir_status_text.append("✓ Created: run_all_simulations.bat")
            
            # Initialize database with automatic naming (project name in lowercase)
            # Database is optional - only create if module is available
            db_name = project_name.lower().replace(' ', '_') + ".db"
            db_path = Path(self.project_dir) / db_name
            
            if QRADatabase is not None:
                try:
                    self.database = QRADatabase(str(db_path))
                    self.database.connect()
                    
                    self.current_project_id = self.database.add_project(
                        project_name=project_name,
                        description="QRA Project v2.0",
                        home_directory=home_dir
                    )
                    self.dir_status_text.append("✓ Database initialized")
                except Exception as e:
                    self.dir_status_text.append(f"⚠️ Database initialization failed: {e}")
                    self.dir_status_text.append("ℹ️ Continuing without database...")
            else:
                self.dir_status_text.append("ℹ️ Database module not available (optional)")
            
            self.dir_status_text.append("✓ Database initialized")
            self.dir_status_text.append(f"\n✅ Project created successfully!")
            
            # Enable next tab
            self.generate_fds_btn.setEnabled(True)
            self.tabs.setCurrentIndex(1)
            self.statusBar().showMessage(f"Project created: {project_name}")
            
            QMessageBox.information(self, "Success",
                                  f"Project created successfully!\n\n{self.project_dir}")
            
        except Exception as e:
            self.dir_status_text.append(f"\n❌ Error: {str(e)}")
            QMessageBox.critical(self, "Error", f"Failed to create project:\n{str(e)}")
    
    def open_existing_project(self):
        """Open existing project"""
        directory = QFileDialog.getExistingDirectory(
            self, "Select Project Directory", str(Path.home())
        )
        
        if directory:
            self.project_dir = directory
            self.project_name_input.setText(Path(directory).name)
            self.home_dir_input.setText(str(Path(directory).parent))
            
            # Initialize database - look for existing database files
            project_name = Path(directory).name
            db_name = project_name.lower().replace(' ', '_') + ".db"
            db_path = Path(self.project_dir) / db_name
            
            # Fallback to qra_database.db if new naming doesn't exist
            if not db_path.exists():
                old_db_path = Path(self.project_dir) / "qra_database.db"
                if old_db_path.exists():
                    db_path = old_db_path
            
            # Database is optional - only load if module is available
            if QRADatabase is not None and db_path.exists():
                try:
                    self.database = QRADatabase(str(db_path))
                    self.database.connect()
                    
                    projects = self.database.get_projects()
                    if projects:
                        self.current_project_id = projects[-1]['id']
                except Exception as e:
                    print(f"⚠️ Database loading failed: {e}")
            else:
                print("ℹ️ Database not available (optional)")
            
            self.generate_fds_btn.setEnabled(True)
            self.dir_status_text.append(f"✓ Opened project: {self.project_dir}")

            # Ensure all expected subdirectories exist (handles legacy projects)
            _ensure = ["ascii_files", "evc_files", "fed_results", "fdb_files",
                       "fds_inputs", "graphs", "logs"]
            for _d in _ensure:
                _p = Path(self.project_dir) / _d
                if not _p.exists():
                    _p.mkdir(parents=True, exist_ok=True)
                    self.dir_status_text.append(f"  ✦ Created missing dir: {_d}")

            self.statusBar().showMessage(f"Project opened: {Path(directory).name}")
            
            # Auto-scan fds_inputs/ for existing .fds files
            self.scan_fds_input_files()
            
            QMessageBox.information(self, "Success",
                                  f"Project opened successfully!\n\n{self.project_dir}")
    
    def calculate_tunnel_dimensions(self):
        """Calculate tunnel width and height from radius"""
        radius = self.tunnel_radius_input.value()
        width = radius * 2
        height = 2 * radius + 0.4  # Full circle height + road offset
        
        self.tunnel_width_input.setValue(width)
        self.tunnel_height_input.setValue(height)
        
        QMessageBox.information(self, "Calculated",
                              f"Width: {width:.2f} m\nHeight: {height:.2f} m")
    
    def add_custom_hrr(self):
        """Add custom HRR value"""
        hrr_value = self.custom_hrr_input.value()
        
        if hrr_value in self.custom_hrr_list:
            QMessageBox.warning(self, "Duplicate", "This HRR value already exists in the custom list.")
            return
        
        self.custom_hrr_list.append(hrr_value)
        self.custom_hrr_list_widget.addItem(f"{hrr_value} MW")
        self.fds_status_text.append(f"Added custom HRR: {hrr_value} MW")
    
    def remove_custom_hrr(self):
        """Remove selected custom HRR"""
        current_item = self.custom_hrr_list_widget.currentItem()
        if current_item:
            row = self.custom_hrr_list_widget.row(current_item)
            self.custom_hrr_list.pop(row)
            self.custom_hrr_list_widget.takeItem(row)
            self.fds_status_text.append(f"Removed custom HRR")
    
