    # ══════════════════════════════════════════════════════════════════════════
    # FDS input-file scanning & import
    # ══════════════════════════════════════════════════════════════════════════

    def _collect_fds_files(self, root_dir):
        """Collect all .fds/.FDS files under *root_dir* (case-insensitive).

        Returns a sorted list of Path objects.
        """
        root = Path(root_dir)
        if not root.exists():
            return []
        return sorted(
            [f for f in root.rglob("*") if f.is_file() and f.suffix.lower() == '.fds'],
            key=lambda p: str(p)
        )

    def _parse_sim_time(self, fds_file_path):
        """Parse the simulation end-time from an FDS input file.

        Handles both FDS6 (``T_END``) and FDS5 (``TWFIN``) keywords inside
        an ``&TIME`` namelist.  Returns the value in seconds, or *None* if
        neither keyword is found.
        """
        import re as _re_local
        try:
            with open(fds_file_path, 'r', errors='replace') as fh:
                content = fh.read()
            # Try FDS6 T_END first, then FDS5 TWFIN
            m = _re_local.search(r"&TIME[^/]*T_END\s*=\s*([\d.]+)", content, _re_local.I | _re_local.S)
            if m:
                return float(m.group(1))
            m = _re_local.search(r"&TIME[^/]*TWFIN\s*=\s*([\d.]+)", content, _re_local.I | _re_local.S)
            if m:
                return float(m.group(1))
        except Exception:
            pass
        return None

    def scan_fds_input_files(self):
        """Scan fds_inputs/ and populate the tree widget + summary label.

        Expected layout under fds_inputs/:
            {HRR}/{Congestion}/{VentilationType}/*.fds
        e.g.  020/Cong/FV0/020_C_FV0_pos500.fds

        The method works even if files are directly in fds_inputs/ or in any
        other subfolder depth.
        """
        if not self.project_dir:
            self.fds_files_summary_label.setText(
                "⚠️ No project loaded — open or create a project first.")
            return

        fds_inputs_dir = Path(self.project_dir) / "fds_inputs"
        fds_files = self._collect_fds_files(fds_inputs_dir)
        total = len(fds_files)

        # ── Clear & rebuild tree ──────────────────────────────────────────
        self.fds_files_tree.clear()

        if total == 0:
            self.fds_files_summary_label.setText(
                f"⚠️ No .fds files found under {fds_inputs_dir}\n"
                "Generate files in Tab 2, or click 'Import FDS Files…' to import them.")
            self.sim_status_text.append(f"\n🔍 Scan: 0 .fds files found in fds_inputs/")
            return

        # Group files by their relative sub-path parts:
        #   HRR / Congestion / Ventilation / filename
        from collections import defaultdict
        tree_data = defaultdict(lambda: defaultdict(lambda: defaultdict(list)))
        flat_files = []  # files directly in fds_inputs/ (no subfolder)

        for fp in fds_files:
            rel = fp.relative_to(fds_inputs_dir)
            parts = rel.parts  # e.g. ('020', 'Cong', 'FV0', 'file.fds')
            if len(parts) >= 4:
                hrr, cong, vent = parts[0], parts[1], parts[2]
                tree_data[hrr][cong][vent].append(fp.name)
            elif len(parts) == 3:
                tree_data[parts[0]][parts[1]][""].append(fp.name)
            elif len(parts) == 2:
                tree_data[parts[0]][""][""].append(fp.name)
            else:
                flat_files.append(fp.name)

        # Populate tree widget
        vent_type_names = {"FV0": "Forced Vent Off", "FVM": "Forced Vent −",
                           "FVP": "Forced Vent +", "NV0": "Natural Vent Off",
                           "NVC": "Natural Vent Cross"}

        for hrr_key in sorted(tree_data.keys()):
            hrr_item = QTreeWidgetItem([f"🔥 {hrr_key}  (HRR)", ""])
            hrr_count = 0
            for cong_key in sorted(tree_data[hrr_key].keys()):
                label = cong_key if cong_key else "(root)"
                cong_item = QTreeWidgetItem([f"🚗 {label}", ""])
                cong_count = 0
                for vent_key in sorted(tree_data[hrr_key][cong_key].keys()):
                    files = tree_data[hrr_key][cong_key][vent_key]
                    vent_label = vent_key if vent_key else "(root)"
                    vent_desc = vent_type_names.get(vent_key, "")
                    vent_item = QTreeWidgetItem(
                        [f"💨 {vent_label}", f"{len(files)} file(s)  {vent_desc}"])
                    for fname in sorted(files):
                        file_item = QTreeWidgetItem([f"  📄 {fname}", ""])
                        vent_item.addChild(file_item)
                    cong_item.addChild(vent_item)
                    cong_count += len(files)
                cong_item.setText(1, f"{cong_count} file(s)")
                hrr_item.addChild(cong_item)
                hrr_count += cong_count
            hrr_item.setText(1, f"{hrr_count} file(s)")
            self.fds_files_tree.addTopLevelItem(hrr_item)

        # Flat files at root level
        if flat_files:
            root_item = QTreeWidgetItem(["📂 (fds_inputs root)", f"{len(flat_files)} file(s)"])
            for fname in sorted(flat_files):
                root_item.addChild(QTreeWidgetItem([f"  📄 {fname}", ""]))
            self.fds_files_tree.addTopLevelItem(root_item)

        # Expand first two levels for visibility
        self.fds_files_tree.expandToDepth(1)
        self.fds_files_tree.resizeColumnToContents(0)

        # Update summary
        hrr_dirs = sorted(tree_data.keys())
        vent_types_found = set()
        for h in tree_data.values():
            for c in h.values():
                for v in c.keys():
                    if v:
                        vent_types_found.add(v)

        self.fds_files_summary_label.setText(
            f"✅ Found {total} .fds file(s)  |  "
            f"HRR groups: {', '.join(hrr_dirs) if hrr_dirs else 'none'}  |  "
            f"Ventilation types: {', '.join(sorted(vent_types_found)) if vent_types_found else 'n/a'}")
        self.fds_files_summary_label.setStyleSheet(
            "padding: 6px; background-color: #d5f5e3; border-radius: 4px; font-size: 12px;")

        self.sim_status_text.append(
            f"\n🔍 Scan: {total} .fds file(s) found across "
            f"{len(hrr_dirs)} HRR group(s), "
            f"ventilation types: {', '.join(sorted(vent_types_found))}")

        # Auto-populate Tab4 Tunnel Info from the first FDS file found
        if fds_files:
            self._evc_parse_fds(fds_files[0])

        # Also refresh time estimates
        self.update_time_estimates()

    def import_fds_files(self):
        """Import .fds files from an external folder into the project's fds_inputs/.

        The user selects a root folder.  Its subfolder tree is reproduced under
        fds_inputs/ and every .fds file found is copied in.

        Typical external layout:
            selected_folder/020/Cong/FV0/some_file.fds
        →  fds_inputs/020/Cong/FV0/some_file.fds
        """
        if not self.project_dir:
            QMessageBox.warning(self, "No Project",
                                "Please create or open a project first.")
            return

        src_dir = QFileDialog.getExistingDirectory(
            self, "Select folder containing .fds files",
            str(Path.home()))
        if not src_dir:
            return

        src_path = Path(src_dir)
        fds_files = self._collect_fds_files(src_path)
        if not fds_files:
            QMessageBox.information(self, "No Files",
                                    f"No .fds files found under:\n{src_dir}")
            return

        dest_root = Path(self.project_dir) / "fds_inputs"
        dest_root.mkdir(parents=True, exist_ok=True)

        copied = 0
        skipped = 0
        for fp in fds_files:
            rel = fp.relative_to(src_path)
            dest_file = dest_root / rel
            dest_file.parent.mkdir(parents=True, exist_ok=True)
            if dest_file.exists():
                skipped += 1
                continue
            shutil.copy2(fp, dest_file)
            copied += 1

        msg = f"Imported {copied} file(s) into fds_inputs/"
        if skipped:
            msg += f"\nSkipped {skipped} file(s) that already existed."
        self.sim_status_text.append(f"\n📥 {msg}")
        QMessageBox.information(self, "Import Complete", msg)

        # Refresh the tree
        self.scan_fds_input_files()
    
